import { createServerClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { Suspense } from 'react'
import {
    TrendingUp, Receipt, AlertCircle,
    CheckCircle2, Clock, FileText, AlertTriangle, ExternalLink, ArrowRight
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { getKPIsAction } from '@/app/actions/informes'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import Link from 'next/link'
import { DashboardPeriodSelector } from '@/components/dashboard/dashboard-period-selector'
import { DashboardVistaSelector } from '@/components/dashboard/dashboard-vista-selector'
import { DashboardCharts } from '@/components/dashboard/dashboard-charts'
import { DashboardKpiCards } from '@/components/dashboard/dashboard-kpi-cards'
import { parseDashboardPeriod, type PeriodoValue, type VistaValue } from '@/lib/dashboard-period'
import { getEvolucionFacturacionAction } from '@/app/actions/informes'

export const dynamic = 'force-dynamic'

export default async function DashboardPage({
    searchParams,
}: {
    searchParams: Promise<{ periodo?: string; vista?: string; desde?: string; hasta?: string }>
}) {
    const params = await searchParams
    const supabase = await createServerClient()
    await supabase.auth.getUser()

    const userContext = await getUserContext().catch(() => null)
    let companyName = 'Dashboard'
    let welcomeText = 'Resumen de ventas'
    let empresaId: string | null = null
    let isGlobal = false
    const adminClient = createAdminClient()

    if (userContext) {
        const ctx = userContext
        empresaId = ctx.empresaId
        isGlobal = !ctx.empresaId && !!ctx.isAdmin
        if (isGlobal) {
            companyName = 'Visión Global'
            welcomeText = 'Resumen consolidado de todas las empresas'
        } else if (ctx.empresaId) {
            const active = ctx.empresas.find((e: { empresa_id: string }) => e.empresa_id === ctx.empresaId) as any
            companyName = active?.empresa?.nombre_comercial || active?.empresa?.razon_social || 'Tu Empresa'
            welcomeText = `Bienvenido al panel de control de ${companyName}`
        }
    }

    const { periodo, vista, desde, hasta } = parseDashboardPeriod(params)
    const fechaDesde = `${desde}T00:00:00.000Z`
    const fechaHasta = `${hasta}T23:59:59.999Z`

    // ── KPIs principales ──────────────────────────────────────────────────────
    const kpisResult = await getKPIsAction(fechaDesde, fechaHasta)
    const kpis = kpisResult.success && kpisResult.data ? kpisResult.data : {
        actual: { facturacion_total: 0, num_facturas: 0, ticket_medio: 0, dias_cobro_promedio: 0 },
        anterior: { facturacion_total: 0, num_facturas: 0, ticket_medio: 0, dias_cobro_promedio: 0 },
        variaciones: { facturacion: 0, facturas: 0, ticket_medio: 0, dias_cobro: 0 }
    }

    // ── Evolución (para sparklines y gráficos) ──────────────────────────────────
    const evolucionRes = await getEvolucionFacturacionAction(fechaDesde, fechaHasta, empresaId ?? undefined)
    const evolution = evolucionRes.success && evolucionRes.data ? evolucionRes.data : []

    // ── Facturas recientes del período ─────────────────────────────────────────
    let facturasQuery = adminClient
        .from('facturas')
        .select('id, numero, serie, total, estado, fecha_emision, divisa, cliente:clientes(nombre_fiscal, nombre_comercial), empresa:empresas(nombre_comercial, razon_social)')
        .gte('fecha_emision', desde)
        .lte('fecha_emision', hasta)
        .neq('estado', 'anulada')
        .order('fecha_emision', { ascending: false })
        .limit(6)
    if (empresaId) facturasQuery = facturasQuery.eq('empresa_id', empresaId)
    const { data: facturasRecientes } = await facturasQuery

    // ── Estados del período ────────────────────────────────────────────────────
    let estadosQuery = adminClient
        .from('facturas')
        .select('estado')
        .gte('fecha_emision', desde)
        .lte('fecha_emision', hasta)
    if (empresaId) estadosQuery = estadosQuery.eq('empresa_id', empresaId)
    const { data: estadosRaw } = await estadosQuery
    const estadosCount: Record<string, number> = {}
    for (const f of estadosRaw || []) {
        estadosCount[f.estado] = (estadosCount[f.estado] || 0) + 1
    }

    // ── Alertas: vencimientos próximos (7 días) ────────────────────────────────
    const nowLocal = new Date()
    const hoy = nowLocal.toISOString().slice(0, 10)
    const en7dias = new Date(nowLocal.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10)
    let vencimientosQuery = adminClient
        .from('facturas')
        .select('id, numero, serie, total, fecha_vencimiento, cliente:clientes(nombre_fiscal, nombre_comercial)')
        .gte('fecha_vencimiento', hoy)
        .lte('fecha_vencimiento', en7dias)
        .not('estado', 'in', '("pagada","anulada")')
        .order('fecha_vencimiento', { ascending: true })
        .limit(5)
    if (empresaId) vencimientosQuery = vencimientosQuery.eq('empresa_id', empresaId)
    const { data: vencimientosProximos } = await vencimientosQuery

    // ── Desglose por empresa (solo visión global) ──────────────────────────────
    let desgloseEmpresas: Array<{ nombre: string; facturacion: number; num_facturas: number; ticket_medio: number; id: string }> = []
    if (isGlobal && userContext) {
        const empresasDisp = (userContext.empresas as any[])
            .filter((e) => e.empresa_id)
            .slice(0, 10)
        const resultados = await Promise.all(
            empresasDisp.map(async (e) => {
                const res = await getKPIsAction(fechaDesde, fechaHasta, e.empresa_id)
                return {
                    id: e.empresa_id,
                    nombre: e.empresa?.nombre_comercial || e.empresa?.razon_social || e.empresa_id,
                    facturacion: res.success ? (res.data?.actual.facturacion_total ?? 0) : 0,
                    num_facturas: res.success ? (res.data?.actual.num_facturas ?? 0) : 0,
                    ticket_medio: res.success ? (res.data?.actual.ticket_medio ?? 0) : 0,
                }
            })
        )
        desgloseEmpresas = resultados.sort((a, b) => b.facturacion - a.facturacion)
    }

    // ── Helpers de formato ─────────────────────────────────────────────────────
    const formatCurrency = (amount: number) =>
        new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(amount)

    const formatPeriodoLabel = () => {
        const d = new Date(`${desde}T12:00:00`)
        const h = new Date(`${hasta}T12:00:00`)
        const fmt = (x: Date) => x.toLocaleDateString('es-ES', { day: 'numeric', month: 'short', year: 'numeric' })
        return `${fmt(d)} – ${fmt(h)}`
    }

    const estadoBadge = (estado: string) => {
        switch (estado) {
            case 'pagada': return <Badge className="bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300 border-0 text-[10px]">Pagada</Badge>
            case 'emitida': return <Badge className="bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300 border-0 text-[10px]">Emitida</Badge>
            case 'borrador': return <Badge className="bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300 border-0 text-[10px]">Borrador</Badge>
            default: return <Badge variant="secondary" className="text-[10px]">{estado}</Badge>
        }
    }

    const verFacturasUrl = `/ventas/facturas?desde=${desde}&hasta=${hasta}`

    return (
        <div className="space-y-8 pb-8">
            {/* ── Cabecera ── */}
            <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
                <div className="space-y-1.5">
                    <nav className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400" data-testid="dashboard-breadcrumb" aria-label="Breadcrumb">
                        <span>Dashboard</span>
                        <span aria-hidden>›</span>
                        <span className="text-slate-700 dark:text-slate-200 font-medium">Inicio</span>
                    </nav>
                    <h1 className="text-3xl sm:text-4xl font-semibold text-slate-900 dark:text-white tracking-tight">
                        {companyName}
                    </h1>
                    <p className="text-slate-600 dark:text-slate-300 text-sm sm:text-base">{welcomeText}</p>
                    <div className="flex flex-wrap items-center gap-2 pt-1">
                        <Badge
                            variant="outline"
                            className="bg-slate-100 text-slate-800 border-slate-300 dark:bg-slate-800 dark:text-slate-100 dark:border-slate-600 text-xs font-semibold px-3 py-1 shadow-sm"
                            data-testid="dashboard-datos-periodo"
                        >
                            Datos: {formatPeriodoLabel()}
                        </Badge>
                        {vista === 'semana' && (
                            <Badge variant="outline" className="text-xs border-amber-300 text-amber-700 dark:text-amber-400 dark:border-amber-600">
                                Vista 7 días
                            </Badge>
                        )}
                    </div>
                </div>
                    <div className="flex flex-col sm:flex-row flex-wrap items-stretch sm:items-center gap-3 w-full sm:w-auto">
                    <DashboardVistaSelector vista={vista as VistaValue} />
                    <Suspense fallback={<div className="h-10 w-full sm:w-[200px] rounded-md border bg-slate-100 animate-pulse" />}>
                        <DashboardPeriodSelector periodo={periodo as PeriodoValue} desde={desde} hasta={hasta} vista={vista as VistaValue} />
                    </Suspense>
                    <Link href="/ventas/facturas/nueva" className="w-full sm:w-auto">
                        <Button variant="premium" size="lg" className="w-full sm:w-auto min-h-[44px] hover:shadow-lg transition-shadow duration-200">+ Nueva Factura</Button>
                    </Link>
                </div>
            </div>

            {/* ── KPIs con sparklines ── */}
            <DashboardKpiCards kpis={kpis} evolution={evolution} vista={vista as VistaValue} />

            {/* ── Gráficos: Evolución + Estados ── */}
            <DashboardCharts
                fechaDesde={fechaDesde}
                fechaHasta={fechaHasta}
                empresaId={empresaId}
            />

            {/* ── Fila: Estados + Alertas ── */}
            <div className="grid gap-6 lg:grid-cols-3">
                {/* Estados del período */}
                <Card className="border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900/95 shadow-md" data-testid="dashboard-card-estados">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-semibold text-slate-600 dark:text-slate-300 uppercase tracking-wider flex items-center gap-2">
                            <FileText className="h-4 w-4" /> Estados del período
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-2">
                        {Object.entries({ pagada: 'Pagadas', emitida: 'Emitidas', borrador: 'Borradores' }).map(([key, label]) => (
                            <div key={key} className="flex items-center justify-between py-1">
                                <div className="flex items-center gap-2">
                                    {key === 'pagada' && <CheckCircle2 className="h-4 w-4 text-emerald-500" />}
                                    {key === 'emitida' && <Clock className="h-4 w-4 text-blue-500" />}
                                    {key === 'borrador' && <FileText className="h-4 w-4 text-slate-400" />}
                                    <span className="text-sm text-slate-700 dark:text-slate-300">{label}</span>
                                </div>
                                <span className="font-bold text-slate-900 dark:text-white text-sm">{estadosCount[key] ?? 0}</span>
                            </div>
                        ))}
                        {Object.keys(estadosCount).length === 0 && (
                            <div className="flex flex-col items-center justify-center py-6 px-4 text-center" data-testid="dashboard-empty-estados">
                                <FileText className="h-10 w-10 text-slate-300 dark:text-slate-600 mb-2" aria-hidden />
                                <p className="text-sm text-slate-500 dark:text-slate-400">Sin facturas en este período</p>
                                <Link href="/ventas/facturas/nueva" className="mt-3 text-xs font-medium text-primary hover:text-primary/80 transition-colors">
                                    Crear factura
                                </Link>
                            </div>
                        )}
                        <div className="pt-2 border-t border-slate-100 dark:border-slate-800">
                            <Link href={verFacturasUrl} className="group text-xs text-primary hover:underline hover:text-primary/80 transition-colors duration-150 flex items-center gap-1 min-h-[44px] min-w-[44px] sm:min-h-0 sm:min-w-0">
                                Ver todas las facturas del período <ArrowRight className="h-3 w-3 transition-transform duration-150 group-hover:translate-x-0.5" />
                            </Link>
                        </div>
                    </CardContent>
                </Card>

                {/* Alertas: vencimientos próximos */}
                <Card className="lg:col-span-2 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900/95 shadow-md" data-testid="dashboard-card-vencimientos">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-semibold text-slate-600 dark:text-slate-300 uppercase tracking-wider flex items-center gap-2">
                            <AlertTriangle className="h-4 w-4 text-amber-500" /> Vencimientos próximos (7 días)
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        {!vencimientosProximos || vencimientosProximos.length === 0 ? (
                            <div className="flex flex-col sm:flex-row items-center sm:items-start gap-3 py-6 px-4 text-emerald-600 dark:text-emerald-400" data-testid="dashboard-empty-vencimientos">
                                <CheckCircle2 className="h-10 w-10 sm:h-6 sm:w-6 shrink-0" aria-hidden />
                                <span className="text-sm font-medium text-center sm:text-left">Sin vencimientos pendientes en los próximos 7 días</span>
                            </div>
                        ) : (
                            <div className="space-y-2">
                                {vencimientosProximos.map((f: any) => (
                                    <Link key={f.id} href={`/ventas/facturas/${f.id}`} className="flex flex-wrap items-center justify-between gap-2 p-2 sm:p-3 rounded-lg hover:bg-amber-50 dark:hover:bg-amber-900/10 transition-colors duration-150 group min-h-[44px] sm:min-h-0">
                                        <div className="flex items-center gap-2 min-w-0 flex-1">
                                            <div className="text-xs bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300 px-2 py-0.5 rounded font-mono font-semibold shrink-0">
                                                {f.serie ? `${f.serie}-${f.numero}` : f.numero}
                                            </div>
                                            <span className="text-sm text-slate-700 dark:text-slate-300 truncate min-w-0">
                                                {(f.cliente as any)?.nombre_comercial || (f.cliente as any)?.nombre_fiscal || '—'}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-2 sm:gap-3 shrink-0">
                                            <span className="text-xs text-slate-500" suppressHydrationWarning>{new Date(`${f.fecha_vencimiento}T12:00:00`).toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}</span>
                                            <span className="text-sm font-bold text-slate-900 dark:text-white">{formatCurrency(f.total)}</span>
                                            <ExternalLink className="h-3 w-3 text-slate-400 opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all duration-150" aria-hidden />
                                        </div>
                                    </Link>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>

            {/* ── Desglose por empresa (solo visión global) ── */}
            {isGlobal && desgloseEmpresas.length > 0 && (
                <Card className="border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900/95 shadow-md">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-sm font-semibold text-slate-600 dark:text-slate-300 uppercase tracking-wider flex items-center gap-2">
                            <TrendingUp className="h-4 w-4" /> Desglose por empresa
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                            {desgloseEmpresas.map((emp) => (
                                <div key={emp.id} className="rounded-xl border border-slate-100 dark:border-slate-800 p-4 bg-white/80 dark:bg-slate-900/80 hover:shadow-lg hover:border-primary/20 transition-all duration-200">
                                    <p className="font-semibold text-slate-800 dark:text-slate-100 text-sm mb-3 truncate">{emp.nombre}</p>
                                    <div className="space-y-1 text-xs text-slate-600 dark:text-slate-400">
                                        <div className="flex justify-between">
                                            <span>Facturación</span>
                                            <span className="font-bold text-slate-900 dark:text-white">{formatCurrency(emp.facturacion)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span>Facturas</span>
                                            <span className="font-semibold">{emp.num_facturas}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span>Ticket medio</span>
                                            <span className="font-semibold">{formatCurrency(emp.ticket_medio)}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* ── Facturas recientes del período ── */}
            {facturasRecientes && facturasRecientes.length > 0 && (
                <Card className="border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900/95 shadow-md" data-testid="dashboard-card-facturas">
                    <CardHeader className="pb-3 flex flex-row items-center justify-between">
                        <CardTitle className="text-sm font-semibold text-slate-600 dark:text-slate-300 uppercase tracking-wider flex items-center gap-2">
                            <Receipt className="h-4 w-4" /> Facturas del período
                        </CardTitle>
                        <Link href={verFacturasUrl} className="group text-xs text-primary hover:underline hover:text-primary/80 transition-colors duration-150 flex items-center gap-1 min-h-[44px] min-w-[44px] sm:min-h-0 sm:min-w-0">
                            Ver todas <ArrowRight className="h-3 w-3 transition-transform duration-150 group-hover:translate-x-0.5" />
                        </Link>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-1">
                            {facturasRecientes.map((f: any) => (
                                <Link key={f.id} href={`/ventas/facturas/${f.id}`}
                                    className="flex flex-wrap items-center justify-between gap-2 p-2 sm:p-3 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors duration-150 group min-h-[44px] sm:min-h-0">
                                    <div className="flex items-center gap-2 sm:gap-3 min-w-0 flex-1">
                                        <span className="font-mono text-xs font-semibold text-slate-700 dark:text-slate-300 shrink-0">
                                            {f.serie ? `${f.serie}-${f.numero}` : f.numero}
                                        </span>
                                        <span className="text-sm text-slate-600 dark:text-slate-400 truncate">
                                            {(f.cliente as any)?.nombre_comercial || (f.cliente as any)?.nombre_fiscal || '—'}
                                        </span>
                                        {isGlobal && (
                                            <span className="text-[10px] bg-slate-100 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded shrink-0">
                                                {(f.empresa as any)?.nombre_comercial || (f.empresa as any)?.razon_social}
                                            </span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-2 sm:gap-3 shrink-0 ml-0 sm:ml-3">
                                        {estadoBadge(f.estado)}
                                        <span className="text-sm font-bold text-slate-900 dark:text-white">{formatCurrency(f.total)}</span>
                                        <span className="text-xs text-slate-400 hidden sm:inline" suppressHydrationWarning>{new Date(`${f.fecha_emision}T12:00:00`).toLocaleDateString('es-ES', { day: 'numeric', month: 'short' })}</span>
                                        <ExternalLink className="h-3 w-3 text-slate-400 opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all duration-150 hidden sm:block" aria-hidden />
                                    </div>
                                </Link>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            )}

            {/* ── Error KPIs ── */}
            {!kpisResult.success && (
                <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg flex items-center gap-2 text-red-600 dark:text-red-400">
                    <AlertCircle className="h-5 w-5" />
                    <span className="font-medium">Error cargando KPIs: {kpisResult.error}</span>
                </div>
            )}
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import Link from 'next/link'
import { ChevronRight } from 'lucide-react'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { PerfilForm } from '@/components/perfil/perfil-form'

function getDisplayName(email: string | null, metadata?: Record<string, unknown>): string {
    const fromMeta = metadata?.full_name
    if (typeof fromMeta === 'string' && fromMeta.trim()) return fromMeta.trim()
    if (!email) return 'Usuario'
    if (email.toLowerCase().startsWith('administracion@')) return 'Administración'
    const local = email.split('@')[0] || ''
    const cleaned = local.replace(/[._-]+/g, ' ').trim()
    if (!cleaned) return 'Usuario'
    return cleaned
        .split(' ')
        .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
        .join(' ')
}

export default async function PerfilPage() {
    const supabase = await createServerClient()
    const {
        data: { user },
    } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    let context: Awaited<ReturnType<typeof getUserContext>> | null = null
    try {
        context = await getUserContext()
    } catch {
        // Usuario sin contexto multi-empresa
    }

    const displayName = getDisplayName(user.email || null, user.user_metadata)
    const avatarUrl =
        (user.user_metadata?.avatar_url as string | undefined) || null

    const empresas = (context?.empresas ?? []).map((ue: any) => {
        const emp = ue.empresa
        const nombre = emp?.nombre_comercial || emp?.razon_social || 'Sin nombre'
        return {
            nombre,
            rol: ue.rol ?? 'operador',
            empresa_activa: ue.empresa_activa,
            logo_url: emp?.logo_url ?? null,
        }
    })

    const isAdmin = context?.isAdmin ?? false
    const rol = context?.rol ?? 'operador'

    return (
        <div className="space-y-6 w-full min-w-0">
            {/* Breadcrumb */}
            <nav className="flex items-center gap-2 text-sm">
                <Link
                    href="/dashboard"
                    className="text-slate-500 dark:text-slate-400 hover:text-primary transition-colors"
                >
                    Dashboard
                </Link>
                <ChevronRight className="h-4 w-4 text-slate-400" />
                <span className="font-medium text-slate-900 dark:text-white">Mi Perfil</span>
            </nav>

            {/* Header */}
            <div>
                <h1 className="text-2xl sm:text-3xl font-bold text-slate-900 dark:text-white tracking-tight">
                    Mi Perfil
                </h1>
                <p className="text-slate-600 dark:text-slate-400 mt-1">
                    Información de tu cuenta y empresas vinculadas
                </p>
            </div>

            <PerfilForm
                displayName={displayName}
                email={user.email || ''}
                avatarUrl={avatarUrl}
                createdAt={user.created_at}
                empresas={empresas}
                isAdmin={isAdmin}
                rol={rol}
            />
        </div>
    )
}

import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { ClientesTabla } from '@/components/clientes/clientes-tabla'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { Cliente } from '@/types/ventas'
import { Plus } from 'lucide-react'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'
import { ClientesStats } from '@/components/clientes/clientes-stats'

export const dynamic = 'force-dynamic'

type OrdenValue = 'nombre_asc' | 'nombre_desc' | 'cif_asc' | 'cif_desc' | 'facturacion_asc' | 'facturacion_desc' | 'estado_asc' | 'estado_desc'

export default async function ClientesPage({
    searchParams,
}: {
    searchParams: Promise<{ search?: string; estado?: string; orden?: string }>
}) {
    const { supabase, empresaId } = await getUserContext()
    const params = await searchParams

    // Ordenación
    const orden = (params.orden || 'nombre_asc') as OrdenValue
    let orderField = 'nombre_fiscal'
    let orderAsc = true
    switch (orden) {
        case 'nombre_desc': orderField = 'nombre_fiscal'; orderAsc = false; break
        case 'cif_asc': orderField = 'cif'; orderAsc = true; break
        case 'cif_desc': orderField = 'cif'; orderAsc = false; break
        case 'facturacion_asc': orderField = 'total_facturado'; orderAsc = true; break
        case 'facturacion_desc': orderField = 'total_facturado'; orderAsc = false; break
        case 'estado_asc': orderField = 'activo'; orderAsc = true; break
        case 'estado_desc': orderField = 'activo'; orderAsc = false; break
        default: orderField = 'nombre_fiscal'; orderAsc = true; break
    }

    // Cargar clientes con filtros
    let query = supabase.from('clientes').select('*')

    if (empresaId) {
        const { data: ces } = await (supabase.from as any)('clientes_empresas')
            .select('cliente_id')
            .eq('empresa_id', empresaId)
        const clienteIds = (ces || []).map((c: { cliente_id: string }) => c.cliente_id)
        if (clienteIds.length > 0) {
            query = query.in('id', clienteIds)
        } else {
            query = query.eq('id', '00000000-0000-0000-0000-000000000000')
        }
    }

    if (params.search?.trim()) {
        const s = sanitizeSearchInput(params.search)
        if (s) query = query.or(`nombre_fiscal.ilike.%${s}%,cif.ilike.%${s}%,nombre_comercial.ilike.%${s}%`)
    }

    if (params.estado === 'activos') query = query.eq('activo', true)
    if (params.estado === 'inactivos') query = query.eq('activo', false)

    query = query.order(orderField, { ascending: orderAsc, nullsFirst: false })

    const { data: clientesRaw, error } = await query

    let clientes = clientesRaw as unknown as Cliente[]

    if (error) {
        console.error('Error loading clients:', error)
        return <div>Error al cargar clientes</div>
    }

    // Cuando hay empresa seleccionada: facturación solo de esa empresa (no global)
    let totalFacturadoPorCliente: Record<string, number> = {}
    if (empresaId && clientes && clientes.length > 0) {
        const clienteIds = clientes.map((c) => c.id)
        const { data: facturas } = await supabase
            .from('facturas')
            .select('cliente_id, total')
            .eq('empresa_id', empresaId)
            .in('cliente_id', clienteIds)
            .in('estado', ['emitida', 'vencida', 'parcial', 'pagada'])
        for (const f of facturas || []) {
            totalFacturadoPorCliente[f.cliente_id] = (totalFacturadoPorCliente[f.cliente_id] || 0) + Number(f.total ?? 0)
        }
        clientes = clientes.map((c) => ({
            ...c,
            total_facturado: totalFacturadoPorCliente[c.id] ?? 0,
        }))
        if (orden === 'facturacion_asc' || orden === 'facturacion_desc') {
            const asc = orden === 'facturacion_asc'
            clientes = [...clientes].sort((a, b) => {
                const ta = a.total_facturado ?? 0
                const tb = b.total_facturado ?? 0
                return asc ? ta - tb : tb - ta
            })
        }
    }

    // Stats
    const stats = {
        totalClientes: clientes?.length || 0,
        activos: clientes?.filter(c => c.activo).length || 0,
        inactivos: (clientes?.length || 0) - (clientes?.filter(c => c.activo).length || 0),
        facturacionTotal: clientes?.reduce((sum, c) => sum + (c.total_facturado || 0), 0) || 0
    }

    return (
        <div className="space-y-6 p-2 md:p-4 animate-in fade-in slide-in-from-bottom-4 duration-500" data-testid="page-clientes">
            {/* Breadcrumbs */}
            <nav className="flex items-center gap-2 text-sm text-slate-500" data-testid="clientes-breadcrumb" aria-label="Breadcrumb">
                <Link href="/ventas" className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors">Ventas</Link>
                <span aria-hidden>›</span>
                <span className="text-slate-900 dark:text-slate-100 font-medium">Clientes</span>
            </nav>

            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-3xl font-serif font-bold text-slate-900 dark:text-slate-100 tracking-tight">
                        Clientes
                    </h1>
                    <p className="text-slate-600 dark:text-slate-400 mt-1 text-lg">
                        Gestiona la base de datos de tus clientes
                    </p>
                </div>
                <Button asChild size="lg" className="sm:w-auto w-full min-h-[44px] bg-primary hover:bg-primary/90 hover:shadow-lg text-white shadow-lg shadow-primary/20 transition-all duration-300">
                    <Link href="/ventas/clientes/nuevo">
                        <Plus className="h-5 w-5 mr-2" aria-hidden />
                        Nuevo Cliente
                    </Link>
                </Button>
            </div>

            {/* Stats */}
            <ClientesStats stats={stats} />

            {/* Tabla */}
            <div className="space-y-4">
                <ClientesTabla clientes={clientes || []} searchParams={{ search: params.search, estado: params.estado, orden: params.orden }} />
            </div>
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { ConfiguracionEmpresaForm } from '@/components/configuracion/empresa-form'
import { DescargarDatosFiscalesButton } from '@/components/configuracion/descargar-datos-fiscales-button'
import type { Empresa } from '@/types/empresa'
import { getUserContext } from '@/app/actions/usuarios-empresas'

export default async function ConfiguracionEmpresaPage() {
    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')
    const { empresaId: empresaActivaId, empresas, rol } = await getUserContext()

    // Fallback: si por alguna raz?n no hay empresa activa en el contexto, usar perfil cl?sico
    let empresaIdParaConfig = empresaActivaId
    if (!empresaIdParaConfig) {
        const { data: perfil } = await supabase.from('perfiles').select('empresa_id').eq('user_id', user.id).single()
        empresaIdParaConfig = perfil?.empresa_id || null
    }
    if (!empresaIdParaConfig) {
        return (
            <div className="p-8 text-center bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl">
                <h2 className="text-xl font-bold text-red-600 dark:text-red-400">Sin empresa activa</h2>
                <p className="text-slate-600 dark:text-slate-400 mt-2">No se ha podido determinar una empresa activa. Selecciona una empresa desde el selector del header.</p>
            </div>
        )
    }
    const { data: empresaData } = await supabase.from('empresas').select('*').eq('id', empresaIdParaConfig).single()
    if (!empresaData) {
        return (
            <div className="p-8 text-center bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl">
                <h2 className="text-xl font-bold text-red-600 dark:text-red-400">Error: Empresa no encontrada</h2>
                <p className="text-slate-600 dark:text-slate-400 mt-2">No se han podido cargar los datos de la empresa activa seleccionada.</p>
                <p className="text-xs text-slate-500 mt-4">ID Empresa: {empresaIdParaConfig}</p>
            </div>
        )
    }
    const empresa = empresaData as unknown as Empresa
    const { data: seriesData } = await supabase.from('series_facturacion').select('id, codigo, nombre, prefijo').eq('empresa_id', empresaIdParaConfig).eq('activa', true).order('codigo')
    const series = (seriesData || []).map((s) => ({ id: s.id, codigo: s.codigo || '', nombre: s.nombre || '', prefijo: s.prefijo || '' }))
    const { data: plantillasData } = await supabase.from('plantillas_pdf').select('id, nombre').eq('empresa_id', empresaIdParaConfig).eq('activa', true).order('nombre')
    const plantillas = plantillasData || []
    return (
        <div className="space-y-6">
            <div className="text-sm text-slate-500">Configuración → Empresa</div>

            <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
                <div>
                    <h1 className="text-2xl sm:text-4xl font-serif font-bold">Configuración de Empresa</h1>
                    <p className="text-slate-600 dark:text-slate-400 text-sm sm:text-base">
                    Datos fiscales y de facturación
                    </p>
                </div>
                <DescargarDatosFiscalesButton
                    empresaId={empresaIdParaConfig}
                    nombreEmpresa={empresa.razon_social}
                />
            </div>
            <ConfiguracionEmpresaForm empresa={empresa} series={series} plantillas={plantillas} />
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { redirect } from 'next/navigation'
import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { Alert, AlertDescription } from '@/components/ui/alert'
import { Info } from 'lucide-react'
import { SeriesGrid } from '@/components/series/series-grid'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { obtenerOCrearSerieAnualAction } from '@/app/actions/series'

export const dynamic = 'force-dynamic'

export default async function SeriesPage() {
    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    const { empresaId, rol, empresas } = await getUserContext()
    const isGlobal = !empresaId && rol === 'admin'

    const { data: perfil } = await supabase
        .from('perfiles')
        .select('empresa_id')
        .eq('user_id', user.id)
        .single()

    if (!perfil?.empresa_id && !isGlobal) throw new Error('Usuario sin empresa')

    const adminClient = createAdminClient()

    // Vision Global → todas las empresas; empresa seleccionada → solo esa
    let empresaIds: string[] = isGlobal
        ? (empresas as { empresa_id: string }[]).map((e) => e.empresa_id).filter(Boolean)
        : [empresaId || perfil!.empresa_id].filter(Boolean)

    // Fallback: si Vision Global o empresaIds vacío, obtener IDs desde BD
    if (empresaIds.length === 0 || isGlobal) {
        const { data: todas } = await adminClient.from('empresas').select('id')
        const idsBd = (todas || []).map((e) => e.id)
        empresaIds = isGlobal ? idsBd : (empresaIds.length > 0 ? empresaIds : idsBd)
    }

    // Asegurar que cada empresa tiene serie del año actual (V2026, Y2026, E2026)
    for (const eid of empresaIds) {
        await obtenerOCrearSerieAnualAction(eid)
    }

    const { data: seriesRaw, error: seriesError } = empresaIds.length > 0
        ? await adminClient
            .from('series_facturacion')
            .select('*')
            .in('empresa_id', empresaIds)
            .order('empresa_id', { ascending: true })
        : { data: [] as any[], error: null }

    if (seriesError) console.error('[SeriesPage] Error:', seriesError)

    // Enriquecer con datos de empresa (la relación FK puede no estar en el schema)
    let series = seriesRaw || []
    if (series.length > 0) {
        const empIds = [...new Set(series.map((s: any) => s.empresa_id))]
        const { data: empresasData } = await adminClient
            .from('empresas')
            .select('id, razon_social, nombre_comercial, tipo_empresa')
            .in('id', empIds)
        const empMap = new Map((empresasData || []).map((e: any) => [e.id, e]))
        series = series.map((s: any) => ({ ...s, empresa: empMap.get(s.empresa_id) || null }))
    }

    return (
        <div className="space-y-6">
            {/* Breadcrumbs */}
            <div className="text-sm text-slate-500">
                Ventas › Configuración › Series de Facturación
            </div>

            {/* Header */}
            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-2xl sm:text-4xl font-serif font-bold">Series de Facturación</h1>
                    <p className="text-slate-600 dark:text-slate-400 text-sm sm:text-base">
                        Gestiona las series de numeración para tus facturas y documentos
                    </p>
                </div>
                <Link href="/ventas/configuracion/series/nueva" className="w-full sm:w-auto">
                    <Button className="w-full sm:w-auto min-h-[44px] bg-gradient-to-r from-primary to-primary/80 hover:scale-105 active:scale-95 transition-all duration-300">
                        + Nueva Serie
                    </Button>
                </Link>
            </div>

            {/* Alert Verifactu */}
            <Alert className="bg-emerald-50/50 border border-emerald-200 backdrop-blur-md dark:bg-emerald-900/20 dark:border-emerald-800">
                <Info className="h-4 w-4 text-emerald-600" />
                <AlertDescription className="text-emerald-800 dark:text-emerald-200">
                    <strong>Verifactu / RD 1007/2023:</strong> Numeración consecutiva por serie y emisor. Formato: Código-Año-Número (ej. F2026-001). Puedes editar el próximo número manualmente si necesitas ajustar la secuencia (no puede ser menor al último emitido).
                </AlertDescription>
            </Alert>

            {seriesError && (
                <p className="text-red-500 text-sm">Error al cargar: {seriesError.message}</p>
            )}
            {/* Grid de series */}
            <SeriesGrid series={series || []} />
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'
import { VencidasStats } from '@/components/vencidas/vencidas-stats'
import { VencidasTabla } from '@/components/vencidas/vencidas-tabla'

export default async function FacturasVencidasPage({
    searchParams,
}: {
    searchParams: { nivel?: string; search?: string }
}) {
    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    const { data: perfil } = await supabase
        .from('perfiles')
        .select('empresa_id')
        .eq('user_id', user.id)
        .single()

    if (!perfil) throw new Error('Usuario sin empresa')

    // Cargar facturas vencidas
    let query = supabase
        .from('vista_facturas_vencidas' as any)
        .select('*')
        .eq('empresa_id', perfil.empresa_id)

    // Filtro por nivel de criticidad
    const nivel = searchParams.nivel || 'todas'
    if (nivel !== 'todas') {
        query = query.eq('nivel_criticidad', nivel)
    }

    // Filtro de búsqueda
    const searchSanitized = sanitizeSearchInput(searchParams.search)
    if (searchSanitized) {
        query = query.or(`cliente_nombre.ilike.%${searchSanitized}%,serie.ilike.%${searchSanitized}%`)
    }

    query = query.order('dias_vencido', { ascending: false })

    const { data: facturas } = await query

    // Cargar estadísticas
    // Importante: server action para stats
    const { getEstadisticasVencidasAction } = await import('@/app/actions/recordatorios')
    const statsResult = await getEstadisticasVencidasAction()
    const stats = statsResult.success ? statsResult.data : {}

    return (
        <div className="space-y-6">
            <div className="text-sm text-slate-500">Ventas › Facturas Vencidas</div>

            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-2xl sm:text-4xl font-serif font-bold">Facturas Vencidas</h1>
                    <p className="text-slate-600 dark:text-slate-400 text-sm sm:text-base">
                        Control de impagos y gestión de recordatorios de cobro
                    </p>
                </div>
            </div>

            <VencidasStats stats={stats} />

            <VencidasTabla facturas={facturas || []} nivel={nivel} />
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { redirect, notFound } from 'next/navigation'
import Link from 'next/link'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { EditarFacturaForm } from '@/components/ventas/editar-factura-form'
import { EmpresaInfo } from '@/components/ventas/empresa-info'
import { formatFacturaDisplayNumero } from '@/lib/utils'

export default async function EditarFacturaPage({
    params,
}: {
    params: Promise<{ id: string }>
}) {
    const { id } = await params
    const supabase = await createServerClient()

    const {
        data: { user },
    } = await supabase.auth.getUser()

    if (!user) {
        redirect('/login')
    }

    let empresas: { empresa_id?: string }[] = []
    let isAdmin = false
    try {
        const ctx = await getUserContext()
        empresas = (ctx.empresas as { empresa_id?: string }[]) || []
        isAdmin = !!ctx.isAdmin
    } catch {
        redirect('/login')
    }

    // Cargar factura por id; comprobar acceso por empresas del usuario (evita 404 al editar factura de otra empresa del selector)
    const { data: factura, error } = await supabase
        .from('facturas')
        .select(
            `
      *,
      cliente:clientes(*),
      lineas:lineas_factura(*)
    `
        )
        .eq('id', id)
        .single()

    if (error || !factura) {
        notFound()
    }

    const tieneAcceso = isAdmin || empresas.some((e) => e.empresa_id === factura.empresa_id)
    if (!tieneAcceso) notFound()

    // Obtener empresa emisora
    const { data: empresa } = await supabase
        .from('empresas')
        .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, cif, email')
        .eq('id', factura.empresa_id)
        .single()

    const empresaDisplay = empresa ? {
        nombre_fiscal: empresa.razon_social || empresa.nombre_comercial,
        razon_social: empresa.razon_social,
        nombre_comercial: empresa.nombre_comercial,
        cif: empresa.cif || '',
        email: empresa.email,
        direccion: empresa.direccion,
        ciudad: empresa.ciudad,
        codigo_postal: empresa.codigo_postal,
    } : null

    // No permitir editar facturas anuladas
    if (factura.estado === 'anulada') {
        redirect(`/ventas/facturas/${id}?error=no_editable`)
    }

    // Cargar historial de cambios
    const { data: cambios } = await supabase
        .from('eventos_factura')
        .select('*')
        .eq('factura_id', id)
        .in('tipo', ['modificado', 'creado', 'pagado']) // Include 'pagado' to context
        .order('created_at', { ascending: false })
        .limit(10)

    // Cargar clientes para selector (solo si es borrador), filtrados por empresa de la factura
    let clientes: any[] = []
    if (factura.estado === 'borrador' && factura.empresa_id) {
        const { data: ces } = await (supabase.from as any)('clientes_empresas')
            .select('cliente_id')
            .eq('empresa_id', factura.empresa_id)
        const clienteIds = (ces || []).map((c: { cliente_id: string }) => c.cliente_id)
        if (clienteIds.length > 0) {
            const { data } = await supabase
                .from('clientes')
                .select('*')
                .in('id', clienteIds)
                .eq('activo', true)
                .order('nombre_fiscal')
            clientes = data || []
        }
    }

    return (
        <div className="space-y-6">
            {/* Breadcrumbs */}
            <div className="flex items-center gap-2 text-sm text-slate-500 animate-in slide-in-from-top-4 duration-500">
                <Link href="/ventas" className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors">Ventas</Link>
                <span>›</span>
                <Link href="/ventas/facturas" className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors">Facturas</Link>
                <span>›</span>
                <Link href={`/ventas/facturas/${id}`} className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors">{formatFacturaDisplayNumero(factura.serie, factura.numero)}</Link>
                <span>›</span>
                <span className="text-slate-900 dark:text-slate-100 font-medium">Editar</span>
            </div>

            {/* Empresa emisora */}
            {empresaDisplay && (
                <div className="max-w-md">
                    <EmpresaInfo empresa={empresaDisplay} />
                </div>
            )}

            {/* Formulario */}
            <EditarFacturaForm
                factura={factura as any}
                empresaId={factura.empresa_id}
                cambios={cambios || []}
                clientes={clientes}
            />
        </div>
    )
}

import { redirect, notFound } from 'next/navigation'
import Link from 'next/link'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { DetalleFacturaHeader } from '@/components/ventas/detalle-factura-header'
import { RectificativaInfoPopover } from '@/components/ventas/rectificativa-info-popover'
import { InformacionFactura } from '@/components/ventas/informacion-factura'
import { EmpresaInfo } from '@/components/ventas/empresa-info'
import { ClienteInfo } from '@/components/ventas/cliente-info'
import { LineasFacturaTable } from '@/components/ventas/lineas-factura-table'
import { ResumenFinanciero } from '@/components/ventas/resumen-financiero'
import { TimelineEventos } from '@/components/ventas/timeline-eventos'
import { formatFacturaDisplayNumero } from '@/lib/utils'
import { Factura, Cliente, LineaFactura, PagoFactura, EventoFactura } from '@/types/ventas'

interface DetalleFacturaPageProps {
    params: Promise<{ id: string }>
}

type FacturaData = Factura & {
    cliente: Cliente
    lineas: LineaFactura[]
}

export default async function DetalleFacturaPage({
    params,
}: DetalleFacturaPageProps) {
    const { id } = await params

    let supabase: Awaited<ReturnType<typeof getUserContext>>['supabase']
    let empresas: { empresa_id?: string }[] = []
    let isAdmin = false
    try {
        const ctx = await getUserContext()
        supabase = ctx.supabase
        empresas = (ctx.empresas as { empresa_id?: string }[]) || []
        isAdmin = !!ctx.isAdmin
    } catch {
        redirect('/login')
    }

    // Cargar factura por id; luego comprobar que el usuario tiene acceso a su empresa (evita 404 al cambiar de empresa en el selector)
    const { data: factura, error } = await supabase
        .from('facturas')
        .select(
            `
      *,
      cliente:clientes(*),
      lineas:lineas_factura(*)
    `
        )
        .eq('id', id)
        .single()

    if (error || !factura) {
        if (error) console.error('Error fetching invoice:', JSON.stringify({ code: error.code, message: error.message, details: error.details }))
        notFound()
    }

    const tieneAcceso = isAdmin || empresas.some((e) => e.empresa_id === factura.empresa_id)
    if (!tieneAcceso) notFound()

    const facturaData = factura as unknown as FacturaData

    // Obtener empresa emisora
    const { data: empresa } = await supabase
        .from('empresas')
        .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, cif, email')
        .eq('id', factura.empresa_id)
        .single()

    const empresaDisplay = empresa ? {
        nombre_fiscal: empresa.razon_social || empresa.nombre_comercial,
        razon_social: empresa.razon_social,
        nombre_comercial: empresa.nombre_comercial,
        cif: empresa.cif || '',
        email: empresa.email,
        direccion: empresa.direccion,
        ciudad: empresa.ciudad,
        codigo_postal: empresa.codigo_postal,
    } : null

    // Obtener eventos de la factura
    const { data: eventos } = await supabase
        .from('eventos_factura')
        .select('*')
        .eq('factura_id', id)
        .order('created_at', { ascending: false })

    // Obtener emails enviados para enriquecer el timeline con "Factura enviada por email"
    const { data: emailsFactura } = await supabase
        .from('emails_factura')
        .select('id, factura_id, enviado_at, created_at, para, estado')
        .eq('factura_id', id)
        .order('enviado_at', { ascending: false })

    // Obtener pagos
    const { data: p } = await supabase
        .from('pagos_factura')
        .select('*')
        .eq('factura_id', id)
        .order('fecha_pago', { ascending: false })

    // Cast to PagoFactura[] to handle potential type inference issues if schema is missing
    const pagos = (p || []) as unknown as PagoFactura[]

    // Obtener rectificativas relacionadas (misma empresa que la factura)
    const { data: rectificativas } = await supabase
        .from('facturas')
        .select('id, serie, numero, fecha_emision, total, estado, tipo_rectificativa, motivo_rectificacion')
        .eq('factura_rectificada_id', id)
        .eq('empresa_id', factura.empresa_id)
        .eq('es_rectificativa', true)
        .order('created_at', { ascending: false })

    const totalPagadoFromPagos = pagos?.reduce((sum, p) => sum + Number(p.importe), 0) || 0
    // Si estado=pagada, usar factura.pagado o total para que Resumen Financiero muestre Pagada correctamente
    const totalPagado = factura.estado === 'pagada'
        ? (Number(factura.pagado) || Number(factura.total) || totalPagadoFromPagos)
        : totalPagadoFromPagos

    // Total efectivo: respeta el signo de retencion_porcentaje
    // Porcentaje negativo (-1%) = resta del total; positivo = suma
    const retPct = Number(factura.retencion_porcentaje) || 0
    // importe_retencion se almacena como ABS en BD; usamos Math.abs para compatibilidad con datos legacy
    const importeRetencionAbs = factura.importe_retencion != null
        ? Math.abs(Number(factura.importe_retencion))
        : Math.abs(retPct * Number(factura.base_imponible) / 100)
    // El efecto sobre el total sigue el signo del porcentaje: negativo = resta, positivo = suma
    const efectoRetencion = retPct < 0 ? -importeRetencionAbs : importeRetencionAbs
    const totalEfectivo = Number(factura.base_imponible) + Number(factura.iva) + efectoRetencion + (Number(factura.importe_recargo) || 0)
    const pendiente = Math.max(0, totalEfectivo - totalPagado)

    // Combinar eventos de estado con eventos de envío de email
    const emailEventos: EventoFactura[] = (emailsFactura || [])
        .filter((e: any) => e.estado === 'enviado')
        .map((e: any) => {
            const paraTexto =
                Array.isArray(e.para)
                    ? (e.para[0] || '')
                    : typeof e.para === 'string'
                        ? (e.para.split(',')[0] || e.para)
                        : ''

            return {
                id: `email-${e.id}`,
                factura_id: e.factura_id,
                tipo: 'enviado',
                descripcion: paraTexto
                    ? `Factura enviada por email a ${paraTexto}`
                    : 'Factura enviada por email',
                created_at: (e.enviado_at || e.created_at) as string | null,
                // Rellenamos campos opcionales que no usa el UI
                user_id: null as any,
                empresa_id: null as any,
            } as unknown as EventoFactura
        })

    const timelineEventos: EventoFactura[] = [
        ...((eventos as unknown as EventoFactura[]) || []),
        ...emailEventos,
    ].sort((a, b) => {
        const da = a.created_at || ''
        const db = b.created_at || ''
        return db.localeCompare(da)
    })

    // Header con acciones
    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Breadcrumbs */}
            <div className="flex items-center gap-2 text-sm text-slate-500 overflow-x-auto min-w-0 pb-1">
                <Link href="/ventas" className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors shrink-0">Ventas</Link>
                <span className="shrink-0">›</span>
                <Link href="/ventas/facturas" className="hover:text-slate-700 dark:hover:text-slate-300 transition-colors shrink-0">Facturas</Link>
                <span className="shrink-0">›</span>
                <span className="text-slate-900 dark:text-slate-100 font-medium truncate min-w-0">
                    {formatFacturaDisplayNumero(facturaData.serie, facturaData.numero)}
                </span>
            </div>

            {/* Aviso de Rectificativa */}
            {facturaData.es_rectificativa && (
                <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg p-4 flex items-start gap-3">
                    <div className="p-2 bg-red-100 dark:bg-red-900/40 rounded-full">
                        <svg className="h-5 w-5 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                        </svg>
                    </div>
                    <div className="flex-1">
                        <h3 className="font-semibold text-red-900 dark:text-red-200 flex items-center gap-2">
                            Factura Rectificativa
                            <RectificativaInfoPopover variant="banner" />
                        </h3>
                        <p className="text-sm text-red-700 dark:text-red-300 mt-1">
                            Esta es una factura rectificativa de tipo <strong>{facturaData.tipo_rectificativa}</strong>.
                            {facturaData.motivo_rectificacion && (
                                <span className="block mt-1">Motivo: {facturaData.motivo_rectificacion}</span>
                            )}
                        </p>
                        {facturaData.factura_rectificada_id && (
                            <div className="mt-2 text-sm">
                                <Link
                                    href={`/ventas/facturas/${facturaData.factura_rectificada_id}`}
                                    className="text-red-700 dark:text-red-300 underline hover:no-underline font-medium"
                                >
                                    Ver factura original rectificada
                                </Link>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Aviso si tiene rectificativas asociadas */}
            {rectificativas && rectificativas.length > 0 && (
                <div className="bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800 rounded-lg p-4">
                    <h3 className="font-semibold text-orange-900 dark:text-orange-200 flex items-center gap-2 mb-3">
                        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                        </svg>
                        Facturas Rectificativas Asociadas ({rectificativas.length})
                        <RectificativaInfoPopover variant="section" />
                    </h3>
                    <div className="space-y-2">
                        {rectificativas.map((rect) => (
                            <Link
                                key={rect.id}
                                href={`/ventas/facturas/${rect.id}`}
                                className="block p-3 bg-white dark:bg-slate-900 border border-orange-200 dark:border-slate-700 rounded-md hover:shadow-sm transition-shadow group"
                            >
                                <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-2">
                                    <div className="flex flex-wrap items-center gap-2 min-w-0">
                                        <span className="font-mono font-medium group-hover:text-primary transition-colors">
                                            {rect.serie}-{rect.numero}
                                        </span>
                                        <span className="text-sm text-slate-500">
                                            ({new Date(rect.fecha_emision).toLocaleDateString('es-ES')})
                                        </span>
                                        <span className="px-2 py-0.5 bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300 text-xs rounded-full border border-red-200 dark:border-red-800 capitalize">
                                            {rect.tipo_rectificativa}
                                        </span>
                                    </div>
                                    <div className="font-semibold text-red-600 shrink-0">
                                        {Number(rect.total).toLocaleString('es-ES', { style: 'currency', currency: 'EUR' })}
                                    </div>
                                </div>
                                {rect.motivo_rectificacion && (
                                    <div className="text-sm text-slate-500 mt-1 line-clamp-1 italic">
                                        &quot;{rect.motivo_rectificacion}&quot;
                                    </div>
                                )}
                            </Link>
                        ))}
                    </div>
                </div>
            )}

            {/* Header con acciones */}
            <DetalleFacturaHeader factura={facturaData} />

            {/* Contenido en 2 columnas */}
            <div className="grid gap-4 sm:gap-6 lg:grid-cols-12 min-w-0">
                {/* Columna Principal (8/12) */}
                <div className="lg:col-span-8 space-y-4 sm:space-y-6 min-w-0">
                    <div className="grid gap-4 sm:gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
                        {/* Información de la Factura */}
                        <InformacionFactura factura={facturaData} />

                        {/* Empresa emisora */}
                        {empresaDisplay && <EmpresaInfo empresa={empresaDisplay} />}

                        {/* Cliente */}
                        <ClienteInfo cliente={facturaData.cliente} />
                    </div>

                    {/* Líneas de Factura */}
                    <LineasFacturaTable lineas={facturaData.lineas} />
                </div>

                {/* Columna Lateral (4/12) */}
                <div className="lg:col-span-4 space-y-6">
                    {/* Resumen Financiero */}
                    <ResumenFinanciero
                        factura={facturaData}
                        totalPagado={totalPagado}
                        pendiente={pendiente}
                        totalEfectivo={totalEfectivo}
                    />

                    {/* Timeline de Eventos */}
                    <TimelineEventos eventos={timelineEventos} />
                </div>
            </div>
        </div>
    )
}

'use client'

import { useState, use, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import Link from 'next/link'
import { ArrowLeft, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'

import { RegistrarPagoForm } from '@/components/ventas/pagos/registrar-pago-form'
import { ResumenFacturaPago } from '@/components/ventas/pagos/resumen-factura-pago'
import { HistorialPagosCard } from '@/components/ventas/pagos/historial-pagos-card'

interface PageProps {
    params: Promise<{ id: string }>
}

import { Factura, Pago } from '@/types/ventas'

interface FacturaWithCliente extends Factura {
    cliente: {
        nombre_fiscal: string
    }
}

export default function RegistrarPagoPage({ params }: PageProps) {
    const { id } = use(params)
    const router = useRouter()
    const [factura, setFactura] = useState<FacturaWithCliente | null>(null)
    const [pagos, setPagos] = useState<Pago[]>([])
    const [loading, setLoading] = useState(true)

    // State for realtime preview
    const [currentImporteInput, setCurrentImporteInput] = useState(0)

    const supabase = createClient()

    useEffect(() => {
        async function loadData() {
            try {
                const { data: { user } } = await supabase.auth.getUser()
                if (!user) return

                const { data: perfil } = await supabase
                    .from('perfiles')
                    .select('empresa_id, rol')
                    .eq('user_id', user.id)
                    .single()

                const { data: ue } = await supabase
                    .from('usuarios_empresas')
                    .select('empresa_activa, empresa_id')
                    .eq('user_id', user.id)

                const isAdmin = perfil?.rol === 'admin'
                const empresaActiva = ue?.find((x: any) => x.empresa_activa)
                const empresaId = empresaActiva?.empresa_id || perfil?.empresa_id
                const isGlobal = isAdmin && !empresaActiva

                let query = supabase
                    .from('facturas')
                    .select(`*, cliente:clientes(nombre_fiscal)`)
                    .eq('id', id)
                if (!isGlobal && empresaId) query = query.eq('empresa_id', empresaId)
                const { data: fac } = await query.single()

                if (fac) {
                    setFactura(fac)

                    // Set input default if not set
                    if (!fac.pagado) {
                        setCurrentImporteInput(prev => prev === 0 ? fac.total : prev)
                    }

                    // Fetch Payments History
                    const { data: p } = await supabase
                        .from('pagos_factura')
                        .select('*')
                        .eq('factura_id', id)
                        .order('fecha_pago', { ascending: false })

                    setPagos(p || [])
                }

            } catch (e) {
                console.error(e)
            } finally {
                setLoading(false)
            }
        }
        loadData()
    }, [id, supabase])

    if (loading) {
        return (
            <div className="flex h-[80vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        )
    }

    if (!factura) return <div>Factura no encontrada</div>

    // Redirigir si la factura ya está pagada
    if (factura.estado === 'pagada') {
        router.replace(`/ventas/facturas/${id}`)
        return null
    }

    // Calculate generic accumulated payment (if not using 'pagado' column yet, calculate manually)
    const totalPagado = pagos.reduce((acc, p) => acc + (Number(p.importe) || 0), 0)
    const pendiente = Math.max(0, factura.total - totalPagado)

    return (
        <div className="space-y-6">
            {/* Breadcrumbs & Header */}
            <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between animate-in slide-in-from-top-4 duration-500">
                <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm text-slate-500">
                        <Link href="/ventas/facturas" className="hover:text-slate-900 transition-colors">Facturas</Link>
                        <span>›</span>
                        <Link href={`/ventas/facturas/${id}`} className="hover:text-slate-900 transition-colors">
                            {factura.serie}-{factura.numero}
                        </Link>
                        <span>›</span>
                        <span className="font-medium text-slate-900 dark:text-slate-100">Registrar Pago</span>
                    </div>
                    <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
                        Registrar Pago
                    </h1>
                    <p className="text-slate-500">
                        {factura.serie}-{factura.numero} · {factura.cliente.nombre_fiscal}
                    </p>
                </div>
                <div className="flex gap-3">
                    <Button variant="outline" asChild>
                        <Link href={`/ventas/facturas/${id}`}>
                            <ArrowLeft className="mr-2 h-4 w-4" />
                            Cancelar
                        </Link>
                    </Button>
                </div>
            </div>

            <div className="grid lg:grid-cols-12 gap-8 items-start">
                {/* Left Column: Form */}
                <div className="lg:col-span-7 space-y-6">
                    <RegistrarPagoForm
                        facturaId={factura.id}
                        empresaId={factura.empresa_id}
                        pendienteActual={pendiente}
                        onImporteChange={setCurrentImporteInput}
                    />
                </div>

                {/* Right Column: Summary & History */}
                <div className="lg:col-span-5 space-y-6">
                    <ResumenFacturaPago
                        factura={factura}
                        pagadoHastaHoy={totalPagado}
                        importePagoActual={currentImporteInput}
                    />
                    <HistorialPagosCard pagos={pagos} />
                </div>
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState, use } from 'react'
import Link from 'next/link'
import { createClient } from '@/lib/supabase/client'
import { PdfLayoutPreview } from '@/components/ventas/pdf/pdf-layout-preview'
import { PdfOptionsPanel, PdfOptions, getPlantillasDisponibles } from '@/components/ventas/pdf/pdf-options-panel'
import { Button } from '@/components/ui/button'
import { ArrowLeft, Loader2, FileDown, FileText } from 'lucide-react'
import type { Empresa } from '@/components/ventas/pdf/pdf-document'
import { FacturaWithRelations, FacturaPdfDocument } from '@/components/ventas/pdf/pdf-document'
import { listarEmpresasUsuarioAction } from '@/app/actions/usuarios-empresas'
import { clientConfig } from '@/config/clients'

const EMPRESA_VILLEGAS_ID = '4b77324c-a10e-4714-b0a4-df4b9c5f6ca5'
const EMPRESA_YENIFER_ID = 'e9a30c7d-eb2a-4c7a-91a6-a8bfe8f2278a'
const EMPRESA_EDISON_ID = 'af15f25a-7ade-4de8-9241-a42e1b8407da'

interface PageProps {
    params: Promise<{ id: string }>
}

export default function FacturaPdfPage({ params }: PageProps) {
    const { id } = use(params)
    const [factura, setFactura] = useState<FacturaWithRelations | null>(null)
    const [empresa, setEmpresa] = useState<Empresa | null>(null)
    const [empresaActivaId, setEmpresaActivaId] = useState<string | null>(null)
    const [loading, setLoading] = useState(true)
    const [downloading, setDownloading] = useState(false)
    const [options, setOptions] = useState<PdfOptions>({
        plantilla: 'estandar',
        idioma: 'es',
        incluirLogo: false,
        notasPie: 'Gracias por su confianza.',
        incluirDatosBancarios: true
    })

    const supabase = createClient()

    useEffect(() => {
        async function loadData() {
            try {
                const { data: { user } } = await supabase.auth.getUser()
                if (!user) return

                const [empresasResult, { data: perfil }] = await Promise.all([
                    listarEmpresasUsuarioAction(),
                    supabase.from('perfiles').select('empresa_id').eq('user_id', user.id).single()
                ])

                const isGlobal = empresasResult.success && empresasResult.data?.isGlobal
                const activaId = empresasResult.success ? empresasResult.data?.empresaActivaId ?? null : null
                const empresaIds = (empresasResult.success && empresasResult.data?.empresas)
                    ? (empresasResult.data.empresas as { id: string }[]).map((e) => e.id)
                    : perfil?.empresa_id ? [perfil.empresa_id] : []

                setEmpresaActivaId(activaId ?? null)

                const { data: fac, error } = await supabase
                    .from('facturas')
                    .select(`
                *,
                cliente:clientes(*),
                lineas:lineas_factura(*)
            `)
                    .eq('id', id)
                    .single()

                if (error || !fac) {
                    console.error('Error loading invoice', error)
                    return
                }
                const tieneAcceso = isGlobal || empresaIds.includes(fac.empresa_id)
                if (!tieneAcceso) return

                setFactura(fac)

                const plantillas = getPlantillasDisponibles(activaId ?? null)

                // Plantilla por defecto según empresa de la factura:
                // - Villegas: Premium (logo y colores marca)
                // - Yenifer / Edison: Estándar (sin logo por defecto)
                // - Otras: la primera disponible según empresa activa / visión global
                let defaultPlantilla = plantillas[0]?.value ?? 'estandar'
                if (fac.empresa_id === EMPRESA_VILLEGAS_ID && plantillas.some(p => p.value === 'premium')) {
                    defaultPlantilla = 'premium'
                } else if (fac.empresa_id === EMPRESA_YENIFER_ID || fac.empresa_id === EMPRESA_EDISON_ID) {
                    defaultPlantilla = 'estandar'
                }

                setOptions(prev => ({ ...prev, plantilla: defaultPlantilla }))

                const { data: emp } = await supabase
                    .from('empresas')
                    .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, provincia, pais, cif, email, iban, banco, pie_factura')
                    .eq('id', fac.empresa_id)
                    .single()

                if (emp) {
                    setEmpresa({
                        nombre_fiscal: emp.razon_social || emp.nombre_comercial || 'Empresa',
                        direccion: emp.direccion || '',
                        ciudad: emp.ciudad || '',
                        codigo_postal: emp.codigo_postal || '',
                        cif: emp.cif || '',
                        email: emp.email || undefined,
                        iban: emp.iban || undefined,
                        banco: emp.banco || undefined,
                        pie_factura: emp.pie_factura || undefined,
                    })
                } else {
                    setEmpresa({
                        nombre_fiscal: 'Empresa',
                        direccion: '',
                        ciudad: '',
                        codigo_postal: '',
                        cif: '',
                    })
                }
            } catch (e) {
                console.error(e)
            } finally {
                setLoading(false)
            }
        }
        loadData()
    }, [id, supabase])

    const handleDownloadTemplate = async () => {
        if (!factura || !empresa) return
        setDownloading(true)
        try {
            // Generar el mismo PDF que la vista previa (mismo componente y datos) para que el archivo guardado sea idéntico
            const { pdf } = await import('@react-pdf/renderer')
            const logoUrl = typeof window !== 'undefined' ? `${window.location.origin}${clientConfig.logoPath}` : undefined
            const doc = (
                <FacturaPdfDocument
                    factura={factura}
                    empresa={empresa}
                    options={options}
                    logoUrl={logoUrl}
                />
            )
            const blob = await pdf(doc).toBlob()
            const url = URL.createObjectURL(blob)
            const a = document.createElement('a')
            a.href = url
            a.download = `${factura.serie ?? 'FAC'}-${factura.numero ?? id}.pdf`
            document.body.appendChild(a)
            a.click()
            document.body.removeChild(a)
            URL.revokeObjectURL(url)
        } catch (e) {
            console.error(e)
        } finally {
            setDownloading(false)
        }
    }

    const handleDownloadOriginal = () => {
        if ((factura as any)?.archivo_url) {
            window.open((factura as any).archivo_url, '_blank')
        }
    }

    const esExterna = !!(factura as any)?.es_externa
    const tieneArchivoOriginal = !!(factura as any)?.archivo_url

    if (loading) {
        return (
            <div className="flex h-[80vh] items-center justify-center">
                <Loader2 className="h-8 w-8 animate-spin text-slate-400" />
            </div>
        )
    }

    if (!factura) {
        return <div>Factura no encontrada o acceso denegado.</div>
    }

    return (
        <div className="space-y-6">
            {/* Breadcrumbs & Header */}
            <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between animate-in slide-in-from-top-4 duration-500">
                <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm text-slate-500">
                        <Link href="/ventas/facturas" className="hover:text-slate-900 transition-colors">Facturas</Link>
                        <span>›</span>
                        <Link href={`/ventas/facturas/${id}`} className="hover:text-slate-900 transition-colors">
                            {factura.serie}-{factura.numero}
                        </Link>
                        <span>›</span>
                        <span className="font-medium text-slate-900 dark:text-slate-100">Generar PDF</span>
                    </div>
                    <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
                        Generar Documento
                    </h1>
                </div>
                <div className="flex flex-col sm:flex-row flex-wrap gap-2 sm:gap-3 w-full sm:w-auto">
                    <Button variant="outline" asChild className="w-full sm:w-auto min-h-[44px]">
                        <Link href={`/ventas/facturas/${id}`}>
                            <ArrowLeft className="mr-2 h-4 w-4" />
                            Volver
                        </Link>
                    </Button>
                    {tieneArchivoOriginal && (
                        <Button variant="outline" onClick={handleDownloadOriginal} className="w-full sm:w-auto min-h-[44px]">
                            <FileDown className="mr-2 h-4 w-4" />
                            Descargar PDF original
                        </Button>
                    )}
                    <Button onClick={handleDownloadTemplate} disabled={downloading} className="w-full sm:w-auto min-h-[44px]">
                        {downloading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <FileText className="mr-2 h-4 w-4" />}
                        {downloading ? 'Generando...' : (tieneArchivoOriginal ? 'Generar PDF con plantilla' : 'Descargar PDF')}
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 items-start">
                {/* Left: Preview (8 cols) */}
                <div className="lg:col-span-8 space-y-4">
                    <PdfLayoutPreview
                        factura={factura}
                        empresa={empresa || { nombre_fiscal: 'Empresa', direccion: '', ciudad: '', codigo_postal: '', cif: '' }}
                        options={options}
                    />
                </div>

                {/* Right: Options (4 cols) */}
                <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-6">
                    {tieneArchivoOriginal && (
                        <div className="rounded-lg border border-amber-200 bg-amber-50 dark:border-amber-800 dark:bg-amber-950/30 p-4 space-y-2">
                            <p className="text-sm font-medium text-amber-800 dark:text-amber-200">
                                PDF original disponible
                            </p>
                            <p className="text-xs text-amber-700 dark:text-amber-300">
                                Puedes descargar el PDF subido (histórico/importado) o generar uno nuevo con la plantilla de la empresa.
                            </p>
                        </div>
                    )}
                    <PdfOptionsPanel
                        options={options}
                        onChange={setOptions}
                        onDownload={handleDownloadTemplate}
                        esExterna={esExterna}
                        tieneArchivoOriginal={tieneArchivoOriginal}
                        empresaActivaId={empresaActivaId}
                        facturaId={id}
                    />
                </div>
            </div>
        </div>
    )
}

import { createServerClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { NuevaFacturaForm } from '@/components/ventas/nueva-factura-form'
import { EmpresaInfo } from '@/components/ventas/empresa-info'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { obtenerOCrearSerieAnualAction } from '@/app/actions/series'

export const dynamic = 'force-dynamic'

export default async function NuevaFacturaPage() {
    const supabase = await createServerClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    const { empresaId: empresaActivaId, rol, empresas } = await getUserContext()
    const isGlobal = !empresaActivaId && rol === 'admin'

    const { data: perfil } = await supabase
        .from('perfiles')
        .select('empresa_id')
        .eq('user_id', user.id)
        .single()

    const empresaId = empresaActivaId || perfil?.empresa_id
    if (!empresaId && !isGlobal) {
        throw new Error('Usuario sin empresa asignada')
    }

    const empresaIdParaForm = isGlobal ? 'ALL' : empresaId!
    const empresaIds = (empresas as { empresa_id: string; empresa?: { razon_social?: string; nombre_comercial?: string } }[]).map((e) => e.empresa_id).filter(Boolean)
    const empresasParaSelector = (empresas as { empresa_id: string; empresa?: { razon_social?: string; nombre_comercial?: string } }[])
        .filter((e) => e.empresa_id)
        .map((e) => ({
            id: e.empresa_id,
            nombre: (e.empresa?.nombre_comercial || e.empresa?.razon_social || e.empresa_id) as string
        }))
    const empresaIdParaDatos = empresaId || empresaIds[0] || ''
    const empresaIdsParaSeries = isGlobal ? empresaIds : (empresaId ? [empresaId] : [])

    // Asegurar que cada empresa tiene serie del año actual (V2026, Y2026, E2026 → V2027, Y2027, E2027 en 2027)
    for (const eid of empresaIdsParaSeries) {
        await obtenerOCrearSerieAnualAction(eid)
    }

    const { data: empresa } = await supabase
        .from('empresas')
        .select('*')
        .eq('id', empresaIdParaDatos)
        .single()

    // Config de todas las empresas (para retencion_predeterminada al cambiar empresa en Vision Global)
    const { data: empresasConfigs } = isGlobal && empresaIds.length > 0
        ? await supabase
            .from('empresas')
            .select('id, retencion_predeterminada')
            .in('id', empresaIds)
        : { data: [] }
    const empresasConfigsMap: Record<string, { retencion_predeterminada?: number | null }> = {}
    for (const e of empresasConfigs || []) {
        empresasConfigsMap[e.id] = { retencion_predeterminada: e.retencion_predeterminada }
    }

    const empresaIdsParaClientes = isGlobal ? empresaIds : (empresaId ? [empresaId] : [])
    const clientesByEmpresa: Record<string, any[]> = {}
    for (const eid of empresaIdsParaClientes) {
        const { data: ces } = await (supabase.from as any)('clientes_empresas')
            .select('cliente_id')
            .eq('empresa_id', eid)
        const clienteIds = (ces || []).map((c: { cliente_id: string }) => c.cliente_id)
        if (clienteIds.length > 0) {
            const { data } = await supabase
                .from('clientes')
                .select('*')
                .in('id', clienteIds)
                .eq('activo', true)
                .order('nombre_fiscal')
            clientesByEmpresa[eid] = data || []
        } else {
            clientesByEmpresa[eid] = []
        }
    }
    const clientes = clientesByEmpresa[empresaId || empresaIds[0] || ''] || []

    const { data: series } = empresaIdsParaSeries.length > 0
        ? await supabase
            .from('series_facturacion')
            .select('id, codigo, nombre, predeterminada, empresa_id')
            .in('empresa_id', empresaIdsParaSeries)
            .eq('activa', true)
            .order('predeterminada', { ascending: false })
        : { data: [] }

    return (
        <div className="space-y-6 w-full px-0">
            {/* Breadcrumbs */}
            <div className="flex items-center gap-2 text-sm text-slate-500">
                <span className="hover:text-slate-700 dark:hover:text-slate-300 cursor-pointer">Ventas</span>
                <span>›</span>
                <span className="hover:text-slate-700 dark:hover:text-slate-300 cursor-pointer">Facturas</span>
                <span>›</span>
                <span className="text-slate-900 dark:text-slate-100 font-medium">Nueva Factura</span>
            </div>

            {/* Page Header */}
            <div>
                <h1 className="text-2xl sm:text-3xl font-serif font-bold text-slate-900 dark:text-slate-100 tracking-tight">
                    Nueva Factura
                </h1>
                <p className="text-slate-600 dark:text-slate-400 mt-1 text-lg">
                    Completa los datos para generar una nueva factura de venta
                </p>
            </div>

            {/* Empresa emisora (oculto en Vision Global: se selecciona en el form) */}
            {empresa && empresaIdParaForm !== 'ALL' && (
                <div className="max-w-md">
                    <EmpresaInfo empresa={{
                        nombre_fiscal: empresa.razon_social || empresa.nombre_comercial,
                        razon_social: empresa.razon_social,
                        nombre_comercial: empresa.nombre_comercial,
                        cif: empresa.cif || '',
                        email: empresa.email,
                        direccion: empresa.direccion,
                        ciudad: empresa.ciudad,
                        codigo_postal: empresa.codigo_postal,
                    }} />
                </div>
            )}

            {/* Formulario */}
            <NuevaFacturaForm
                clientes={clientes || []}
                clientesByEmpresa={clientesByEmpresa}
                series={(series || []).map(s => ({
                    ...s,
                    predeterminada: s.predeterminada === null ? undefined : s.predeterminada,
                    empresa_id: s.empresa_id === null ? undefined : s.empresa_id
                }))}
                empresaId={empresaIdParaForm}
                empresaConfig={empresa}
                empresasConfigs={empresasConfigsMap}
                defaultEmpresaId={empresaIds[0]}
                empresas={empresasParaSelector}
            />
        </div>
    )
}

import { createAdminClient } from '@/lib/supabase/admin'
import { FacturasTable } from '@/components/ventas/facturas-table'
import { FacturasStats } from '@/components/ventas/facturas-stats'
import { FacturasFilters } from '@/components/ventas/facturas-filters'
import { Button } from '@/components/ui/button'
import { Plus } from 'lucide-react'
import Link from 'next/link'
import { FacturaWithCliente } from '@/types/ventas'

interface SearchParams {
    q?: string
    estado?: string
    desde?: string
    hasta?: string
    mes?: string
    anio?: string
    serie?: string
    page?: string
    pageSize?: string
    orden?: string
    clienteId?: string
    clienteLabel?: string
}

import { getUserContext } from '@/app/actions/usuarios-empresas'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'

export const dynamic = 'force-dynamic'

export default async function FacturasPage({
    searchParams,
}: {
    searchParams: Promise<SearchParams>
}) {
    const params = await searchParams
    const adminClient = createAdminClient()

    // Obtener contexto de empresa (soporta Global/Null)
    const { empresaId, empresas } = await getUserContext()

    // Series para filtro: por empresa o solo de empresas del usuario (evita duplicados GRAL de empresas huérfanas)
    const empresaIds = (empresas as { empresa_id?: string }[]).map((e) => e.empresa_id).filter(Boolean) as string[]
    const seriesQuery = empresaId
        ? adminClient.from('series_facturacion').select('id, codigo, nombre').eq('empresa_id', empresaId).eq('activa', true).order('codigo')
        : empresaIds.length > 0
            ? adminClient.from('series_facturacion').select('id, codigo, nombre').in('empresa_id', empresaIds).eq('activa', true).order('codigo')
            : adminClient.from('series_facturacion').select('id, codigo, nombre').eq('activa', true).order('codigo')
    const { data: series } = await seriesQuery

    // Resolver ordenación
    type OrderField = 'fecha_emision' | 'fecha_vencimiento' | 'total' | 'estado' | 'numero_orden'
    let orderField: OrderField = 'fecha_emision'
    let orderAsc = false
    let orderByCliente = false
    let orderByNumero = false

    switch (params.orden) {
        case 'fecha_asc':
            orderField = 'fecha_emision'; orderAsc = true; break
        case 'fecha_desc':
            orderField = 'fecha_emision'; orderAsc = false; break
        case 'fecha_vencimiento_asc':
            orderField = 'fecha_vencimiento'; orderAsc = true; break
        case 'fecha_vencimiento_desc':
            orderField = 'fecha_vencimiento'; orderAsc = false; break
        case 'cliente_asc':
            orderByCliente = true; orderAsc = true; break
        case 'cliente_desc':
            orderByCliente = true; orderAsc = false; break
        case 'total_desc':
            orderField = 'total'; orderAsc = false; break
        case 'total_asc':
            orderField = 'total'; orderAsc = true; break
        case 'numero_asc':
            orderByNumero = true; orderAsc = true; break
        case 'numero_desc':
            orderByNumero = true; orderAsc = false; break
        case 'estado_asc':
            orderField = 'estado'; orderAsc = true; break
        case 'estado_desc':
            orderField = 'estado'; orderAsc = false; break
        default:
            orderField = 'fecha_emision'; orderAsc = false; break
    }

    let query = adminClient
        .from('facturas')
        .select(`
      *,
      cliente:clientes(nombre_fiscal, nombre_comercial, cif),
      empresa:empresas(nombre_comercial)
    `, { count: 'exact' })

    if (orderByCliente) {
        query = query.order('nombre_fiscal', { referencedTable: 'clientes', ascending: orderAsc, nullsFirst: false })
    } else if (orderByNumero) {
        query = query.order('serie', { ascending: orderAsc }).order('numero_orden', { ascending: orderAsc, nullsFirst: false })
    } else {
        query = query.order(orderField, { ascending: orderAsc })
    }

    if (empresaId) query = query.eq('empresa_id', empresaId)

    // Aplicar filtros de búsqueda (cliente, CIF/NIF, número, serie, importe)
    const q = sanitizeSearchInput(params.q)
    if (q) {
        // Para CIF/NIF: búsqueda con y sin espacios/guiones (ej. "B 12345678" vs "B12345678")
        const qNorm = q.replace(/[\s\-.]/g, '')
        const cifPatterns = qNorm !== q ? [`cif.ilike.%${q}%`, `cif.ilike.%${qNorm}%`] : [`cif.ilike.%${q}%`]
        const orCif = cifPatterns.join(',')
        const { data: clientesMatch } = await adminClient
            .from('clientes')
            .select('id')
            .or(`nombre_fiscal.ilike.%${q}%,nombre_comercial.ilike.%${q}%,${orCif}`)

        const clienteIds = clientesMatch?.map((c) => c.id) ?? []
        const orParts: string[] = [
            `numero.ilike.%${q}%`,
            `serie.ilike.%${q}%`,
        ]
        if (clienteIds.length > 0) {
            orParts.push(`cliente_id.in.(${clienteIds.join(',')})`)
        }
        // Búsqueda por importe (ej. "1210" o "1.210")
        const importeNum = parseFloat(q.replace(/\./g, '').replace(',', '.'))
        if (!Number.isNaN(importeNum)) {
            orParts.push(`total.eq.${importeNum}`)
        }
        query = query.or(orParts.join(','))
    }

    if (params.estado && params.estado !== 'todas') {
        if (params.estado === 'externa-emitida') {
            // Externas: todas las facturas con es_externa=true (emitida, pagada, borrador, etc.)
            query = query.eq('es_externa', true)
        } else if (params.estado === 'enviada') {
            // Facturas que tienen al menos un email enviado correctamente
            const { data: facturasEnviadas } = await adminClient
                .from('emails_factura')
                .select('factura_id')
                .eq('estado', 'enviado')
            const idsEnviadas = [...new Set((facturasEnviadas || []).map((e: any) => e.factura_id))]
            if (idsEnviadas.length > 0) {
                query = query.in('id', idsEnviadas)
            } else {
                // Ninguna factura enviada, devolver resultado vacío
                query = query.eq('id', '00000000-0000-0000-0000-000000000000')
            }
        } else if (params.estado === 'emitida') {
            // Solo estado emitida: excluir las que ya fueron enviadas por email
            const { data: facturasEnviadas } = await adminClient
                .from('emails_factura')
                .select('factura_id')
                .eq('estado', 'enviado')
            const idsEnviadas = new Set((facturasEnviadas || []).map((e: any) => e.factura_id))
            query = query.eq('estado', 'emitida')
            if (idsEnviadas.size > 0) {
                const idsStr = Array.from(idsEnviadas).map((id) => `"${id}"`).join(',')
                query = query.not('id', 'in', `(${idsStr})`)
            }
        } else {
            query = query.eq('estado', params.estado)
        }
    }

    if (params.clienteId) query = query.eq('cliente_id', params.clienteId)
    if (params.serie) query = query.eq('serie_id', params.serie)

    if (params.mes || params.anio) {
        const anio = params.anio ? parseInt(params.anio, 10) : new Date().getFullYear()
        const mes = params.mes ? parseInt(params.mes, 10) : null
        if (mes) {
            const desde = `${anio}-${String(mes).padStart(2, '0')}-01`
            const hasta = `${anio}-${String(mes).padStart(2, '0')}-${String(new Date(anio, mes, 0).getDate()).padStart(2, '0')}`
            query = query.gte('fecha_emision', desde).lte('fecha_emision', hasta)
        } else if (params.anio) query = query.gte('fecha_emision', `${anio}-01-01`).lte('fecha_emision', `${anio}-12-31`)
    } else {
        if (params.desde) query = query.gte('fecha_emision', params.desde)
        if (params.hasta) query = query.lte('fecha_emision', params.hasta)
    }

    const page = parseInt(params.page || '1')
    const pageSize = Math.min(50, Math.max(10, parseInt(params.pageSize || '10', 10) || 10))
    const from = (page - 1) * pageSize
    query = query.range(from, from + pageSize - 1)

    const { data: facturas, error, count } = await query
    if (error) {
        console.error('Error al obtener facturas:', error)
        throw new Error('Error al cargar facturas')
    }

    // IDs de facturas enviadas por email (para mostrar badge "Enviada" en la tabla)
    let enviadaIds: string[] = []
    if (facturas && facturas.length > 0) {
        const ids = facturas.map((f: any) => f.id)
        const { data: emails } = await adminClient
            .from('emails_factura')
            .select('factura_id')
            .in('factura_id', ids)
            .eq('estado', 'enviado')
        if (emails) {
            enviadaIds = [...new Set(emails.map((e: any) => e.factura_id))]
        }
    }

    // Stats filtrados (mismos filtros que la tabla)
    let statsQuery = adminClient.from('facturas').select('total, estado, fecha_emision')
    if (empresaId) {
        statsQuery = statsQuery.eq('empresa_id', empresaId)
    }

    // Aplicar mismos filtros que la query principal (sin paginación)
    if (params.q?.trim()) {
        const q = String(params.q).trim()
        const qNorm = q.replace(/[\s\-.]/g, '')
        const cifPatterns = qNorm !== q ? [`cif.ilike.%${q}%`, `cif.ilike.%${qNorm}%`] : [`cif.ilike.%${q}%`]
        const { data: clientesMatch } = await adminClient.from('clientes').select('id').or(`nombre_fiscal.ilike.%${q}%,nombre_comercial.ilike.%${q}%,${cifPatterns.join(',')}`)
        const clienteIds = clientesMatch?.map((c: any) => c.id) ?? []
        const orParts: string[] = [`numero.ilike.%${q}%`, `serie.ilike.%${q}%`]
        if (clienteIds.length > 0) orParts.push(`cliente_id.in.(${clienteIds.join(',')})`)
        const importeNum = parseFloat(q.replace(/\./g, '').replace(',', '.'))
        if (!Number.isNaN(importeNum)) orParts.push(`total.eq.${importeNum}`)
        statsQuery = statsQuery.or(orParts.join(','))
    }
    if (params.estado && params.estado !== 'todas') {
        if (params.estado === 'externa-emitida') statsQuery = statsQuery.eq('es_externa', true)
        else if (params.estado === 'enviada') {
            const { data: fe } = await adminClient.from('emails_factura').select('factura_id').eq('estado', 'enviado')
            const ids = [...new Set((fe || []).map((e: any) => e.factura_id))]
            statsQuery = ids.length > 0 ? statsQuery.in('id', ids) : statsQuery.eq('id', '00000000-0000-0000-0000-000000000000')
        } else if (params.estado === 'emitida') {
            const { data: fe } = await adminClient.from('emails_factura').select('factura_id').eq('estado', 'enviado')
            const idsEnviadas = new Set((fe || []).map((e: any) => e.factura_id))
            statsQuery = statsQuery.eq('estado', 'emitida')
            if (idsEnviadas.size > 0) {
                const idsStr = Array.from(idsEnviadas).map((id) => `"${id}"`).join(',')
                statsQuery = statsQuery.not('id', 'in', `(${idsStr})`)
            }
        } else statsQuery = statsQuery.eq('estado', params.estado)
    }
    if (params.clienteId) statsQuery = statsQuery.eq('cliente_id', params.clienteId)
    if (params.serie) statsQuery = statsQuery.eq('serie_id', params.serie)
    if (params.mes || params.anio) {
        const anio = params.anio ? parseInt(params.anio, 10) : new Date().getFullYear()
        const mes = params.mes ? parseInt(params.mes, 10) : null
        if (mes) {
            const desde = `${anio}-${String(mes).padStart(2, '0')}-01`
            const ultimoDia = new Date(anio, mes, 0).getDate()
            const hasta = `${anio}-${String(mes).padStart(2, '0')}-${String(ultimoDia).padStart(2, '0')}`
            statsQuery = statsQuery.gte('fecha_emision', desde).lte('fecha_emision', hasta)
        } else if (params.anio) {
            statsQuery = statsQuery.gte('fecha_emision', `${anio}-01-01`).lte('fecha_emision', `${anio}-12-31`)
        }
    } else {
        if (params.desde) statsQuery = statsQuery.gte('fecha_emision', params.desde)
        if (params.hasta) statsQuery = statsQuery.lte('fecha_emision', params.hasta)
    }

    const { data: statsData } = await statsQuery

    const stats = {
        totalFacturado: statsData?.reduce((sum, f) => sum + (Number(f.total) || 0), 0) || 0,
        pendienteCobro: statsData?.filter((f) => f.estado === 'emitida').reduce((sum, f) => sum + (Number(f.total) || 0), 0) || 0,
        vencidas: statsData?.filter((f) => f.estado === 'vencida').reduce((sum, f) => sum + (Number(f.total) || 0), 0) || 0,
        esteMes: statsData?.filter((f) => {
            const fecha = new Date(f.fecha_emision)
            const hoy = new Date()
            return fecha.getMonth() === hoy.getMonth() && fecha.getFullYear() === hoy.getFullYear()
        }).reduce((sum, f) => sum + (Number(f.total) || 0), 0) || 0,
    }

    return (
        <div data-testid="page-facturas" className="space-y-6 p-2 md:p-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Breadcrumbs */}
            <div className="flex items-center gap-2 text-sm text-slate-500">
                <Link href="/ventas" className="hover:text-slate-700 transition-colors">Ventas</Link>
                <span>›</span>
                <span className="text-slate-900 dark:text-slate-100 font-medium">Facturas</span>
            </div>
            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-3xl font-serif font-bold text-slate-900 dark:text-slate-100 tracking-tight">Facturas</h1>
                    <p className="text-slate-600 dark:text-slate-400 mt-1 text-lg">Gestiona y consulta todas tus facturas de venta</p>
                </div>
                <Button asChild size="lg" className="sm:w-auto w-full min-h-[44px] bg-primary hover:bg-primary/90 text-white shadow-lg shadow-primary/20 hover:shadow-primary/40 transition-all duration-300">
                    <Link href="/ventas/facturas/nueva">
                        <Plus className="h-5 w-5 mr-2" />
                        Nueva Factura
                    </Link>
                </Button>
            </div>
            <FacturasStats stats={stats} />
            <div className="space-y-4">
                {/* Filtros */}
                <FacturasFilters
                    series={series || []}
                    pageSize={pageSize}
                />

                {/* Tabla */}
                <FacturasTable
                    facturas={(facturas || []) as unknown as FacturaWithCliente[]}
                    totalCount={count || 0}
                    currentPage={page}
                    pageSize={pageSize}
                    searchQuery={params.q?.trim() || undefined}
                    enviadaIds={enviadaIds}
                />
            </div>
        </div>
    )
}

import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { sanitizeSearchInput } from '@/lib/security/sanitize-search'
import { PagosStats } from '@/components/pagos/pagos-stats'
import { PagosTabla } from '@/components/pagos/pagos-tabla'
import { getUserContext } from '@/app/actions/usuarios-empresas'

export const dynamic = 'force-dynamic'

export default async function PagosPage({
    searchParams,
}: {
    searchParams: Promise<{ tab?: string; search?: string; metodo?: string; estado?: string }>
}) {
    const { supabase, empresaId, rol } = await getUserContext()

    // En Next.js 16, searchParams es una Promise y hay que resolverla
    const resolvedSearchParams = await searchParams

    const isGlobalAdmin = !empresaId && rol === 'admin'
    if (!empresaId && !isGlobalAdmin) {
        throw new Error('Usuario sin empresa activa para pagos')
    }

    const tab = resolvedSearchParams.tab || 'todos'
    const search = resolvedSearchParams.search || ''
    const metodo = resolvedSearchParams.metodo || 'todos'
    const today = new Date().toISOString().split('T')[0]

    let pagos: (any & { esFacturaRow: boolean })[] = [] // Still partially generic due to view structure but typed with row indicator

    // IMPORTANTE: Las pestañas "Pendientes" y "Vencidos" deben mostrar FACTURAS pendientes de cobro,
    // no solo registros de pago. vista_pagos_dashboard solo tiene filas por cada PAGO registrado,
    // así que una factura emitida SIN ningún pago nunca aparecería. Los KPIs sí consultan facturas.
    if (tab === 'pendientes' || tab === 'vencidos') {
        let facturasQuery = supabase
            .from('facturas')
            .select(`
                id,
                serie,
                numero,
                total,
                pagado,
                estado,
                fecha_vencimiento,
                empresa_id,
                cliente:clientes(nombre_fiscal)
            `)
            .in('estado', ['emitida', 'parcial'])

        if (tab === 'vencidos') {
            facturasQuery = facturasQuery.lt('fecha_vencimiento', today)
        }

        if (!isGlobalAdmin && empresaId) {
            facturasQuery = facturasQuery.eq('empresa_id', empresaId)
        }

        const q = sanitizeSearchInput(search)
        if (q) {
            const orParts = [`serie.ilike.%${q}%`, `numero.ilike.%${q}%`]
            const { data: clientesMatch } = await supabase
                .from('clientes')
                .select('id')
                .or(`nombre_fiscal.ilike.%${q}%,nombre_comercial.ilike.%${q}%`)
            const clienteIds = (clientesMatch as { id: string }[] | null)?.map((c) => c.id) ?? []
            if (clienteIds.length > 0) {
                orParts.push(`cliente_id.in.(${clienteIds.join(',')})`)
            }
            facturasQuery = facturasQuery.or(orParts.join(','))
        }

        facturasQuery = facturasQuery.order('fecha_vencimiento', { ascending: true })

        const { data: facturas } = await facturasQuery

        // Mapear facturas al formato que espera PagosTabla (una fila por factura pendiente)
        pagos = (facturas || []).map((f) => {
            const totalPagado = Number(f.pagado) || 0
            const pendiente = Math.max(0, Number(f.total) - totalPagado)
            const clienteNombre = f.cliente?.nombre_fiscal || '-'
            return {
                id: `factura-${f.id}`,
                factura_id: f.id,
                serie: f.serie || '',
                numero: f.numero,
                cliente_nombre: clienteNombre,
                fecha_vencimiento: f.fecha_vencimiento,
                factura_total: Number(f.total),
                pendiente,
                metodo_pago: null,
                factura_estado: f.estado,
                conciliado: false,
                esFacturaRow: true,
            }
        })

        // Filtro por método no aplica a facturas pendientes sin pago (todas tienen metodo null)
        // Se ignora para no vaciar la lista; el usuario puede filtrar por método en Cobrados/Parciales
    } else {
        // Cobrados, Parciales, Todos: usamos vista_pagos_dashboard (una fila por pago)
        let query = supabase.from('vista_pagos_dashboard' as any).select('*')

        if (!isGlobalAdmin && empresaId) {
            query = query.eq('empresa_id', empresaId)
        }

        if (tab === 'cobrados') {
            query = query.eq('factura_estado', 'pagada')
        } else if (tab === 'parciales') {
            query = query.eq('factura_estado', 'parcial')
        }

        const searchSanitized = sanitizeSearchInput(search)
        if (searchSanitized) {
            query = query.or(
                `serie.ilike.%${searchSanitized}%,cliente_nombre.ilike.%${searchSanitized}%,referencia.ilike.%${searchSanitized}%`
            )
        }

        if (metodo !== 'todos') {
            query = query.eq('metodo_pago', metodo)
        }

        query = query.order('fecha_pago', { ascending: false })

        const { data } = await query
        pagos = (data || []).map((p) => ({ ...(p as Record<string, any>), esFacturaRow: false }))
    }

    // Cargar estadísticas
    // Using rpc if defined, or reusing server action logic. The migration didn't include 'get_estadisticas_pagos' RPC function.
    // The server action 'getEstadisticasPagosAction' was defined in 'src/app/actions/pagos.ts'.
    // However, the prompt's page code calls `supabase.rpc('get_estadisticas_pagos', ...)` which implies referencing a stored procedure.
    // The migration SQL provided in step 1/2 did NOT include `get_estadisticas_pagos` function.
    // BUT, the prompt's `getEstadisticasPagosAction` is a SERVER ACTION that calculates it in JS/Node.
    // In `PagosPage`, the prompt calls `supabase.rpc`. This is a discrepancy in the user prompt.
    // Prompt says: "Cargar estadísticas: const { data: stats } = await supabase.rpc('get_estadisticas_pagos'..."
    // But also provided `getEstadisticasPagosAction` in `src/app/actions/pagos.ts` which does logic in JS.
    // I should probably use the Server Action `getEstadisticasPagosAction` directly in the page component instead of RPC, 
    // OR create the RPC function.
    // Given I deployed the migration provided which didn't have the RPC, calling RPC checks against the DB will fail.
    // I will use `getEstadisticasPagosAction` from locally imported actions. This is safer and matches the backend logic provided.

    // Import the action
    const { getEstadisticasPagosAction } = await import('@/app/actions/pagos')
    const statsResult = await getEstadisticasPagosAction()
    const stats = statsResult.success ? statsResult.data : ({} as any)

    return (
        <div className="space-y-6">
            <div className="text-sm text-slate-500">Ventas › Pagos</div>

            <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <h1 className="text-2xl sm:text-4xl font-serif font-bold">Gestión de Pagos</h1>
                    <p className="text-slate-600 dark:text-slate-400 text-sm sm:text-base">
                        Controla los cobros de tus facturas y concilia pagos
                    </p>
                </div>
                <Link href="/ventas/pagos/registrar" className="w-full sm:w-auto">
                    <Button className="w-full sm:w-auto min-h-[44px] bg-linear-to-r from-primary to-primary/80 hover:scale-105 active:scale-95 transition-all duration-300">
                        + Registrar Pago
                    </Button>
                </Link>
            </div>

            {/* Explicit cast or use generic component */}
            <PagosStats stats={stats} />

            <PagosTabla
                pagos={pagos}
                tab={tab}
                search={resolvedSearchParams.search || ''}
                metodo={resolvedSearchParams.metodo || 'todos'}
            />
        </div>
    )
}

/**
 * Tests unitarios: actualizarEmpresaAction
 *
 * Valida especialmente que el action usa empresa_id del formulario
 * en lugar de perfiles.empresa_id, evitando el error de constraint única
 * cuando el usuario opera en una empresa distinta a la de su perfil.
 */
import { vi, describe, test, expect, beforeEach } from 'vitest'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('next/cache', () => ({ revalidatePath: vi.fn() }))

// Supabase query builder encadenable: todos los métodos devuelven `this`,
// sólo `single()` resuelve la promesa con el valor configurado.
function makeBuilder(resolveWith: { data?: any; error?: any }) {
    const b: any = {
        select: vi.fn().mockReturnThis(),
        eq: vi.fn().mockReturnThis(),
        update: vi.fn().mockReturnThis(),
        single: vi.fn().mockResolvedValue(resolveWith),
    }
    return b
}

// Mock configurable de createServerClient
const mockGetSession = vi.fn()
const mockFrom = vi.fn()
const mockRpc = vi.fn()

vi.mock('@/lib/supabase/server', () => ({
    createServerClient: vi.fn(() =>
        Promise.resolve({
            auth: { getSession: mockGetSession },
            from: mockFrom,
            rpc: mockRpc,
        })
    ),
}))

// Admin client no se usa en actualizarEmpresaAction
vi.mock('@/lib/supabase/admin', () => ({ createAdminClient: vi.fn() }))

// ─── Helpers ──────────────────────────────────────────────────────────────────

const ID_EMPRESA_PERFIL = 'empresa-villegas-id'
const ID_EMPRESA_FORM = 'empresa-edison-id'
const CIF_NIF = '12345678A' // NIF persona → omite el SELECT previo al UPDATE

function buildSession(userId = 'user-123') {
    return { data: { session: { user: { id: userId } } } }
}

function buildPerfil(empresaId: string, rol = 'administrador') {
    return { data: { empresa_id: empresaId, rol }, error: null }
}

function makeFormData(overrides: Record<string, string> = {}) {
    const fd = new FormData()
    fd.append('razon_social', 'Edison Test S.L.')
    fd.append('cif', overrides.cif ?? CIF_NIF)
    fd.append('tipo_empresa', overrides.tipo_empresa ?? 'autonomo')
    fd.append('pais', 'España')
    fd.append('iva_predeterminado', '21')
    fd.append('retencion_predeterminada', '0')
    fd.append('regimen_iva', 'general')
    fd.append('aplica_recargo_equivalencia', 'false')
    fd.append('recargo_porcentaje', '0')
    fd.append('dias_pago_predeterminados', '30')
    if (overrides.empresa_id !== undefined) fd.append('empresa_id', overrides.empresa_id)
    if (overrides.lugar_expedicion) fd.append('lugar_expedicion', overrides.lugar_expedicion)
    if (overrides.iban) fd.append('iban', overrides.iban)
    return fd
}

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('actualizarEmpresaAction', () => {
    beforeEach(() => {
        vi.clearAllMocks()
        mockGetSession.mockResolvedValue(buildSession())
    })

    // ── Autenticación ──────────────────────────────────────────────────────

    test('devuelve error si el usuario no tiene sesión', async () => {
        mockGetSession.mockResolvedValue({ data: { session: null } })
        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData())
        expect(result.success).toBe(false)
    })

    // ── Permisos ───────────────────────────────────────────────────────────

    test('devuelve error si el rol no es admin', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL, 'usuario')))
        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/permisos/i)
    })

    // ── Empresa ID: campo oculto del formulario ────────────────────────────

    test('usa empresa_id del formulario cuando está presente', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))

        expect(result.success).toBe(true)
        // El update debe haberse ejecutado sobre la empresa del formulario, no la del perfil
        expect(updateEqArg).toBe(ID_EMPRESA_FORM)
        expect(updateEqArg).not.toBe(ID_EMPRESA_PERFIL)
    })

    test('usa empresaId del perfil como fallback cuando no hay empresa_id en el formulario', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_PERFIL }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        // Sin empresa_id en el form
        const result = await actualizarEmpresaAction(makeFormData())

        expect(result.success).toBe(true)
        expect(updateEqArg).toBe(ID_EMPRESA_PERFIL)
    })

    test('empresa_id vacío en el formulario usa el fallback del perfil', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_PERFIL }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: '   ' }))

        expect(result.success).toBe(true)
        expect(updateEqArg).toBe(ID_EMPRESA_PERFIL)
    })

    // ── Validación de CIF/NIF ──────────────────────────────────────────────

    test('devuelve error si el CIF está vacío', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL)))
        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', '')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/cif.*obligatorio/i)
    })

    test('devuelve error si el CIF tiene formato inválido', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL)))
        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', 'INVALIDO')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/formato/i)
    })

    test('acepta CIF empresa formato B12345678', async () => {
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        // Primera llamada a empresas: SELECT cif para comparar
        const empresaSelectBuilder = makeBuilder({ data: { cif: 'B12345678' }, error: null })
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }

        let empresasCallCount = 0
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            empresasCallCount++
            return empresasCallCount === 1 ? empresaSelectBuilder : empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', 'B12345678')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(true)
    })

    // ── Propagación de error de Supabase ───────────────────────────────────

    test('propaga error de Supabase en el update (ej. duplicate key)', async () => {
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({
                data: null,
                error: { message: 'duplicate key value violates unique constraint "empresas_cif_key_active"' },
            }),
        }
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/duplicate key/i)
    })

    // ── lugar_expedicion ───────────────────────────────────────────────────

    test('guarda lugar_expedicion correctamente', async () => {
        let capturedData: any = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockImplementation((data: any) => {
                capturedData = data
                return empresaUpdateBuilder
            }),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        await actualizarEmpresaAction(
            makeFormData({ empresa_id: ID_EMPRESA_FORM, lugar_expedicion: 'Barcelona' })
        )
        expect(capturedData?.lugar_expedicion).toBe('Barcelona')
    })
})

'use server'

import { revalidatePath } from 'next/cache'
import { createAdminClient } from '@/lib/supabase/admin'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { clienteSchema } from '@/lib/validations/cliente-schema'
import { z } from 'zod'

/** Obtiene IDs de empresas del usuario (para notificaciones y fallback) */
function getEmpresaIds(empresas: Array<{ empresa_id?: string | null }>): string[] {
    return empresas
        .filter((e) => e.empresa_id)
        .map((e) => e.empresa_id as string)
}

export async function crearClienteAction(formData: FormData) {
    try {
        const { supabase, userId, empresas } = await getUserContext()
        let empresaIds = getEmpresaIds(empresas as { empresa_id?: string }[])
        if (empresaIds.length === 0) {
            const { data: perfil } = await supabase.from('perfiles').select('empresa_id').eq('user_id', userId).single()
            if (perfil?.empresa_id) empresaIds = [perfil.empresa_id]
        }
        if (empresaIds.length === 0) return { success: false, error: 'Usuario sin empresa asignada' }

        const rawData = Object.fromEntries(formData.entries())

        const dataToValidate = {
            ...rawData,
            dias_vencimiento: Number(rawData.dias_vencimiento) || 30,
            descuento_comercial: Number(rawData.descuento_comercial) || 0,
            iva_aplicable: Number(rawData.iva_aplicable) || 21,
            activo: rawData.activo === 'on',
        }

        const compartido = rawData.compartido === 'true'
        const empresasIdsRaw = rawData.empresas_ids
        const empresasIds: string[] = compartido
            ? empresaIds
            : (typeof empresasIdsRaw === 'string' ? (empresasIdsRaw ? empresasIdsRaw.split(',').filter(Boolean) : []) : [])

        if (!compartido && empresasIds.length === 0) {
            return { success: false, error: 'Selecciona al menos una empresa' }
        }

        const validated = clienteSchema.parse(dataToValidate)

        const insertData: Record<string, unknown> = { ...validated, empresa_id: null }
        for (const k of Object.keys(insertData)) {
            if (insertData[k] === '') insertData[k] = null
        }

        const adminClient = createAdminClient()
        const { data, error } = await (adminClient
            .from('clientes') as any)
            .insert({ ...insertData, empresa_id: null })
            .select()
            .single()

        if (error) {
            console.error('Supabase error:', error)
            throw error
        }

        const idsToInsert = compartido ? empresaIds : empresasIds
        if (idsToInsert.length > 0) {
            const { error: ceError } = await (adminClient.from as any)('clientes_empresas')
                .insert(idsToInsert.map((empresa_id: string) => ({ cliente_id: data.id, empresa_id })))

            if (ceError) {
                console.error('[crearClienteAction] Error clientes_empresas:', ceError)
                await adminClient.from('clientes').delete().eq('id', data.id)
                return { success: false, error: 'Error al asociar empresas: ' + ceError.message }
            }
        }

        const notifEmpresaId = empresaIds[0]
        try {
            if (notifEmpresaId) {
                await supabase.rpc('crear_notificacion', {
                    p_user_id: userId,
                    p_empresa_id: notifEmpresaId,
                    p_tipo: 'success',
                    p_categoria: 'cliente',
                    p_titulo: 'Nuevo cliente creado',
                    p_mensaje: `Se ha creado el cliente "${data.nombre_fiscal}" exitosamente.`,
                    p_enlace: `/ventas/clientes/${data.id}`,
                    p_metadata: { cliente_id: data.id, nombre: data.nombre_fiscal }
                })
            }
        } catch (notifError) {
            console.error('[crearClienteAction] Error creando notificación:', notifError)
        }

    } catch (error: unknown) {
        console.error('[crearClienteAction]', error)

        if (error instanceof z.ZodError) {
            const issues = error.issues
            if (issues && issues.length > 0) {
                return { success: false, error: issues[0].message }
            }
            return { success: false, error: 'Error de validación' }
        }

        const errorMessage = error instanceof Error ? error.message : (typeof error === 'object' && error !== null && 'message' in error ? String((error as any).message) : 'Error desconocido')
        return { success: false, error: errorMessage }
    }
}

export async function actualizarClienteAction(clienteId: string, formData: FormData) {
    try {
        const { supabase, userId, empresas } = await getUserContext()
        let empresaIds = getEmpresaIds(empresas as { empresa_id?: string }[])
        if (empresaIds.length === 0) {
            const { data: perfil } = await supabase.from('perfiles').select('empresa_id').eq('user_id', userId).single()
            if (perfil?.empresa_id) empresaIds = [perfil.empresa_id]
        }
        if (empresaIds.length === 0) return { success: false, error: 'Usuario sin empresa asignada' }

        const rawData = Object.fromEntries(formData.entries())
        const dataToValidate = {
            ...rawData,
            dias_vencimiento: Number(rawData.dias_vencimiento) || 30,
            descuento_comercial: Number(rawData.descuento_comercial) || 0,
            iva_aplicable: Number(rawData.iva_aplicable) || 21,
            activo: rawData.activo === 'on',
        }

        const compartido = rawData.compartido === 'true'
        const empresasIdsRaw = rawData.empresas_ids
        const empresasIds: string[] = compartido
            ? empresaIds
            : (typeof empresasIdsRaw === 'string' ? (empresasIdsRaw ? empresasIdsRaw.split(',').filter(Boolean) : []) : [])

        if (!compartido && empresasIds.length === 0) {
            return { success: false, error: 'Selecciona al menos una empresa' }
        }

        const validated = clienteSchema.parse(dataToValidate)

        const adminClient = createAdminClient()
        const { data, error } = await (adminClient
            .from('clientes') as any)
            .update({ ...validated, empresa_id: null })
            .eq('id', clienteId)
            .select()
            .single()

        if (error) throw error

        await (adminClient.from as any)('clientes_empresas').delete().eq('cliente_id', clienteId)
        const idsToInsert = compartido ? empresaIds : empresasIds
        if (idsToInsert.length > 0) {
            const { error: ceError } = await (adminClient.from as any)('clientes_empresas')
                .insert(idsToInsert.map((empresa_id: string) => ({ cliente_id: clienteId, empresa_id })))

            if (ceError) {
                console.error('[actualizarClienteAction] Error clientes_empresas:', ceError)
                return { success: false, error: 'Error al actualizar empresas: ' + ceError.message }
            }
        }

        revalidatePath('/ventas/clientes')
        revalidatePath(`/ventas/clientes/${clienteId}`)
        return { success: true, data }
    } catch (error: unknown) {
        console.error('[actualizarClienteAction]', error)

        if (error instanceof z.ZodError) {
            const issues = error.issues
            if (issues && issues.length > 0) {
                return { success: false, error: issues[0].message }
            }
            return { success: false, error: 'Error de validación' }
        }

        const errorMessage = error instanceof Error ? error.message : 'Error al actualizar cliente'
        return { success: false, error: errorMessage }
    }
}

export async function eliminarClienteAction(clienteId: string) {
    try {
        const { supabase } = await getUserContext()

        const { count, error: countError } = await supabase
            .from('facturas')
            .select('id', { count: 'exact', head: true })
            .eq('cliente_id', clienteId)

        if (countError) {
            console.error('[eliminarClienteAction] Error checking facturas:', countError)
        }

        if (count && count > 0) {
            return { success: false, error: `No se puede eliminar: tiene ${count} factura(s) asociada(s). Elimina las facturas primero.` }
        }

        const { error } = await supabase
            .from('clientes')
            .delete()
            .eq('id', clienteId)

        if (error) {
            console.error('[eliminarClienteAction] Delete error:', error)
            // Handle FK constraint violation (client has invoices)
            if (error.message?.includes('violates foreign key constraint') || error.message?.includes('not-null constraint') || error.code === '23503') {
                return { success: false, error: 'No se puede eliminar: el cliente tiene facturas asociadas. Elimina las facturas primero.' }
            }
            return { success: false, error: `Error al eliminar: ${error.message}` }
