async function streamToBuffer(stream: NodeJS.ReadableStream): Promise<Buffer> {
  const chunks: Uint8Array[] = []
  return new Promise((resolve, reject) => {
    stream.on('data', (chunk) => chunks.push(chunk))
    stream.on('error', reject)
    stream.on('end', () => resolve(Buffer.concat(chunks)))
  })
}

export async function GET(request: Request) {
  if (process.env.NODE_ENV === 'production') {
    return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
  }

  const { searchParams } = new URL(request.url)
  const facturaId = searchParams.get('id')

  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )

  let query = supabase
    .from('facturas')
    .select('*, cliente:clientes(*), lineas:lineas_factura(*)')
    .in('estado', ['emitida', 'pagada'])

  if (facturaId) query = query.eq('id', facturaId)
  query = query.limit(1)

  const { data: facturas, error } = await query

  if (error || !facturas?.length) {
    return NextResponse.json({ error: 'No se encontró factura' }, { status: 404 })
  }

  const factura = facturas[0] as any

  try {
    const { data: empresaRow } = await supabase
      .from('empresas')
      .select('razon_social, nombre_comercial, direccion, ciudad, codigo_postal, provincia, pais, cif, email, iban, banco, pie_factura')
      .eq('id', factura.empresa_id)
      .single()

    const empresa: Empresa = empresaRow ? {
      nombre_fiscal: empresaRow.razon_social || empresaRow.nombre_comercial || 'Empresa',
      direccion: empresaRow.direccion || '',
      ciudad: empresaRow.ciudad || '',
      codigo_postal: empresaRow.codigo_postal || '',
      cif: empresaRow.cif || '',
      email: empresaRow.email || undefined,
      iban: empresaRow.iban || undefined,
      banco: empresaRow.banco || undefined,
      pie_factura: empresaRow.pie_factura || undefined,
    } : {
      nombre_fiscal: 'Empresa',
      direccion: '',
      ciudad: '',
      codigo_postal: '',
      cif: '',
    }

    const fullFactura = { ...factura, descuento_tipo: factura.descuento_tipo as 'porcentaje' | 'fijo' | null }
    const EMPRESA_VILLEGAS_ID = '4b77324c-a10e-4714-b0a4-df4b9c5f6ca5'
    const EMPRESA_YENIFER_ID = 'e9a30c7d-eb2a-4c7a-91a6-a8bfe8f2278a'
    const EMPRESA_EDISON_ID = 'af15f25a-7ade-4de8-9241-a42e1b8407da'
    let pdfPlantilla: 'estandar' | 'premium' = 'estandar'
    let incluirLogoPdf = false
    if (factura.empresa_id === EMPRESA_VILLEGAS_ID) {
      pdfPlantilla = 'premium'
      incluirLogoPdf = true
    } else if (factura.empresa_id === EMPRESA_YENIFER_ID || factura.empresa_id === EMPRESA_EDISON_ID) {
      pdfPlantilla = 'estandar'
      incluirLogoPdf = false
    } else {
      pdfPlantilla = 'estandar'
      incluirLogoPdf = true
    }
    const pdfOptions: PdfOptions = {
      plantilla: pdfPlantilla,
      idioma: 'es',
      incluirLogo: incluirLogoPdf,
      incluirDatosBancarios: true,
      notasPie: '',
      colorAcento: '#0f172a',
    }

    let logoUrl: string | undefined
    if (incluirLogoPdf) {
      try {
        const logoPath = path.join(process.cwd(), 'public', clientConfig.logoPath.replace(/^\//, ''))
        if (fs.existsSync(logoPath)) {
          logoUrl = `data:image/png;base64,${fs.readFileSync(logoPath).toString('base64')}`
        }
      } catch {}
    }

    const stream = await renderToStream(
      React.createElement(FacturaPdfDocument as any, {
        factura: fullFactura,
        empresa,
        options: pdfOptions,
        logoUrl,
      }) as any
    )
    const pdfBuffer = await streamToBuffer(stream as any)

    const filename = `Factura-${factura.serie || 'FAC'}-${factura.numero}.pdf`
    const tempPath = path.join(process.cwd(), 'temp-factura.pdf')
    fs.writeFileSync(tempPath, pdfBuffer)

    return NextResponse.json({
      ok: true,
      path: tempPath,
      filename,
      factura: `${factura.serie}-${factura.numero}`,
    })
  } catch (e: any) {
    console.error(e)
    return NextResponse.json({ error: e.message }, { status: 500 })
  }
}

/**
 * API de desarrollo: sube un PDF de prueba y actualiza la factura externa
 * para poder emitirla. Solo en desarrollo.
 *
 * GET /api/dev/seed-factura-externa?id=FACTURA_ID
 */
import { createServerClient } from '@/lib/supabase/server'
import { NextResponse } from 'next/server'
import { getUserContext } from '@/app/actions/usuarios-empresas'

const MINIMAL_PDF = Buffer.from(
    '%PDF-1.4\n1 0 obj<</Type/Catalog/Pages 2 0 R>>endobj\n2 0 obj<</Type/Pages/Kids[3 0 R]/Count 1>>endobj\n3 0 obj<</Type/Page/MediaBox[0 0 612 792]/Parent 2 0 R>>endobj\nxref\n0 4\n0000000000 65535 f \n0000000009 00000 n \n0000000058 00000 n \n0000000115 00000 n \ntrailer<</Size 4/Root 1 0 R>>\nstartxref\n190\n%%EOF\n',
    'utf-8'
)

export async function GET(request: Request) {
    if (process.env.NODE_ENV === 'production') {
        return NextResponse.json({ error: 'No disponible en producción' }, { status: 403 })
    }

    const { searchParams } = new URL(request.url)
    const facturaId = searchParams.get('id')
    if (!facturaId) {
        return NextResponse.json({ error: 'Falta id de factura (query param id)' }, { status: 400 })
    }

    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return NextResponse.json({ error: 'No autenticado' }, { status: 401 })
    }

    const { empresaId, rol } = await getUserContext()
    const isGlobal = !empresaId && rol === 'admin'

    let query = supabase
        .from('facturas')
        .select('id, empresa_id, es_externa')
        .eq('id', facturaId)
        .eq('es_externa', true)
    if (!isGlobal && empresaId) query = query.eq('empresa_id', empresaId)
    const { data: factura } = await query.single()

    if (!factura) {
        return NextResponse.json({ error: 'Factura externa no encontrada' }, { status: 404 })
    }

    const fileName = `facturas/${facturaId}_${Date.now()}.pdf`

    const { error: uploadError } = await supabase.storage
        .from('facturas-externas')
        .upload(fileName, MINIMAL_PDF, {
            contentType: 'application/pdf',
            upsert: true
        })

    if (uploadError) {
        return NextResponse.json({ error: `Error subiendo PDF: ${uploadError.message}` }, { status: 500 })
    }

    const { data: { publicUrl } } = supabase.storage
        .from('facturas-externas')
        .getPublicUrl(fileName)

    const { error: updateError } = await supabase
        .from('facturas')
        .update({ archivo_url: publicUrl } as any)
        .eq('id', facturaId)

    if (updateError) {
        return NextResponse.json({ error: `Error actualizando: ${updateError.message}` }, { status: 500 })
    }

    return NextResponse.json({
        success: true,
        archivo_url: publicUrl,
        message: 'PDF subido. Puedes emitir la factura desde la UI.'
    })
}

