                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </div>

                                <div className="grid grid-cols-2 gap-2 text-sm">
                                    <div className="space-y-1">
                                        <p className="text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider font-bold">Contacto</p>
                                        <p className="text-slate-900 dark:text-slate-100 truncate font-medium">{cliente.email_principal}</p>
                                    </div>
                                    <div className="space-y-1 text-right">
                                        <p className="text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider font-bold">Estado</p>
                                        <Badge variant="outline" className={`border ${cliente.activo
                                            ? 'bg-green-100 text-green-700 dark:bg-green-900/50 dark:text-green-300 border-green-200 dark:border-green-800'
                                            : 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300 border-slate-200 dark:border-slate-700'
                                            }`}>
                                            {cliente.activo ? 'Activo' : 'Inactivo'}
                                        </Badge>
                                    </div>
                                </div>

                                <div className="pt-3 border-t border-slate-200 dark:border-slate-800 flex justify-between items-center">
                                    <span className="text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider font-bold">Facturado</span>
                                    <span className="font-bold text-slate-900 dark:text-slate-100 text-lg" suppressHydrationWarning>
                                        {formatCurrency(cliente.total_facturado || 0)}
                                    </span>
                                </div>
                            </CardContent>
                        </Card>
                    )
                })}
                {clientesFiltrados.length === 0 && (
                    <div className="p-8 text-center bg-white/70 dark:bg-slate-900/60 rounded-xl border border-white/20 dark:border-white/10" data-testid="clientes-empty-mobile">
                        <p className="text-slate-500 dark:text-slate-400 font-medium">No se encontraron clientes.</p>
                        <Link href="/ventas/clientes/nuevo" className="mt-3 inline-block text-sm font-medium text-primary hover:text-primary/80 transition-colors">
                            Crear cliente
                        </Link>
                    </div>
                )}
            </div>
            )}

            <AlertDialog open={!!deleteId} onOpenChange={(open) => !open && setDeleteId(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>¿Estás seguro?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Esta acción eliminará permanentemente al cliente <strong>{deleteName}</strong> y no se puede deshacer.
                            Si tiene facturas asociadas, no se podrá eliminar.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={confirmDelete}
                            className="bg-red-600 hover:bg-red-700 text-white"
                            disabled={isDeleting}
                        >
                            {isDeleting ? 'Eliminando...' : 'Eliminar Cliente'}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu'
import { MoreVertical, Edit, Copy, Trash2, TrendingUp } from 'lucide-react'
import { toast } from 'sonner'
import { eliminarConceptoAction, duplicarConceptoAction } from '@/app/actions/conceptos'
import Link from 'next/link'

interface ConceptosTablaProps {
    conceptos: any[]
}

export function ConceptosTabla({ conceptos }: ConceptosTablaProps) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const [search, setSearch] = useState(searchParams.get('search') || '')

    const getCategoriaColor = (categoria: string) => {
        const colores: Record<string, string> = {
            transporte: 'bg-blue-100 text-blue-700 hover:bg-blue-100/80',
            almacenaje: 'bg-green-100 text-green-700 hover:bg-green-100/80',
            logistica: 'bg-purple-100 text-purple-700 hover:bg-purple-100/80',
            material: 'bg-orange-100 text-orange-700 hover:bg-orange-100/80',
            otros: 'bg-slate-100 text-slate-700 hover:bg-slate-100/80',
        }
        return colores[categoria] || colores.otros
    }

    const getCategoriaIcon = (categoria: string) => {
        const iconos: Record<string, string> = {
            transporte: '🚚',
            almacenaje: '📦',
            logistica: '📋',
            material: '🔧',
            otros: '📄',
        }
        return iconos[categoria] || '📄'
    }

    const handleDuplicar = async (conceptoId: string) => {
        const result = await duplicarConceptoAction(conceptoId)
        if (result.success) {
            toast.success('Concepto duplicado')
            router.refresh()
        } else {
            toast.error(result.error)
        }
    }

    const handleEliminar = async (conceptoId: string) => {
        if (!confirm('¿Eliminar este concepto? Esta acción no se puede deshacer.')) return

        const result = await eliminarConceptoAction(conceptoId)
        if (result.success) {
            toast.success('Concepto eliminado')
            router.refresh()
        } else {
            toast.error(result.error)
        }
    }

    // Handle filters update
    const updateFilters = (key: string, value: string) => {
        const params = new URLSearchParams(searchParams.toString())
        if (value && value !== 'todas' && value !== 'todos') {
            params.set(key, value)
        } else {
            params.delete(key)
        }
        router.push(`?${params.toString()}`)
    }

    // Handle search with debounce ideally, but direct push for now
    const handleSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            updateFilters('search', search)
        }
    }

    return (
        <div className="space-y-4">
            {/* Filtros */}
            <div className="flex flex-wrap gap-4 items-center bg-white p-4 rounded-xl shadow-sm border border-slate-100 dark:bg-slate-900 dark:border-slate-800">
                <div className="flex-1 min-w-[200px]">
                    <Input
                        placeholder="Buscar por código, concepto..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        onKeyDown={handleSearch}
                        className="w-full"
                    />
                </div>

                <Select
                    defaultValue={searchParams.get('categoria') || 'todas'}
                    onValueChange={(val) => updateFilters('categoria', val)}
                >
                    <SelectTrigger className="w-[180px]">
                        <SelectValue placeholder="Categoría" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="todas">Todas</SelectItem>
                        <SelectItem value="transporte">Transporte</SelectItem>
                        <SelectItem value="almacenaje">Almacenaje</SelectItem>
                        <SelectItem value="logistica">Logística</SelectItem>
                        <SelectItem value="material">Material</SelectItem>
                        <SelectItem value="otros">Otros</SelectItem>
                    </SelectContent>
                </Select>

                <Select
                    defaultValue={searchParams.get('tipo') || 'todos'}
                    onValueChange={(val) => updateFilters('tipo', val)}
                >
                    <SelectTrigger className="w-[150px]">
                        <SelectValue placeholder="Tipo" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="todos">Todos</SelectItem>
                        <SelectItem value="servicio">Servicio</SelectItem>
                        <SelectItem value="producto">Producto</SelectItem>
                    </SelectContent>
                </Select>

                <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => {
                        setSearch('')
                        router.push('?')
                    }}
                >
                    Limpiar Filtros
                </Button>
            </div>

            {/* Tabla */}
            <div className="rounded-2xl bg-white border border-slate-200 overflow-hidden shadow-sm dark:bg-slate-900 dark:border-slate-800">
                <table className="w-full">
                    <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                        <tr>
                            <th className="p-4 text-left text-xs font-semibold uppercase tracking-wide text-slate-500">Código</th>
                            <th className="p-4 text-left text-xs font-semibold uppercase tracking-wide text-slate-500">Concepto</th>
                            <th className="p-4 text-left text-xs font-semibold uppercase tracking-wide text-slate-500">Categoría</th>
                            <th className="p-4 text-left text-xs font-semibold uppercase tracking-wide text-slate-500">Tipo</th>
                            <th className="p-4 text-right text-xs font-semibold uppercase tracking-wide text-slate-500">Precio Base</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase tracking-wide text-slate-500">IVA</th>
                            <th className="p-4 text-right text-xs font-semibold uppercase tracking-wide text-slate-500">Total</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase tracking-wide text-slate-500">Usado</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase tracking-wide text-slate-500">Acciones</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {conceptos.map((concepto) => {
                            const precioTotal = (concepto.precio_base || 0) * (1 + (concepto.iva_porcentaje || 0) / 100)
                            return (
                                <tr key={concepto.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                                    <td className="p-4 font-mono text-sm text-slate-500">{concepto.codigo}</td>
                                    <td className="p-4">
                                        <p className="font-semibold text-slate-900 dark:text-slate-100">{concepto.nombre}</p>
                                        {concepto.descripcion && <p className="text-sm text-slate-500 line-clamp-1">{concepto.descripcion}</p>}
                                    </td>
                                    <td className="p-4">
                                        <Badge variant="secondary" className={`font-medium border-0 ${getCategoriaColor(concepto.categoria)}`}>
                                            <span className="mr-1">{getCategoriaIcon(concepto.categoria)}</span> {concepto.categoria}
                                        </Badge>
                                    </td>
                                    <td className="p-4 capitalize text-sm text-slate-600 dark:text-slate-400">{concepto.tipo}</td>
                                    <td className="p-4 text-right font-medium text-slate-700 dark:text-slate-300">
                                        {(concepto.precio_base || 0).toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                                    </td>
                                    <td className="p-4 text-center text-sm text-slate-500">{concepto.iva_porcentaje}%</td>
                                    <td className="p-4 text-right font-bold text-slate-900 dark:text-slate-100">
                                        {precioTotal.toLocaleString('es-ES', { minimumFractionDigits: 2 })}€
                                    </td>
                                    <td className="p-4 text-center">
                                        <div className="flex justify-center">
                                            <Badge variant="outline" className="flex items-center gap-1 font-normal bg-slate-50 dark:bg-slate-900">
                                                <TrendingUp className="h-3 w-3 text-slate-400" />
                                                {concepto.veces_usado || 0}
                                            </Badge>
                                        </div>
                                    </td>
                                    <td className="p-4 text-center">
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" size="icon" className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <MoreVertical className="h-4 w-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                                <DropdownMenuItem asChild>
                                                    <Link href={`/ventas/configuracion/conceptos/${concepto.id}/editar`} className="cursor-pointer font-medium">
                                                        <Edit className="h-4 w-4 mr-2" /> Editar
                                                    </Link>
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onClick={() => handleDuplicar(concepto.id)} className="cursor-pointer">
                                                    <Copy className="h-4 w-4 mr-2" /> Duplicar
                                                </DropdownMenuItem>
                                                <DropdownMenuItem className="text-red-600 cursor-pointer focus:text-red-600 focus:bg-red-50" onClick={() => handleEliminar(concepto.id)}>
                                                    <Trash2 className="h-4 w-4 mr-2" /> Eliminar
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    </td>
                                </tr>
                            )
                        })}
                    </tbody>
                </table>

                {conceptos.length === 0 && (
                    <div className="text-center py-12 text-slate-500">
                        <div className="inline-flex items-center justify-center p-4 bg-slate-100 rounded-full mb-4">
                            <span className="text-2xl">🔍</span>
                        </div>
                        <p className="text-lg font-medium text-slate-900">No se encontraron conceptos</p>
                        <p className="text-sm mt-1">Intenta ajustar los filtros de búsqueda</p>
                    </div>
                )}
            </div>

            <div className="flex justify-end text-xs text-slate-400">
                Mostrando {conceptos.length} conceptos
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Download, Loader2 } from 'lucide-react'
import { toast } from 'sonner'

interface Props {
    empresaId: string
    nombreEmpresa: string
}

export function DescargarDatosFiscalesButton({ empresaId, nombreEmpresa }: Props) {
    const [descargando, setDescargando] = useState(false)

    const handleDescargar = async () => {
        setDescargando(true)
        try {
            const url = `/api/empresas/datos-fiscales/pdf?empresa_id=${encodeURIComponent(empresaId)}`
            const res = await fetch(url)

            if (!res.ok) {
                const msg = await res.text()
                throw new Error(msg || `Error ${res.status}`)
            }

            const blob = await res.blob()
            const link = document.createElement('a')
            link.href = URL.createObjectURL(blob)
            const nombreSanitizado = nombreEmpresa.replace(/[^a-zA-Z0-9\s]/g, '').replace(/\s+/g, '-')
            link.download = `Datos-fiscales-${nombreSanitizado}.pdf`
            document.body.appendChild(link)
            link.click()
            document.body.removeChild(link)
            URL.revokeObjectURL(link.href)

            toast.success('PDF de datos fiscales descargado')
        } catch (err: any) {
            toast.error(err.message || 'Error al generar el PDF')
        } finally {
            setDescargando(false)
        }
    }

    return (
        <Button
            variant="outline"
            onClick={handleDescargar}
            disabled={descargando}
            className="flex items-center gap-2 min-h-[44px] w-full sm:w-auto border-amber-300 text-amber-700 hover:bg-amber-50 hover:text-amber-800 dark:border-amber-700 dark:text-amber-400 dark:hover:bg-amber-900/20"
            data-testid="btn-descargar-datos-fiscales"
        >
            {descargando ? (
                <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
                <Download className="h-4 w-4" />
            )}
            {descargando ? 'Generando PDF...' : 'Descargar datos fiscales'}
        </Button>
    )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import {
    getEvolucionFacturacionAction,
    getEstadoFacturasAction,
    type EvolucionData,
    type EstadoData,
} from '@/app/actions/informes'
import {
    LineChart,
    Line,
    BarChart,
    Bar,
    AreaChart,
    Area,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    PieChart,
    Pie,
    Cell,
    Legend,
} from 'recharts'
import { LineChart as LineIcon, BarChart3, Mountain } from 'lucide-react'
import { cn } from '@/lib/utils'

const STORAGE_KEY_CHART_TYPE = 'dashboard-chart-type'
export type ChartTypeValue = 'line' | 'bar' | 'area'

function getStoredChartType(): ChartTypeValue {
    try {
        const v = window.localStorage.getItem(STORAGE_KEY_CHART_TYPE)
        if (v === 'bar' || v === 'area') return v
    } catch {
        /* ignore */
    }
    return 'line'
}

const COLORS = [
    'hsl(var(--primary))',  // Rojo FNAUTOS
    '#1A1A1A',              // Negro suave
    '#4D4D4D',              // Gris oscuro
    '#CC0108',              // Rojo sólido
    '#7f0005',              // Rojo oscuro
    '#333333'               // Antracita
]

interface DashboardChartsProps {
    fechaDesde: string
    fechaHasta: string
    empresaId?: string | null
}

export function DashboardCharts({ fechaDesde, fechaHasta, empresaId }: DashboardChartsProps) {
    const [evolucion, setEvolucion] = useState<EvolucionData[]>([])
    const [estados, setEstados] = useState<EstadoData[]>([])
    const [loading, setLoading] = useState(true)
    const [chartType, setChartType] = useState<ChartTypeValue>('line')
    const [fetchError, setFetchError] = useState<string | null>(null)

    useEffect(() => {
        setChartType(getStoredChartType())
    }, [])

    useEffect(() => {
        const load = async () => {
            setLoading(true)
            setFetchError(null)
            try {
                const [evRes, estRes] = await Promise.all([
                    getEvolucionFacturacionAction(fechaDesde, fechaHasta, empresaId),
                    getEstadoFacturasAction(fechaDesde, fechaHasta, empresaId),
                ])
                if (evRes.success && evRes.data) setEvolucion(evRes.data)
                if (estRes.success && estRes.data) setEstados(estRes.data.filter((e) => e.estado !== 'anulada'))
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err)
                setFetchError(msg.includes('fetch') || msg.includes('Failed to fetch') ? 'Error de conexión. Comprueba tu conexión e intenta de nuevo.' : msg)
            } finally {
                setLoading(false)
            }
        }
        load()
    }, [fechaDesde, fechaHasta, empresaId])

    const handleChartTypeChange = useCallback((type: ChartTypeValue) => {
        setChartType(type)
        if (typeof window !== 'undefined') window.localStorage.setItem(STORAGE_KEY_CHART_TYPE, type)
    }, [])

    if (loading) {
        return (
            <div className="grid gap-6 lg:grid-cols-3">
                <Card className="lg:col-span-2 h-[320px] animate-pulse bg-slate-100 dark:bg-slate-800/50" />
                <Card className="h-[320px] animate-pulse bg-slate-100 dark:bg-slate-800/50" />
            </div>
        )
    }

    if (fetchError) {
        return (
            <Card className="border-amber-200 dark:border-amber-800 bg-amber-50/50 dark:bg-amber-950/20">
                <CardContent className="py-6 px-4 text-center">
                    <p className="text-amber-800 dark:text-amber-200 font-medium">{fetchError}</p>
                </CardContent>
            </Card>
        )
    }

    const estadoLabels: Record<string, string> = {
        pagada: 'Pagadas',
        emitida: 'Emitidas',
        borrador: 'Borradores',
    }

    const chartTooltipFormatter = (value: number) => [
        new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(value),
        'Facturación',
    ]
    const commonChartProps = {
        data: evolucion,
        margin: { top: 5, right: 10, left: 0, bottom: 0 },
    }
    const commonAxis = (
        <>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" className="stroke-slate-200 dark:stroke-slate-700" />
            <XAxis dataKey="periodo" stroke="#64748b" fontSize={11} tickLine={false} axisLine={false} />
            <YAxis stroke="#64748b" fontSize={11} tickLine={false} axisLine={false} tickFormatter={(v: number) => `${(v / 1000).toFixed(0)}k€`} />
            <Tooltip
                formatter={(value: any) => chartTooltipFormatter(Number(value))}
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            />
        </>
    )

    return (
        <div className="grid gap-6 lg:grid-cols-3">
            <Card className="lg:col-span-2 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900/95 shadow-lg">
                <CardHeader className="pb-2 flex flex-row items-start justify-between gap-4">
                    <div>
                        <CardTitle className="text-base font-semibold text-slate-800 dark:text-slate-100">
                            Evolución de facturación
                        </CardTitle>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                            Ingresos por mes en el período seleccionado
                        </p>
                    </div>
                    <div role="group" aria-label="Tipo de gráfico" className="flex rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/80 p-0.5">
                        {([
                            { value: 'line' as const, icon: LineIcon, label: 'Línea' },
                            { value: 'bar' as const, icon: BarChart3, label: 'Barras' },
                            { value: 'area' as const, icon: Mountain, label: 'Área' },
                        ]).map(({ value, icon: Icon, label }) => (
                            <Button
                                key={value}
                                variant="ghost"
                                size="sm"
                                data-testid={`dashboard-chart-type-${value}`}
                                className={cn(
                                    'h-8 w-9 min-h-[44px] min-w-[44px] sm:min-h-0 sm:min-w-0 sm:h-8 sm:w-9 p-0 rounded-md transition-all duration-200 active:scale-95',
                                    chartType === value ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm ring-2 ring-primary/20' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
                                )}
                                onClick={() => handleChartTypeChange(value)}
                                title={label}
                                aria-label={`Tipo de gráfico: ${label}`}
                            >
                                <Icon className="h-4 w-4" />
                            </Button>
                        ))}
                    </div>
                </CardHeader>
                <CardContent className="pl-2">
                    <div className="h-[260px] min-h-[200px] w-full min-w-0">
                        {evolucion.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%" minWidth={200} minHeight={200}>
                                {chartType === 'line' && (
                                    <LineChart {...commonChartProps}>
                                        {commonAxis}
                                        <Line type="monotone" dataKey="facturacion" stroke="hsl(var(--primary))" strokeWidth={2.5} dot={{ fill: 'hsl(var(--primary))', r: 4 }} activeDot={{ r: 6, strokeWidth: 2 }} />
                                    </LineChart>
                                )}
                                {chartType === 'bar' && (
                                    <BarChart {...commonChartProps}>
                                        {commonAxis}
                                        <Bar dataKey="facturacion" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                )}
                                {chartType === 'area' && (
                                    <AreaChart {...commonChartProps}>
                                        {commonAxis}
                                        <Area type="monotone" dataKey="facturacion" stroke="hsl(var(--primary))" fill="hsl(var(--primary))" fillOpacity={0.3} strokeWidth={2} />
                                    </AreaChart>
                                )}
                            </ResponsiveContainer>
                        ) : (
                            <div className="flex h-full items-center justify-center text-slate-400 text-sm">
                                Sin datos de evolución en este período
                            </div>
                        )}
                    </div>
                </CardContent>
            </Card>

            <Card className="border border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/60 shadow-lg">
                <CardHeader className="pb-2">
                    <CardTitle className="text-base font-semibold text-slate-800 dark:text-slate-100">
                        Facturas por estado
                    </CardTitle>
                    <p className="text-xs text-slate-500 dark:text-slate-400">
                        Distribución en el período
                    </p>
                </CardHeader>
                <CardContent>
                    <div className="h-[260px] min-h-[200px] w-full min-w-0">
                        {estados.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%" minWidth={200} minHeight={200}>
                                <PieChart>
                                    <Pie
                                        data={estados}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={55}
                                        outerRadius={85}
                                        paddingAngle={3}
                                        dataKey="cantidad"
                                        nameKey="estado"
                                        label={(props: any) =>
                                            `${estadoLabels[props.name] || props.name} ${((props.percent || 0) * 100).toFixed(0)}%`
                                        }
                                    >
                                        {estados.map((_, i) => (
                                            <Cell key={i} fill={COLORS[i % COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip
                                        formatter={(value: any, name: any) => [
                                            Number(value),
                                            estadoLabels[name] || name,
                                        ]}
                                    />
                                    <Legend
                                        verticalAlign="bottom"
                                        height={36}
                                        formatter={(value) => estadoLabels[value] || value}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="flex h-full items-center justify-center text-slate-400 text-sm">
                                Sin facturas en este período
                            </div>
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

'use client'

import { useRouter, useSearchParams } from 'next/navigation'
import { useCallback, useState, useEffect } from 'react'
import { Calendar, Check } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from '@/components/ui/popover'
import { cn } from '@/lib/utils'
import { getRangeForPeriodo, type PeriodoValue, type VistaValue } from '@/lib/dashboard-period'

export type { PeriodoValue, VistaValue }

const PERIODO_OPTIONS: { value: PeriodoValue; label: string }[] = [
    { value: 'actual', label: 'Mes actual' },
    { value: 'anterior', label: 'Mes anterior' },
    { value: 'trimestre', label: 'Este trimestre' },
    { value: 'ytd', label: 'Año hasta hoy' },
    { value: 'ultimo_anio', label: 'Últimos 12 meses' },
    { value: 'custom', label: 'Rango personalizado' },
]

interface DashboardPeriodSelectorProps {
    periodo: PeriodoValue
    desde: string
    hasta: string
    vista?: VistaValue
    className?: string
}

export function DashboardPeriodSelector({ periodo, desde, hasta, vista = 'mes', className }: DashboardPeriodSelectorProps) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const [customDesde, setCustomDesde] = useState(desde)
    const [customHasta, setCustomHasta] = useState(hasta)
    const [open, setOpen] = useState(false)
    const [isApplying, setIsApplying] = useState(false)

    // Sincronizar con props cuando cambian (ej. tras navegación)
    useEffect(() => {
        setCustomDesde(desde)
        setCustomHasta(hasta)
    }, [desde, hasta])

    const applyParams = useCallback(
        (p: PeriodoValue, d?: string, h?: string) => {
            const range = getRangeForPeriodo(p, d, h)
            const params = new URLSearchParams(searchParams.toString())
            params.set('periodo', p)
            params.set('desde', range.desde)
            params.set('hasta', range.hasta)
            params.set('vista', vista)
            setIsApplying(true)
            router.push(`/dashboard?${params.toString()}`)
            setOpen(false)
            router.refresh()
            setTimeout(() => setIsApplying(false), 800)
        },
        [router, searchParams, vista]
    )

    const handlePeriodoChange = (value: string) => {
        const p = value as PeriodoValue
        if (p === 'custom') {
            setCustomDesde(desde)
            setCustomHasta(hasta)
        } else {
            applyParams(p)
        }
    }

    const handleApplyCustom = () => {
        if (customDesde && customHasta && customDesde <= customHasta) {
            applyParams('custom', customDesde, customHasta)
        }
    }

    const periodLabel =
        periodo === 'custom'
            ? `${desde} – ${hasta}`
            : periodo === 'actual'
                ? 'Mes actual'
                : periodo === 'anterior'
                    ? 'Mes anterior'
                    : periodo === 'trimestre'
                        ? 'Este trimestre'
                        : periodo === 'ytd'
                            ? 'Año hasta hoy'
                            : periodo === 'ultimo_anio'
                                ? 'Últimos 12 meses'
                                : periodo

    return (
        <Popover open={open} onOpenChange={setOpen}>
            <PopoverTrigger asChild>
                <Button
                    variant="outline"
                    data-testid="dashboard-period-btn"
                    disabled={isApplying}
                    className={cn(
                        'min-w-[180px] sm:min-w-[220px] justify-start gap-2 font-medium border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 hover:bg-slate-50 dark:hover:bg-slate-800',
                        isApplying && 'opacity-70',
                        className
                    )}
                >
                    <Calendar className="h-4 w-4 text-slate-500 shrink-0" />
                    <span className="truncate text-left flex-1 min-w-0">{isApplying ? 'Aplicando…' : periodLabel}</span>
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-[340px] p-4" align="end">
                <div className="space-y-4">
                    <div>
                        <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Período</Label>
                        <div className="mt-2 flex flex-wrap gap-2">
                            {PERIODO_OPTIONS.filter((o) => o.value !== 'custom').map((opt) => (
                                <Button
                                    key={opt.value}
                                    variant={periodo === opt.value ? 'default' : 'ghost'}
                                    size="sm"
                                    className={cn(
                                        'h-8 min-h-[44px] sm:min-h-[32px] text-xs transition-colors duration-200 active:scale-[0.98]',
                                        periodo === opt.value && 'ring-2 ring-primary/30'
                                    )}
                                    onClick={() => handlePeriodoChange(opt.value)}
                                >
                                    {periodo === opt.value && <Check className="mr-1 h-3 w-3" />}
                                    {opt.label}
                                </Button>
                            ))}
                        </div>
                    </div>
                    <div className="border-t border-slate-200 dark:border-slate-700 pt-3">
                        <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
                            Rango personalizado
                        </Label>
                        <div className="mt-2 grid grid-cols-2 gap-3">
                            <div>
                                <Label htmlFor="desde" className="text-xs text-slate-500">Desde</Label>
                                <Input
                                    id="desde"
                                    type="date"
                                    value={customDesde}
                                    onChange={(e) => setCustomDesde(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                            <div>
                                <Label htmlFor="hasta" className="text-xs text-slate-500">Hasta</Label>
                                <Input
                                    id="hasta"
                                    type="date"
                                    value={customHasta}
                                    onChange={(e) => setCustomHasta(e.target.value)}
                                    className="mt-1"
                                />
                            </div>
                            <Button
                                className="col-span-2"
                                onClick={handleApplyCustom}
                                disabled={!customDesde || !customHasta || customDesde > customHasta}
                            >
                                Aplicar rango
                            </Button>
                        </div>
                    </div>
                </div>
            </PopoverContent>
        </Popover>
    )
}

'use client'

import Link from 'next/link'
import { usePathname, useRouter } from 'next/navigation'
import Image from 'next/image'
import { cn } from '@/lib/utils'
import { useState, useEffect, useRef } from 'react'
import { clientConfig } from '@/config/clients'
import {
    LayoutDashboard,
    ShoppingCart,
    Receipt,
    Users,
    CreditCard,
    BarChart3,
    Settings,
    ChevronDown,
    ChevronRight,
    Hash,
} from 'lucide-react'

interface NavItem {
    name: string
    href: string
    icon: any
    submenu?: {
        name: string
        href: string
        icon: any
    }[]
}

const navigation: NavItem[] = [
    {
        name: 'Dashboard',
        href: '/dashboard',
        icon: LayoutDashboard,
    },
    {
        name: 'Ventas',
        href: '/ventas',
        icon: ShoppingCart,
        submenu: [
            { name: 'Facturas', href: '/ventas/facturas', icon: Receipt },
            { name: 'Clientes', href: '/ventas/clientes', icon: Users },
            { name: 'Pagos', href: '/ventas/pagos', icon: CreditCard },
            { name: 'Informes', href: '/ventas/informes', icon: BarChart3 },
        ]
    },
]

const tools: NavItem[] = [
    {
        name: 'Configuración',
        href: '/ventas/configuracion/empresa',
        icon: Settings,
        submenu: [
            { name: 'Empresa', href: '/ventas/configuracion/empresa', icon: Settings },
            { name: 'Series', href: '/ventas/configuracion/series', icon: Hash },
        ]
    },
]

interface SidebarProps {
    className?: string
    userEmail?: string
}

export function Sidebar({ className, userEmail }: SidebarProps) {
    const pathname = usePathname()
    const router = useRouter()
    const [openMenus, setOpenMenus] = useState<string[]>([])
    const prevPathRef = useRef(pathname)

    // Auto-open solo el menú que contiene la ruta activa (solo al cambiar pathname)
    useEffect(() => {
        if (pathname !== prevPathRef.current) {
            prevPathRef.current = pathname
            const toOpen: string[] = []
            ;[...navigation, ...tools].forEach(item => {
                if (item.submenu && item.submenu.some(sub => pathname.startsWith(sub.href))) {
                    toOpen.push(item.name)
                }
            })
            if (toOpen.length > 0) {
                setOpenMenus(prev => [...new Set([...prev, ...toOpen])])
            }
        }
    }, [pathname])

    const toggleMenu = (name: string) => {
        setOpenMenus(prev =>
            prev.includes(name)
                ? prev.filter(n => n !== name)
                : [...prev, name]
        )
    }

    const baseEmail = (userEmail || clientConfig.email.admin).toLowerCase()

    // Mejorar lógica de visualización de usuario
    const isClientAdmin = baseEmail === clientConfig.email.admin.toLowerCase()
    const footerName = isClientAdmin ? (clientConfig.nombreCorto || 'Administrador') : (userEmail?.split('@')[0] || 'Usuario')
    const footerInitials = isClientAdmin
        ? (clientConfig.nombreCorto?.[0] || 'A')
        : (baseEmail.split('@')[0] || 'us')
              .substring(0, 2)
              .toUpperCase()

    const renderNavItem = (item: NavItem) => {
        const isActive = pathname === item.href || (item.submenu && item.submenu.some(sub => pathname.startsWith(sub.href)))
        const isOpen = openMenus.includes(item.name)
        const Icon = item.icon

        if (item.submenu) {
            return (
                <div key={item.name} className="space-y-1">
                    <button
                        type="button"
                        onClick={() => toggleMenu(item.name)}
                        className={cn(
                            'w-full group flex items-center justify-between gap-3 rounded-xl px-4 py-3 min-h-[44px] sm:min-h-0 sm:py-3 text-sm font-semibold transition-all duration-500 relative overflow-hidden touch-manipulation',
                            isActive
                                ? 'bg-white/5 text-primary shadow-[inset_0_0_20px_rgba(var(--primary),0.05)]'
                                : 'text-slate-400 hover:bg-white/5 hover:text-slate-100 hover:translate-x-1'
                        )}
                    >
                        <div className="flex items-center gap-3">
                            <Icon className={cn("h-5 w-5 shrink-0 transition-colors", isActive ? "text-primary drop-shadow-[0_0_5px_rgba(var(--primary),0.5)]" : "group-hover:text-primary")} />
                            {item.name}
                        </div>
                        {isOpen ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
                    </button>

                    {isOpen && (
                        <div className="pl-4 space-y-1 animate-in slide-in-from-top-2 duration-200">
                            {item.submenu.map(sub => {
                                const SubIcon = sub.icon
                                return (
                                    <Link
                                        key={sub.name}
                                        href={sub.href}
                                        className={cn(
                                            'group flex items-center gap-3 rounded-lg px-3 py-2.5 min-h-[44px] sm:min-h-0 sm:py-2 text-sm font-medium transition-all duration-300 relative touch-manipulation',
                                            pathname === sub.href
                                                ? 'bg-white/5 text-primary'
                                                : 'text-slate-400 hover:bg-white/5 hover:text-slate-100'
                                        )}
                                    >
                                        <SubIcon className={cn("h-4 w-4 shrink-0 transition-colors", pathname === sub.href ? "text-primary" : "group-hover:text-primary")} />
                                        {sub.name}
                                    </Link>
                                )
                            })}
                        </div>
                    )}
                </div>
            )
        }

        return (
            <Link
                key={item.name}
                href={item.href}
                className={cn(
                    'group flex items-center gap-3 rounded-lg px-3 py-3 min-h-[44px] sm:min-h-0 sm:py-3 text-sm font-medium transition-all duration-300 relative overflow-hidden touch-manipulation',
                    isActive
                        ? 'bg-gradient-to-r from-primary/20 to-transparent text-primary'
                        : 'text-slate-400 hover:bg-white/5 hover:text-slate-100 hover:translate-x-1'
                )}
            >
                {isActive && (
                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary shadow-[0_0_10px_2px_rgba(var(--primary),0.5)]" />
                )}
                <Icon className={cn("h-5 w-5 shrink-0 transition-colors", isActive ? "text-primary drop-shadow-[0_0_5px_rgba(var(--primary),0.5)]" : "group-hover:text-primary")} />
                {item.name}
            </Link>
        )
    }

    return (
        <aside
            className={cn(
                'fixed left-0 top-0 z-40 h-screen w-64 flex flex-col bg-black/95 backdrop-blur-xl text-slate-200 border-r border-white/5 shadow-[20px_0_40px_-15px_rgba(0,0,0,0.5)] transition-all duration-500 overflow-hidden',
                className
            )}
        >
            {/* Logo Section - responsive padding y safe area */}
            <div className="flex-shrink-0 flex h-16 sm:h-20 items-center gap-2 sm:gap-3 px-4 sm:px-6 pt-[env(safe-area-inset-top)] border-b border-white/5 bg-[#050505]">
                <div className="relative h-9 w-9 sm:h-10 sm:w-10 shrink-0 overflow-hidden rounded-lg bg-white/5 p-1 ring-1 ring-white/10">
                    <Image
                        src={clientConfig.logoPath}
                        alt={clientConfig.nombre}
                        fill
                        className="object-contain"
                    />
                </div>
                <div className="min-w-0 flex-1">
                    <p className="font-serif font-bold text-base sm:text-lg text-white tracking-wide truncate">{clientConfig.nombre}</p>
                    <p className="text-[10px] font-bold text-primary tracking-[0.2em] uppercase">ERP Platform</p>
                </div>
            </div>

            {/* Navigation - scroll con safe area y padding responsive */}
            <nav className="flex-1 min-h-0 overflow-y-auto overflow-x-hidden px-4 sm:px-3 py-4 sm:py-6 [&::-webkit-scrollbar]:w-1.5 [&::-webkit-scrollbar-track]:bg-transparent [&::-webkit-scrollbar-thumb]:rounded-full [&::-webkit-scrollbar-thumb]:bg-slate-600/60 hover:[&::-webkit-scrollbar-thumb]:bg-slate-500/70">
                {/* Principal */}
                <div className="space-y-1">
                    <p className="px-3 text-xs sm:text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Principal</p>
                    {navigation.map(renderNavItem)}
                </div>

                {/* Herramientas */}
                <div className="pt-4 sm:pt-6 space-y-1">
                    <p className="px-3 text-xs sm:text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">
                        Herramientas
                    </p>
                    {tools.map(renderNavItem)}
                </div>
            </nav>

            {/* User Info Footer - safe area para iOS */}
            <div className="flex-shrink-0 border-t border-white/5 p-4 pb-[max(1rem,env(safe-area-inset-bottom))] bg-[#171f2c]/50 backdrop-blur-md">
                <button
                    type="button"
                    onClick={() => router.push('/perfil')}
                    className="w-full flex items-center gap-3 p-3 min-h-[52px] rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 transition-all duration-300 cursor-pointer group shadow-inner text-left touch-manipulation active:scale-[0.98]"
                    data-testid="sidebar-user-perfil"
                >
                    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-gradient-to-br from-primary to-primary/80 text-white text-xs font-black shadow-lg shadow-primary/20 group-hover:scale-110 transition-transform">
                        {footerInitials}
                    </div>
                    <div className="flex-1 overflow-hidden">
                        <p className="text-sm font-bold text-white truncate">{footerName}</p>
                        <p className="text-[10px] font-medium text-slate-400 truncate">
                            {userEmail || clientConfig.email.admin}
                        </p>
                    </div>
                </button>
            </div>
        </aside>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Building2, ChevronDown, Check, Plus } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { listarEmpresasUsuarioAction, cambiarEmpresaActivaAction } from '@/app/actions/usuarios-empresas'
import { toast } from 'sonner'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import Image from 'next/image'
import { ConfirmDialog } from '@/components/ui/confirm-dialog'

/**
 * Selector de empresas con diseño Premium y optimización táctil.
 * Soporta variantes para el Header (global) y Formularios (local).
 */

interface Empresa {
    id: string
    razon_social: string
    nombre_comercial?: string | null
    logo_url?: string | null
    tipo_empresa: string
    rol: string
    activa: boolean
}

interface EmpresaSelectorProps {
    variant?: 'header' | 'form'
    onSelect?: (empresaId: string) => void
    selectedId?: string
}

export function EmpresaSelector({ variant = 'header', onSelect, selectedId }: EmpresaSelectorProps) {
    const router = useRouter()
    const [empresas, setEmpresas] = useState<Empresa[]>([])
    const [empresaActiva, setEmpresaActiva] = useState<Empresa | null>(null)
    const [isLoading, setIsLoading] = useState(true)
    const [showConfirm, setShowConfirm] = useState(false)
    const [pendingEmpresaId, setPendingEmpresaId] = useState<string | null>(null)
    const [isAdmin, setIsAdmin] = useState(false)

    const loadEmpresas = async () => {
        setIsLoading(true)
        const result = await listarEmpresasUsuarioAction()
        if (result.success && result.data) {
            setEmpresas(result.data.empresas)
            setIsAdmin(!!result.data.isAdmin) // Cast to boolean

            // Determine active company
            if (result.data.isGlobal) {
                setEmpresaActiva({
                    id: 'ALL',
                    razon_social: 'Todas las Empresas',
                    nombre_comercial: 'Visión Global',
                    tipo_empresa: 'Corporación',
                    rol: 'admin',
                    activa: true
                })
            } else {
                const activa = result.data.empresas.find((e: Empresa) => e.activa) || result.data.empresas[0]
                setEmpresaActiva(activa)
            }
        }
        setIsLoading(false)
    }

    useEffect(() => {
        loadEmpresas()
    }, [])

    const handleSelectEmpresa = (empresaOrId: Empresa | string) => {
        const id = typeof empresaOrId === 'string' ? empresaOrId : empresaOrId.id

        if (variant === 'form') {
            if (id === 'ALL') return // Form variant usually doesn't support ALL unless specific requirement
            onSelect?.(id)
            const emp = empresas.find(e => e.id === id)
            if (emp) setEmpresaActiva(emp)
        } else {
            // En el header, el cambio es global y requiere confirmación
            if (id === empresaActiva?.id) return
            setPendingEmpresaId(id)
            setShowConfirm(true)
        }
    }

    const confirmCambioEmpresa = async () => {
        if (!pendingEmpresaId) return

        // Mover el cierre del diálogo aquí para evitar parpadeos o estados inconsistentes
        const empresaIdToSwitch = pendingEmpresaId

        const result = await cambiarEmpresaActivaAction(empresaIdToSwitch)

        if (result.success) {
            toast.success('Entorno de trabajo actualizado')
            setShowConfirm(false) // Cerrar diálogo visualmente

            // Redirigir al dashboard para cargar el nuevo contexto
            setTimeout(() => {
                window.location.href = '/dashboard'
            }, 300)
        } else {
            toast.error(result.error || 'Error al cambiar de empresa')
            setPendingEmpresaId(null) // Reset solo en error
            setShowConfirm(false)
        }
    }

    // Loader minimalista con animación pulsante
    if (isLoading) {
        return (
            <div className="h-10 w-[200px] bg-slate-100 dark:bg-slate-800 rounded-xl animate-pulse flex items-center px-3 gap-2">
                <div className="w-6 h-6 rounded bg-slate-200 dark:bg-slate-700" />
                <div className="h-3 w-24 bg-slate-200 dark:bg-slate-700 rounded" />
            </div>
        )
    }

    if (empresas.length === 0 && !isAdmin) return null

    // Caso de empresa única en selector de formulario (Simplificado)
    if (empresas.length === 1 && !isAdmin && variant === 'form') {
        const emp = empresas[0]
        return (
            <div className="flex items-center gap-3 px-4 py-3 bg-white/50 dark:bg-slate-900/50 backdrop-blur rounded-xl border border-slate-200 dark:border-slate-800">
                {emp.logo_url ? (
                    <Image
                        src={emp.logo_url}
                        alt={emp.razon_social}
                        width={32}
                        height={32}
                        className="w-8 h-8 rounded-lg object-cover shadow-sm"
                    />
                ) : (
                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-amber-400 to-amber-600 flex items-center justify-center">
                        <Building2 className="w-4 h-4 text-white" />
                    </div>
                )}
                <span className="font-bold text-slate-700 dark:text-slate-300">{emp.razon_social}</span>
            </div>
        )
    }

    return (
        <>
            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button
                        data-testid="empresa-selector-trigger"
                        variant={variant === 'header' ? 'ghost' : 'outline'}
                        className={`group transition-all duration-300 active:scale-95 touch-manipulation ${
                            variant === 'header'
                                ? 'h-11 min-h-[44px] px-3 gap-3 bg-white/40 dark:bg-slate-900/40 backdrop-blur-md rounded-2xl hover:bg-white/60 dark:hover:bg-slate-900/60 border border-white/20 dark:border-slate-800/20'
                                : 'w-full justify-between h-12 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border-slate-200 dark:border-slate-800 rounded-2xl shadow-sm'
                        }`}
                    >
                        <div className="flex items-center gap-3">
                            {empresaActiva?.id === 'ALL' ? (
                                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-md">
                                    <Building2 className="w-4 h-4 text-white" />
                                </div>
                            ) : empresaActiva?.logo_url ? (
                                <img
                                    src={empresaActiva.logo_url}
                                    alt={empresaActiva.razon_social}
                                    className="w-8 h-8 rounded-lg object-cover shadow-sm group-hover:scale-105 transition-transform"
                                />
                            ) : (
                                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-amber-400 to-amber-600 flex items-center justify-center shadow-md">
                                    <Building2 className="w-4 h-4 text-white" />
                                </div>
                            )}
                            <span className="font-black text-sm tracking-tight truncate max-w-[140px] md:max-w-[200px] text-slate-800 dark:text-slate-200 uppercase">
