interface InformesTabVentasProps {
    fechaDesde?: string
    fechaHasta?: string
    empresaId?: string | null
    clienteId?: string | null
}

const COLORS = [
    'hsl(var(--primary))',  // Rojo FNAUTOS
    '#020202',              // Negro Premium
    '#4D4D4D',              // Gris oscuro
    '#CC0108',              // Rojo sólido
    '#1A1A1A',              // Antracita
    '#7f0005'               // Rojo oscuro
]

export function InformesTabVentas({ fechaDesde, fechaHasta, empresaId, clienteId }: InformesTabVentasProps) {
    const [evolucion, setEvolucion] = useState<EvolucionData[]>([])
    const [estados, setEstados] = useState<EstadoData[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)

    useEffect(() => {
        const load = async () => {
            setLoading(true)
            setError(null)
            try {
                const [evRes, estRes] = await Promise.all([
                    getEvolucionFacturacionAction(fechaDesde, fechaHasta, empresaId, clienteId),
                    getEstadoFacturasAction(fechaDesde, fechaHasta, empresaId, clienteId),
                ])
                if (evRes.success && evRes.data) setEvolucion(Array.isArray(evRes.data) ? evRes.data : [])
                else if (!evRes.success) setError(evRes.error ?? 'Error al cargar evolución')
                if (estRes.success && estRes.data) setEstados((Array.isArray(estRes.data) ? estRes.data : []).filter((e) => e.estado !== 'anulada'))
                else if (!estRes.success) setError((prev) => prev || (estRes.error ?? 'Error al cargar estado de facturas'))
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err)
                setError(msg.includes('fetch') || msg.includes('Failed to fetch') ? 'Error de conexión. Comprueba tu conexión e intenta de nuevo.' : msg)
            } finally {
                setLoading(false)
            }
        }
        load()
    }, [fechaDesde, fechaHasta, empresaId, clienteId])

    if (loading) {
        return (
            <div className="grid gap-4 md:grid-cols-2">
                <Card className="h-[320px] animate-pulse bg-slate-100 dark:bg-slate-800" />
                <Card className="h-[320px] animate-pulse bg-slate-100 dark:bg-slate-800" />
            </div>
        )
    }

    if (error) {
        return (
            <Card className="border border-amber-200 dark:border-amber-800 bg-amber-50/50 dark:bg-amber-950/20">
                <CardContent className="py-8 px-4 text-center">
                    <p className="text-amber-800 dark:text-amber-200 font-medium mb-1">Error al cargar los datos</p>
                    <p className="text-sm text-slate-600 dark:text-slate-400 mb-4">{error}</p>
                    <p className="text-xs text-slate-500 dark:text-slate-500">
                        Comprueba los filtros de empresa y cliente. Si el problema persiste, contacta con soporte técnico.
                    </p>
                </CardContent>
            </Card>
        )
    }

    const emptyEvolucion = !evolucion?.length
    const emptyEstados = !estados?.length
    const estadoLabels: Record<string, string> = { pagada: 'Pagadas', emitida: 'Emitidas', borrador: 'Borradores', vencida: 'Vencidas' }

    return (
        <div className="grid gap-4 grid-cols-1 lg:grid-cols-3 min-w-0">
            <Card className="lg:col-span-2 border border-slate-200 dark:border-slate-700">
                <CardHeader>
                    <CardTitle className="text-lg flex items-center">
                        Evolución de facturación
                        <SectionInfoButton
                            title="Evolución de facturación"
                            description="Comparativa de la facturación mes a mes (o por trimestre) en el rango seleccionado. Sirve para identificar tendencias, estacionalidad y meses con más o menos ingresos."
                        />
                    </CardTitle>
                    <CardDescription>Comparativa mensual de ingresos</CardDescription>
                </CardHeader>
                <CardContent className="pl-2 pr-2 sm:pr-6 overflow-hidden">
                    <div className="h-[260px] min-[480px]:h-[300px] sm:h-[340px] min-h-[200px] min-w-[200px] w-full flex items-center justify-center">
                        {emptyEvolucion ? (
                            <p className="text-sm text-slate-500 dark:text-slate-400 text-center px-4">
                                No hay facturas en el período seleccionado. Prueba con otro rango de fechas (por ejemplo &quot;Últimos 12 meses&quot;) o revisa los filtros de empresa y cliente.
                            </p>
                        ) : (
                            <ResponsiveContainer width="100%" height="100%" minWidth={200} minHeight={200}>
                                <LineChart data={evolucion} margin={{ top: 24, right: 12, left: 4, bottom: 8 }}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(148,163,184,0.4)" />
                                    <XAxis dataKey="periodo" stroke="hsl(var(--foreground))" fontSize={11} tick={{ fill: 'hsl(var(--foreground))' }} tickLine={false} axisLine={false} />
                                    <YAxis stroke="hsl(var(--foreground))" fontSize={11} tick={{ fill: 'hsl(var(--foreground))' }} tickLine={false} axisLine={false} tickFormatter={(v) => `${v}€`} width={44} />
                                    <Tooltip formatter={(value: any) => [new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(Number(value || 0)), 'Facturación']} />
                                    <Line type="monotone" dataKey="facturacion" stroke="hsl(var(--primary))" strokeWidth={2.5} activeDot={{ r: 10 }}>
                                        <LabelList position="top" formatter={(v: any) => new Intl.NumberFormat('es-ES', { notation: 'compact', maximumFractionDigits: 1 }).format(Number(v || 0)) + '€'} />
                                    </Line>
                                </LineChart>
                            </ResponsiveContainer>
                        )}
                    </div>
                </CardContent>
            </Card>
            <Card className="border border-slate-200 dark:border-slate-700">
                <CardHeader>
                    <CardTitle className="text-lg flex items-center">
                        Estado de facturas
                        <SectionInfoButton
                            title="Estado de facturas"
                            description="Distribución del número de facturas según su estado: pagada, pendiente de cobro, vencida, etc. Las facturas anuladas no se incluyen. Útil para ver cuánto está por cobrar."
                        />
                    </CardTitle>
                    <CardDescription>Distribución por estado</CardDescription>
                </CardHeader>
                <CardContent className="px-2 sm:px-6 overflow-hidden">
                    <div className="h-[260px] min-[480px]:h-[300px] sm:h-[340px] min-h-[200px] min-w-[200px] w-full flex items-center justify-center">
                        {emptyEstados ? (
                            <p className="text-sm text-slate-500 dark:text-slate-400 text-center px-4">
                                No hay facturas en el período seleccionado. Ajusta las fechas o los filtros.
                            </p>
                        ) : (
                            <ResponsiveContainer width="100%" height="100%" minWidth={200} minHeight={200}>
                                <PieChart margin={{ top: 8, right: 8, bottom: 8, left: 8 }}>
                                    <Pie
                                        data={estados}
                                        cx="50%"
                                        cy="45%"
                                        innerRadius="40%"
                                        outerRadius="55%"
                                        paddingAngle={4}
                                        dataKey="cantidad"
                                        nameKey="estado"
                                    >
                                        {estados.map((_, i) => (
                                            <Cell key={i} fill={COLORS[i % COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <Tooltip formatter={(v: any) => [Number(v || 0), 'Facturas']} />
                                    <Legend
                                        verticalAlign="bottom"
                                        height={56}
                                        wrapperStyle={{ fontSize: 12 }}
                                        formatter={(value) => {
                                            const item = estados.find((e) => e.estado === value)
                                            const cant = item?.cantidad ?? 0
                                            const total = estados.reduce((a, e) => a + e.cantidad, 0)
                                            const pct = total > 0 ? ((cant / total) * 100).toFixed(0) : ''
                                            return `${estadoLabels[value] || value}: ${cant}${pct ? ` (${pct}%)` : ''}`
                                        }}
                                    />
                                </PieChart>
                            </ResponsiveContainer>
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Bell, Check, X, Trash2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { ScrollArea } from '@/components/ui/scroll-area'
import { toast } from 'sonner'
import {
    obtenerNotificacionesAction,
    marcarNotificacionLeidaAction,
    marcarTodasLeidasAction,
    eliminarNotificacionAction,
    contarNotificacionesNoLeidasAction
} from '@/app/actions/notificaciones'
import type { Notificacion } from '@/types/notificaciones'
import { useRouter } from 'next/navigation'
import { cn } from '@/lib/utils'

export function NotificacionesDropdown() {
    const router = useRouter()
    const [notificaciones, setNotificaciones] = useState<Notificacion[]>([])
    const [noLeidas, setNoLeidas] = useState(0)
    const [loading, setLoading] = useState(false)
    const [open, setOpen] = useState(false)

    const cargarNotificaciones = async () => {
        setLoading(true)
        const result = await obtenerNotificacionesAction(20, false)
        if (result.success && result.data) {
            setNotificaciones(result.data)
        }
        setLoading(false)
    }

    const cargarContador = async () => {
        const result = await contarNotificacionesNoLeidasAction()
        if (result.success) {
            setNoLeidas(result.count)
        }
    }

    useEffect(() => {
        cargarContador()
        // Actualizar contador cada 30 segundos
        const interval = setInterval(cargarContador, 30000)
        return () => clearInterval(interval)
    }, [])

    useEffect(() => {
        if (open) {
            cargarNotificaciones()
        }
    }, [open])

    const handleMarcarLeida = async (notificacionId: string) => {
        const result = await marcarNotificacionLeidaAction(notificacionId)
        if (result.success) {
            setNotificaciones(prev =>
                prev.map(n => n.id === notificacionId ? { ...n, leida: true } : n)
            )
            setNoLeidas(prev => Math.max(0, prev - 1))
        }
    }

    const handleMarcarTodasLeidas = async () => {
        const result = await marcarTodasLeidasAction()
        if (result.success) {
            setNotificaciones(prev => prev.map(n => ({ ...n, leida: true })))
            setNoLeidas(0)
            toast.success('Todas las notificaciones marcadas como leídas')
        }
    }

    const handleEliminar = async (notificacionId: string, e: React.MouseEvent) => {
        e.stopPropagation()
        const result = await eliminarNotificacionAction(notificacionId)
        if (result.success) {
            setNotificaciones(prev => prev.filter(n => n.id !== notificacionId))
            const notif = notificaciones.find(n => n.id === notificacionId)
            if (notif && !notif.leida) {
                setNoLeidas(prev => Math.max(0, prev - 1))
            }
            toast.success('Notificación eliminada')
        }
    }

    const handleClickNotificacion = async (notificacion: Notificacion) => {
        if (!notificacion.leida) {
            await handleMarcarLeida(notificacion.id)
        }
        if (notificacion.enlace) {
            setOpen(false)
            router.push(notificacion.enlace)
        }
    }

    const getTipoColor = (tipo: string) => {
        switch (tipo) {
            case 'success':
                return 'text-green-600 dark:text-green-400'
            case 'warning':
                return 'text-yellow-600 dark:text-yellow-400'
            case 'error':
                return 'text-red-600 dark:text-red-400'
            default:
                return 'text-blue-600 dark:text-blue-400'
        }
    }

    const getTipoBg = (tipo: string) => {
        switch (tipo) {
            case 'success':
                return 'bg-green-50 dark:bg-green-950/20'
            case 'warning':
                return 'bg-yellow-50 dark:bg-yellow-950/20'
            case 'error':
                return 'bg-red-50 dark:bg-red-950/20'
            default:
                return 'bg-blue-50 dark:bg-blue-950/20'
        }
    }

    return (
        <DropdownMenu open={open} onOpenChange={setOpen}>
            <DropdownMenuTrigger asChild>
                <Button
                    variant="ghost"
                    size="icon"
                    data-testid="navbar-notifications"
                    className="relative h-11 w-11 min-h-[44px] min-w-[44px] rounded-2xl hover:bg-slate-100 dark:hover:bg-white/5 text-slate-500 hover:text-primary transition-all duration-300 group touch-manipulation"
                >
                    <Bell className="h-5 w-5 group-hover:rotate-12 transition-transform" />
                    {noLeidas > 0 && (
                        <>
                            <span className="absolute top-3 right-3 h-2.5 w-2.5 rounded-full bg-gradient-to-tr from-red-500 to-orange-400 ring-2 ring-white dark:ring-slate-900 shadow-[0_0_8px_rgba(239,68,68,0.5)]" />
                            <span className="absolute -top-1 -right-1 h-5 w-5 rounded-full bg-red-500 text-white text-[10px] font-bold flex items-center justify-center ring-2 ring-white dark:ring-slate-900">
                                {noLeidas > 9 ? '9+' : noLeidas}
                            </span>
                        </>
                    )}
                    <span className="sr-only">Notificaciones</span>
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent
                align="end"
                className="w-[min(420px,90vw)] max-w-[420px] p-0 bg-white dark:bg-slate-900 border-slate-200 dark:border-white/10 shadow-2xl"
            >
                <div className="flex items-center justify-between px-4 py-3 border-b border-slate-200 dark:border-white/10">
                    <h3 className="font-semibold text-slate-900 dark:text-white">
                        Notificaciones
                        {noLeidas > 0 && (
                            <span className="ml-2 text-xs text-slate-500 dark:text-slate-400">
                                ({noLeidas} nuevas)
                            </span>
                        )}
                    </h3>
                    {notificaciones.length > 0 && noLeidas > 0 && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={handleMarcarTodasLeidas}
                            className="h-7 text-xs hover:bg-slate-100 dark:hover:bg-white/5"
                        >
                            <Check className="h-3 w-3 mr-1" />
                            Marcar todas
                        </Button>
                    )}
                </div>

                <ScrollArea className="h-[400px]">
                    {loading ? (
                        <div className="flex items-center justify-center py-12">
                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                        </div>
                    ) : notificaciones.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-12 px-4 text-center">
                            <Bell className="h-12 w-12 text-slate-300 dark:text-slate-600 mb-3" />
                            <p className="text-sm text-slate-500 dark:text-slate-400 font-medium">
                                No tienes notificaciones
                            </p>
                            <p className="text-xs text-slate-400 dark:text-slate-500 mt-1">
                                Te avisaremos cuando haya novedades
                            </p>
                        </div>
                    ) : (
                        <div className="divide-y divide-slate-100 dark:divide-white/5">
                            {notificaciones.map((notif) => (
                                <div
                                    key={notif.id}
                                    onClick={() => handleClickNotificacion(notif)}
                                    className={cn(
                                        'px-4 py-3 transition-all duration-200 group relative',
                                        notif.enlace && 'cursor-pointer hover:bg-slate-50 dark:hover:bg-white/5',
                                        !notif.leida && 'bg-blue-50/50 dark:bg-blue-950/10'
                                    )}
                                >
                                    <div className="flex items-start gap-3">
                                        <div
                                            className={cn(
                                                'flex-shrink-0 w-2 h-2 rounded-full mt-2',
                                                !notif.leida ? 'bg-blue-500' : 'bg-transparent'
                                            )}
                                        />
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-start justify-between gap-2">
                                                <p className={cn(
                                                    'text-sm font-semibold',
                                                    getTipoColor(notif.tipo)
                                                )}>
                                                    {notif.titulo}
                                                </p>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    onClick={(e) => handleEliminar(notif.id, e)}
                                                    className="h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-100 dark:hover:bg-red-950/20 hover:text-red-600"
                                                >
                                                    <Trash2 className="h-3 w-3" />
                                                </Button>
                                            </div>
                                            <p className="text-sm text-slate-600 dark:text-slate-400 mt-1 line-clamp-2">
                                                {notif.mensaje}
                                            </p>
                                            <p className="text-xs text-slate-400 dark:text-slate-500 mt-2">
                                                {new Date(notif.created_at).toLocaleString('es-ES', {
                                                    day: '2-digit',
                                                    month: 'short',
                                                    hour: '2-digit',
                                                    minute: '2-digit'
                                                })}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </ScrollArea>
            </DropdownMenuContent>
        </DropdownMenu>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { zodResolver } from '@hookform/resolvers/zod'
import { useForm } from 'react-hook-form'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Checkbox } from '@/components/ui/checkbox'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'

import { pagoSchema, PagoFormData } from '@/lib/validations/pago-schema'
import { registrarPagoAction } from '@/app/actions/pagos'

interface PagoFormProps {
    facturas: any[]
}

interface PagoFormValues {
    factura_id: string
    importe: number
    fecha_pago: string
    metodo_pago: 'transferencia' | 'tarjeta' | 'efectivo' | 'domiciliacion' | 'cheque' | 'otro'
    conciliado: boolean
    marcar_como_pagada: boolean
    referencia?: string
    cuenta_bancaria?: string
    notas?: string
}

export function PagoForm({ facturas }: PagoFormProps) {
    const router = useRouter()
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [selectedFactura, setSelectedFactura] = useState<any>(null)

    const form = useForm<PagoFormValues>({
        resolver: zodResolver(pagoSchema) as any,
        defaultValues: {
            factura_id: '',
            importe: 0.01,
            fecha_pago: new Date().toISOString().split('T')[0],
            metodo_pago: 'transferencia',
            conciliado: false,
            marcar_como_pagada: false,
            referencia: '',
            cuenta_bancaria: '',
            notas: '',
        },
    })

    // Update selected factura details when changed
    const handleFacturaChange = (facturaId: string) => {
        const factura = facturas.find(f => f.id === facturaId)
        setSelectedFactura(factura)
        form.setValue('factura_id', facturaId)

        // Set max importe based on pending amount
        if (factura) {
            const pendiente = factura.total - (factura.pagado || 0)
            form.setValue('importe', Number(pendiente.toFixed(2)))
        }
    }

    const onSubmit = async (data: PagoFormValues) => {
        setIsSubmitting(true)
        try {
            const formData = new FormData()
            Object.entries(data).forEach(([key, value]) => {
                if (key === 'conciliado') {
                    formData.append(key, value ? 'true' : 'false')
                } else {
                    formData.append(key, String(value))
                }
            })

            const result = await registrarPagoAction(formData)

            if (result.success) {
                toast.success('Pago registrado correctamente')
                router.push('/ventas/pagos')
                router.refresh()
            } else {
                toast.error(result.error)
            }
        } catch (_error) {
            toast.error('Error al registrar pago')
        } finally {
            setIsSubmitting(false)
        }
    }

    return (
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Factura Select */}
                <div className="space-y-2 col-span-2">
                    <Label htmlFor="factura_id">Factura Pendiente</Label>
                    <Select onValueChange={handleFacturaChange} value={form.watch('factura_id')}>
                        <SelectTrigger>
                            <SelectValue placeholder="Selecciona una factura..." />
                        </SelectTrigger>
                        <SelectContent>
                            {facturas.map((factura) => (
                                <SelectItem key={factura.id} value={factura.id}>
                                    {factura.serie}-{factura.numero} - {factura.cliente?.nombre_fiscal} (Pendiente: {(factura.total - (factura.pagado || 0)).toFixed(2)}€)
                                </SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                    {form.formState.errors.factura_id && (
                        <p className="text-sm text-red-500">{form.formState.errors.factura_id.message}</p>
                    )}
                </div>

                {/* Importe */}
                <div className="space-y-2">
                    <Label htmlFor="importe">Importe (€)</Label>
                    <Input
                        {...form.register('importe', { valueAsNumber: true })}
                        type="number"
                        step="0.01"
                        placeholder="0.00"
                    />
                    {selectedFactura && (
                        <p className="text-xs text-slate-500">
                            Máximo sugerido: {(selectedFactura.total - (selectedFactura.pagado || 0)).toFixed(2)}€
                        </p>
                    )}
                    {form.formState.errors.importe && (
                        <p className="text-sm text-red-500">{form.formState.errors.importe.message}</p>
                    )}
                </div>

                {/* Fecha Pago */}
                <div className="space-y-2">
                    <Label htmlFor="fecha_pago">Fecha de Pago</Label>
                    <Input
                        {...form.register('fecha_pago')}
                        type="date"
                    />
                    {form.formState.errors.fecha_pago && (
                        <p className="text-sm text-red-500">{form.formState.errors.fecha_pago.message}</p>
                    )}
                </div>

                {/* Metodo Pago */}
                <div className="space-y-2">
                    <Label htmlFor="metodo_pago">Método de Pago</Label>
                    <Select
                        onValueChange={(val) => form.setValue('metodo_pago', val as any)}
                        value={form.watch('metodo_pago')}
                    >
                        <SelectTrigger>
                            <SelectValue placeholder="Selecciona método" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="transferencia">Transferencia Bancaria</SelectItem>
                            <SelectItem value="tarjeta">Tarjeta Crédito/Débito</SelectItem>
                            <SelectItem value="efectivo">Efectivo</SelectItem>
                            <SelectItem value="domiciliacion">Domiciliación</SelectItem>
                            <SelectItem value="cheque">Cheque</SelectItem>
                            <SelectItem value="otro">Otro</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                {/* Referencia */}
                <div className="space-y-2">
                    <Label htmlFor="referencia">Referencia / Nº Operación</Label>
                    <Input {...form.register('referencia')} placeholder="Ej: TRF-123456789" />
                </div>

                {/* Cuenta Bancaria */}
                <div className="space-y-2">
                    <Label htmlFor="cuenta_bancaria">Cuenta Bancaria (Opcional)</Label>
                    <Input {...form.register('cuenta_bancaria')} placeholder="ES12..." />
                </div>

                {/* Conciliado */}
                <div className="flex items-center space-x-2 pt-8">
                    <Checkbox
                        id="conciliado"
                        checked={form.watch('conciliado')}
                        onCheckedChange={(checked) => form.setValue('conciliado', checked === true)}
                    />
                    <Label htmlFor="conciliado" className="font-medium cursor-pointer">
                        Marcar como conciliado
                    </Label>
                </div>
            </div>

            {/* Notas */}
            <div className="space-y-2">
                <Label htmlFor="notas">Notas / Observaciones</Label>
                <Textarea {...form.register('notas')} placeholder="Añadir notas sobre el pago..." />
            </div>

            <div className="flex justify-end gap-4 pt-4">
                <Button
                    type="button"
                    variant="outline"
                    onClick={() => router.back()}
                    disabled={isSubmitting}
                >
                    Cancelar
                </Button>
                <Button
                    type="submit"
                    disabled={isSubmitting}
                    className="bg-linear-to-r from-primary to-primary/80 hover:scale-105 transition-all text-white font-bold"
                >
                    {isSubmitting ? 'Registrando...' : 'Registrar Pago'}
                </Button>
            </div>
        </form>
    )
}

'use client'

import { useState } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Checkbox } from '@/components/ui/checkbox'
import { toggleConciliadoAction } from '@/app/actions/pagos'
import { toast } from 'sonner'

interface Pago {
    id: string
    factura_id: string
    serie: string
    numero: number
    cliente_nombre: string
    fecha_vencimiento: string
    factura_total: number
    pendiente: number
    metodo_pago: string | null
    factura_estado: string
    conciliado: boolean
    /** true = fila de factura pendiente (sin pago aún); no mostrar checkbox conciliado */
    esFacturaRow?: boolean
}

interface PagosTablaProps {
    pagos: Pago[]
    tab: string
    search?: string
    metodo?: string
}

export function PagosTabla({ pagos, tab, search = '', metodo = 'todos' }: PagosTablaProps) {
    const router = useRouter()
    const [searchValue, setSearchValue] = useState(search)

    const handleToggleConciliado = async (pagoId: string, conciliado: boolean) => {
        const result = await toggleConciliadoAction(pagoId, !conciliado)
        if (result.success) {
            toast.success(conciliado ? 'Pago desmarcado' : 'Pago conciliado')
            router.refresh()
        } else {
            toast.error(result.error)
        }
    }

    const getEstadoBadge = (estado: string) => {
        if (estado === 'pagada') {
            return <Badge className="bg-green-100 text-green-700">✅ Pagado</Badge>
        }
        if (estado === 'parcial') {
            return <Badge className="bg-yellow-100 text-yellow-700">🟡 Parcial</Badge>
        }
        return <Badge className="bg-blue-100 text-blue-700">⏳ Pendiente</Badge>
    }

    const buildUrl = (nextTab: string, nextSearch: string, nextMetodo: string) => {
        const params = new URLSearchParams()
        if (nextTab && nextTab !== 'todos') params.set('tab', nextTab)
        if (nextSearch.trim()) params.set('search', nextSearch.trim())
        if (nextMetodo && nextMetodo !== 'todos') params.set('metodo', nextMetodo)
        const qs = params.toString()
        return `/ventas/pagos${qs ? `?${qs}` : ''}`
    }

    const handleTabChange = (value: string) => {
        router.push(buildUrl(value, searchValue, metodo))
    }

    const handleSearchChange = (value: string) => {
        setSearchValue(value)
        router.push(buildUrl(tab, value, metodo))
    }

    const handleMetodoChange = (value: string) => {
        router.push(buildUrl(tab, searchValue, value))
    }

    return (
        <div className="space-y-4">
            {/* Tabs */}
            <Tabs value={tab} onValueChange={handleTabChange}>
                <TabsList>
                    <TabsTrigger value="todos">Todos los Pagos</TabsTrigger>
                    <TabsTrigger value="pendientes">Pendientes</TabsTrigger>
                    <TabsTrigger value="cobrados">Cobrados</TabsTrigger>
                    <TabsTrigger value="vencidos">Vencidos</TabsTrigger>
                    <TabsTrigger value="parciales">Parciales</TabsTrigger>
                </TabsList>
            </Tabs>

            {/* Filtros */}
            <div className="flex flex-wrap gap-4 items-center">
                <Input
                    placeholder="Buscar factura, cliente o referencia..."
                    className="max-w-md"
                    value={searchValue}
                    onChange={(e) => handleSearchChange(e.target.value)}
                />
                <select
                    className="h-9 rounded-md border border-slate-200 bg-white px-2 text-sm text-slate-700 dark:bg-slate-900 dark:border-slate-700 dark:text-slate-200"
                    value={metodo}
                    onChange={(e) => handleMetodoChange(e.target.value)}
                >
                    <option value="todos">Todos los métodos</option>
                    <option value="transferencia">Transferencia</option>
                    <option value="tarjeta">Tarjeta</option>
                    <option value="efectivo">Efectivo</option>
                    <option value="domiciliacion">Domiciliación</option>
                    <option value="cheque">Cheque</option>
                    <option value="otro">Otro</option>
                </select>
            </div>

            {/* Tabla */}
            <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
                <table className="w-full">
                    <thead className="bg-slate-100 dark:bg-slate-800">
                        <tr>
                            <th className="p-4 text-left text-xs font-semibold uppercase">Factura</th>
                            <th className="p-4 text-left text-xs font-semibold uppercase">Cliente</th>
                            <th className="p-4 text-left text-xs font-semibold uppercase">Vencimiento</th>
                            <th className="p-4 text-right text-xs font-semibold uppercase">Total</th>
                            <th className="p-4 text-right text-xs font-semibold uppercase">Pagado</th>
                            <th className="p-4 text-right text-xs font-semibold uppercase">Pendiente</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase">Método</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase">Estado</th>
                            <th className="p-4 text-center text-xs font-semibold uppercase">Conciliado</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {pagos.map((pago) => (
                            <tr key={pago.id} className="hover:bg-white/5 transition-colors">
                                <td className="p-4 font-mono font-semibold">
                                    <Link href={`/ventas/facturas/${pago.factura_id}`} className="hover:text-primary">
                                        {pago.serie}-{pago.numero}
                                    </Link>
                                </td>
                                <td className="p-4">{pago.cliente_nombre}</td>
                                <td className="p-4 text-sm">{new Date(pago.fecha_vencimiento).toLocaleDateString('es-ES')}</td>
                                <td className="p-4 text-right font-bold">{pago.factura_total.toFixed(2)}€</td>
                                <td className="p-4 text-right text-green-600 font-semibold">{(pago.factura_total - pago.pendiente).toFixed(2)}€</td>
                                <td className="p-4 text-right text-red-600 font-semibold">{pago.pendiente.toFixed(2)}€</td>
                                <td className="p-4 text-center text-sm">{pago.metodo_pago || '-'}</td>
                                <td className="p-4 text-center">{getEstadoBadge(pago.factura_estado)}</td>
                                <td className="p-4 text-center">
                                    {pago.esFacturaRow ? (
                                        <span className="text-slate-400 text-sm">—</span>
                                    ) : (
                                        <Checkbox
                                            checked={pago.conciliado}
                                            onCheckedChange={() => handleToggleConciliado(pago.id, pago.conciliado)}
                                        />
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <p className="text-sm text-slate-500">Mostrando {pagos.length} pagos</p>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { FileText, Check } from 'lucide-react'
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select'
import { listarPlantillasEmpresaAction } from '@/app/actions/usuarios-empresas'

interface Plantilla {
    id: string
    nombre: string
    descripcion: string | null
    predeterminada: boolean | null
    activa: boolean | null
    logo_url: string | null
    color_primario: string | null
}

interface PlantillaSelectorProps {
    empresaId: string
    value?: string
    onChange: (plantillaId: string) => void
}

export function PlantillaSelector({ empresaId, value, onChange }: PlantillaSelectorProps) {
    const [plantillas, setPlantillas] = useState<Plantilla[]>([])
    const [isLoading, setIsLoading] = useState(true)

    useEffect(() => {
        const loadPlantillas = async () => {
            setIsLoading(true)
            const result = await listarPlantillasEmpresaAction(empresaId)
            if (result.success && result.data) {
                setPlantillas(result.data)
                // Si hay una predeterminada y no hay valor seleccionado, seleccionarla
                if (!value) {
                    const predeterminada = result.data.find((p: Plantilla) => p.predeterminada)
                    if (predeterminada) {
                        onChange(predeterminada.id)
                    }
                }
            }
            setIsLoading(false)
        }
        loadPlantillas()
    }, [empresaId, value, onChange])

    if (isLoading) {
        return (
            <div className="h-10 bg-slate-100 animate-pulse rounded-md" />
        )
    }

    if (plantillas.length === 0) {
        return (
            <div className="flex items-center gap-2 px-3 py-2 bg-amber-50 rounded-lg border border-amber-200 text-amber-800 text-sm">
                <span>⚠️</span>
                <span>No hay plantillas configuradas para esta empresa</span>
            </div>
        )
    }

    return (
        <div className="min-w-0 w-full">
            <Select value={value} onValueChange={onChange}>
                <SelectTrigger className="bg-white w-full min-w-0 overflow-hidden">
                    <SelectValue placeholder="Seleccionar plantilla..." />
                </SelectTrigger>
            <SelectContent>
                {plantillas.map((plantilla) => (
                    <SelectItem key={plantilla.id} value={plantilla.id}>
                        <div className="flex items-center gap-3 py-1 min-w-0">
                            <div
                                className="w-4 h-4 shrink-0 rounded-sm border"
                                style={{ backgroundColor: plantilla.color_primario ?? '#6366f1' }}
                            />
                            <div className="flex flex-col min-w-0 overflow-hidden">
                                <span className="font-medium truncate">
                                    {plantilla.nombre}
                                    {plantilla.predeterminada && (
                                        <span className="ml-2 text-xs text-primary">(predeterminada)</span>
                                    )}
                                </span>
                                {plantilla.descripcion && (
                                    <span className="text-xs text-slate-500 truncate">{plantilla.descripcion}</span>
                                )}
                            </div>
                        </div>
                    </SelectItem>
                ))}
            </SelectContent>
        </Select>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Switch } from '@/components/ui/switch'
import { Slider } from '@/components/ui/slider'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { Checkbox } from '@/components/ui/checkbox'
import { Upload, Loader2 } from 'lucide-react'
import { crearPlantillaAction, actualizarPlantillaAction, subirLogoAction } from '@/app/actions/plantillas'

interface PlantillaEditorProps {
    plantillaId?: string
    defaultValues?: any
}

/**
 * Editor completo de plantillas PDF con sección de logo, colores, estructura y preview en tiempo real.
 * Aplica el skill premium_ui_design con glassmorphism y micro-interacciones.
 */
export function PlantillaEditor({ plantillaId, defaultValues }: PlantillaEditorProps) {
    const router = useRouter()
    const isEditing = !!plantillaId
    const [isSubmitting, setIsSubmitting] = useState(false)

    // Estados del formulario
    const [logoUrl, setLogoUrl] = useState(defaultValues?.logo_url || '')
    const [logoPosicion, setLogoPosicion] = useState(defaultValues?.logo_posicion || 'izquierda')
    const [logoAncho, setLogoAncho] = useState(defaultValues?.logo_ancho || 120)
    const [logoAlto, setLogoAlto] = useState(defaultValues?.logo_alto || 60)
    const [isUploadingLogo, setIsUploadingLogo] = useState(false)

    // Colores
    const [colorPrimario, setColorPrimario] = useState(defaultValues?.color_primario || '#1a365d')
    const [colorSecundario, setColorSecundario] = useState(defaultValues?.color_secundario || '#718096')
    const [colorEncabezadoTabla, setColorEncabezadoTabla] = useState(defaultValues?.color_encabezado_tabla || '#2d3748')

    // Estructura
    const [alternarColorFilas, setAlternarColorFilas] = useState(defaultValues?.alternar_color_filas ?? true)
    const [mostrarDatosBancarios, setMostrarDatosBancarios] = useState(defaultValues?.mostrar_datos_bancarios ?? true)
    const [mostrarNotas, setMostrarNotas] = useState(defaultValues?.mostrar_notas ?? true)
    const [mostrarQrPago, setMostrarQrPago] = useState(defaultValues?.mostrar_qr_pago ?? false)
    const [mostrarFirma, setMostrarFirma] = useState(defaultValues?.mostrar_firma ?? false)
    const [mostrarSello, setMostrarSello] = useState(defaultValues?.mostrar_sello ?? false)

    // Estado
    const [activa, setActiva] = useState(defaultValues?.activa ?? true)
    const [predeterminada, setPredeterminada] = useState(defaultValues?.predeterminada ?? false)

    // Idiomas
    const [idiomas, setIdiomas] = useState<string[]>(defaultValues?.idiomas || ['es'])

    const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        setIsUploadingLogo(true)
        const formData = new FormData()
        formData.append('logo', file)

        const result = await subirLogoAction(formData)
        setIsUploadingLogo(false)

        if (result.success) {
            setLogoUrl(result.data!.url)
            toast.success('Logo subido correctamente')
        } else {
            toast.error(result.error || 'Error al subir logo')
        }
    }

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault()
        setIsSubmitting(true)

        const formData = new FormData(e.currentTarget)

        // Agregar campos controlados por estado
        formData.set('logo_url', logoUrl)
        formData.set('logo_posicion', logoPosicion)
        formData.set('logo_ancho', String(logoAncho))
        formData.set('logo_alto', String(logoAlto))
        formData.set('color_primario', colorPrimario)
        formData.set('color_secundario', colorSecundario)
        formData.set('color_encabezado_tabla', colorEncabezadoTabla)
        formData.set('idiomas', JSON.stringify(idiomas))
        formData.set('mostrar_numero_factura', 'true')
        formData.set('mostrar_fecha_emision', 'true')
        formData.set('mostrar_fecha_vencimiento', 'true')
        formData.set('mostrar_datos_bancarios', String(mostrarDatosBancarios))
        formData.set('mostrar_notas', String(mostrarNotas))
        formData.set('mostrar_qr_pago', String(mostrarQrPago))
        formData.set('alternar_color_filas', String(alternarColorFilas))
        formData.set('mostrar_firma', String(mostrarFirma))
        formData.set('mostrar_sello', String(mostrarSello))
        formData.set('activa', String(activa))
        formData.set('predeterminada', String(predeterminada))

        const result = isEditing
            ? await actualizarPlantillaAction(plantillaId!, formData)
            : await crearPlantillaAction(formData)

        setIsSubmitting(false)

        if (result.success) {
            toast.success(isEditing ? 'Plantilla actualizada' : 'Plantilla creada')
            router.push('/ventas/configuracion/plantillas')
            router.refresh()
        } else {
            toast.error(result.error || 'Error al guardar')
        }
    }

    const toggleIdioma = (idioma: string, checked: boolean) => {
        if (checked) {
            setIdiomas([...idiomas, idioma])
        } else {
            setIdiomas(idiomas.filter(i => i !== idioma))
        }
    }

    return (
        <form onSubmit={handleSubmit} className="grid lg:grid-cols-2 gap-8">
            {/* Columna Izquierda: Editor */}
            <div className="space-y-6">
                {/* Información básica */}
                <div className="rounded-2xl bg-white/5 backdrop-blur-xl border border-white/10 p-6 shadow-xl">
                    <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                        📝 Información General
                    </h2>

                    <div className="space-y-4">
                        <div>
                            <Label htmlFor="nombre">Nombre de la Plantilla *</Label>
                            <Input
                                id="nombre"
                                name="nombre"
                                defaultValue={defaultValues?.nombre}
                                placeholder="Ej: Plantilla Corporativa"
                                required
                                className="mt-1 bg-white/5 border-white/10 focus:border-primary"
                            />
                        </div>

                        <div>
                            <Label htmlFor="descripcion">Descripción</Label>
                            <Textarea
                                id="descripcion"
                                name="descripcion"
                                defaultValue={defaultValues?.descripcion}
                                placeholder="Descripción breve de la plantilla..."
                                className="mt-1 bg-white/5 border-white/10 focus:border-primary min-h-[80px]"
                            />
                        </div>

                        <div className="flex items-center justify-between pt-2">
                            <div className="flex items-center gap-3">
                                <Switch
                                    id="activa"
                                    checked={activa}
                                    onCheckedChange={setActiva}
                                />
                                <Label htmlFor="activa" className="cursor-pointer">Plantilla activa</Label>
                            </div>
                            <div className="flex items-center gap-3">
                                <Switch
                                    id="predeterminada"
                                    checked={predeterminada}
                                    onCheckedChange={setPredeterminada}
                                />
                                <Label htmlFor="predeterminada" className="cursor-pointer">Predeterminada</Label>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Logo y Cabecera */}
                <div className="rounded-2xl bg-white/5 backdrop-blur-xl border border-white/10 p-6 shadow-xl">
                    <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                        🖼️ Logo y Cabecera
                    </h2>

                    <div className="space-y-5">
                        {/* Preview de logo */}
                        {logoUrl && (
                            <div className="p-4 bg-white rounded-xl border">
                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                <img
                                    src={logoUrl}
                                    alt="Logo preview"
                                    style={{ width: `${logoAncho}px`, height: `${logoAlto}px` }}
                                    className={`object-contain ${logoPosicion === 'centro' ? 'mx-auto' :
                                        logoPosicion === 'derecha' ? 'ml-auto' : ''
                                        }`}
                                />
                            </div>
                        )}

                        {/* Subir logo */}
                        <div className="flex gap-3">
