interface ClienteOption { id: string; label: string; cif?: string }
interface SearchResult { items: ClienteOption[]; total: number; page: number; totalPages: number }
const EMPTY_RESULT: SearchResult = { items: [], total: 0, page: 1, totalPages: 0 }

function ClienteCombobox({ value, label: initialLabel, onChange, disabled }: { value: string; label?: string; onChange: (id: string, label: string) => void; disabled?: boolean }) {
    const [query, setQuery] = useState('')
    const [open, setOpen] = useState(false)
    const [result, setResult] = useState<SearchResult>(EMPTY_RESULT)
    const [loadingMore, setLoadingMore] = useState(false)
    const [searching, setSearching] = useState(false)
    const [selectedLabel, setSelectedLabel] = useState(initialLabel || '')
    const inputRef = useRef<HTMLInputElement>(null)
    const triggerRef = useRef<HTMLDivElement>(null)
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

    const fetchPage = useCallback(async (q: string, page: number, append = false) => {
        if (page === 1) setSearching(true); else setLoadingMore(true)
        try {
            const limit = q ? 25 : 50
            const url = `/api/clientes/search?q=${encodeURIComponent(q)}&page=${page}&limit=${limit}`
            const res = await fetch(url)
            const data: SearchResult = await res.json()
            setResult(prev => append ? { ...data, items: [...prev.items, ...data.items] } : data)
        } catch { if (!append) setResult(EMPTY_RESULT) }
        finally { setSearching(false); setLoadingMore(false) }
    }, [])

    useEffect(() => {
        if (!open) return
        if (debounceRef.current) clearTimeout(debounceRef.current)
        debounceRef.current = setTimeout(() => fetchPage(query, 1), query ? 280 : 0)
        return () => { if (debounceRef.current) clearTimeout(debounceRef.current) }
    }, [open, query, fetchPage])

    useEffect(() => { setSelectedLabel(initialLabel || '') }, [initialLabel, value])

    useEffect(() => {
        if (open) setTimeout(() => inputRef.current?.focus(), 50)
    }, [open])

    const handleSelect = (opt: ClienteOption) => {
        setSelectedLabel(opt.label)
        setQuery('')
        setResult(EMPTY_RESULT)
        setOpen(false)
        onChange(opt.id, opt.label)
    }

    const handleClear = (e: React.MouseEvent) => {
        e.stopPropagation()
        setSelectedLabel('')
        setQuery('')
        setResult(EMPTY_RESULT)
        onChange('', '')
    }

    const hasMore = result.page < result.totalPages

    return (
        <Popover open={open} onOpenChange={(o) => { setOpen(o); if (!o) setQuery('') }}>
            <PopoverTrigger asChild>
                <div
                    ref={triggerRef}
                    className={cn(
                        'flex items-center gap-2 h-9 px-3 rounded-lg border bg-slate-50/80 dark:bg-slate-800/50 border-slate-200 dark:border-slate-600 cursor-text transition-all',
                        open && 'ring-2 ring-primary/20 border-primary/50',
                        disabled && 'opacity-50 cursor-not-allowed'
                    )}
                    onClick={() => { if (!disabled) { setOpen(true); setTimeout(() => inputRef.current?.focus(), 50) } }}
                    data-testid="facturas-filter-cliente-box"
                >
                    <User className="h-3.5 w-3.5 text-slate-400 shrink-0" />
                    {value && selectedLabel ? (
                        <span className="text-sm text-slate-900 dark:text-slate-100 truncate flex-1 max-w-[160px]">{selectedLabel}</span>
                    ) : (
                        <input
                            ref={inputRef}
                            value={query}
                            onChange={e => { setQuery(e.target.value); setOpen(true) }}
                            onFocus={() => setOpen(true)}
                            placeholder="Cliente…"
                            className="flex-1 bg-transparent outline-none text-sm placeholder:text-slate-400 min-w-0"
                            disabled={disabled}
                            data-testid="facturas-filter-cliente-input"
                        />
                    )}
                    {value ? (
                        <button type="button" onClick={handleClear} className="shrink-0 text-slate-400 hover:text-slate-600" data-testid="facturas-filter-cliente-clear">
                            <X className="h-3.5 w-3.5" />
                        </button>
                    ) : (
                        <ChevronDown className={cn('h-3.5 w-3.5 text-slate-400 shrink-0 transition-transform', open && 'rotate-180')} />
                    )}
                </div>
            </PopoverTrigger>
            <PopoverContent
                className="w-[var(--radix-popover-trigger-width)] min-w-[280px] max-w-[min(400px,90vw)] p-0"
                align="start"
                sideOffset={4}
                onOpenAutoFocus={(e) => e.preventDefault()}
            >
                <div className="flex flex-col max-h-[min(320px,70vh)] overflow-hidden">
                    {searching && <div className="px-3 py-2 text-xs text-slate-400">Cargando…</div>}
                    {!searching && query.length === 0 && result.items.length === 0 && <div className="px-3 py-2 text-xs text-slate-400">No hay clientes</div>}
                    {!searching && query.length > 0 && result.items.length === 0 && <div className="px-3 py-2 text-xs text-slate-400">Sin resultados</div>}
                    {result.items.length > 0 && (
                        <div className="overflow-y-auto flex-1">
                            {result.items.map(opt => (
                                <button key={opt.id} type="button" onMouseDown={() => handleSelect(opt)}
                                    className="w-full text-left px-3 py-2 text-sm hover:bg-slate-50 dark:hover:bg-slate-800 flex items-center justify-between gap-2"
                                    data-testid={`cliente-option-${opt.id}`}>
                                    <span className="truncate font-medium">{opt.label}</span>
                                    {opt.cif && <span className="text-xs text-slate-400 shrink-0">{opt.cif}</span>}
                                </button>
                            ))}
                        </div>
                    )}
                    {result.items.length > 0 && (
                        <div className="flex items-center justify-between px-3 py-1.5 border-t border-slate-100 dark:border-slate-700 bg-slate-50/80 shrink-0">
                            <span className="text-[11px] text-slate-400">{result.items.length} de {result.total}</span>
                            {hasMore && (
                                <button type="button" onMouseDown={(e) => { e.preventDefault(); fetchPage(query, result.page + 1, true) }}
                                    disabled={loadingMore} className="text-[11px] text-primary hover:underline font-medium disabled:opacity-50"
                                    data-testid="facturas-filter-cliente-ver-mas">
                                    {loadingMore ? 'Cargando…' : 'Ver más'}
                                </button>
                            )}
                        </div>
                    )}
                </div>
            </PopoverContent>
        </Popover>
    )
}

const DEBOUNCE_MS = 350
const currentYear = new Date().getFullYear()

const PERIODO_OPTIONS = [
    { value: 'todos', label: 'Todas las fechas' },
    { value: 'este-mes', label: 'Este mes' },
    { value: 'este-anio', label: 'Este año' },
    { value: 'rango', label: 'Rango personalizado' },
]

// Constantes eliminadas por no usarse: MESES, ANIOS

const ESTADOS: { value: string; label: string; color: string }[] = [
    { value: 'todas', label: 'Todos', color: '' },
    { value: 'borrador', label: 'Borrador', color: 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300' },
    { value: 'emitida', label: 'Emitida', color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' },
    { value: 'enviada', label: 'Enviada', color: 'bg-violet-100 text-violet-700 dark:bg-violet-900/30 dark:text-violet-300' },
    { value: 'pagada', label: 'Pagada', color: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' },
    { value: 'parcial', label: 'Parcial', color: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300' },
    { value: 'vencida', label: 'Vencida', color: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300' },
    { value: 'externa-emitida', label: 'Externa', color: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300' },
]

const PAGE_SIZE_OPTIONS = [
    { value: '10', label: '10' },
    { value: '25', label: '25' },
    { value: '50', label: '50' },
]

const ORDEN_OPTIONS = [
    { value: 'fecha_desc', label: 'Más reciente' },
    { value: 'fecha_asc', label: 'Más antiguo' },
    { value: 'numero_asc', label: 'Número 0001→9999' },
    { value: 'numero_desc', label: 'Número 9999→0001' },
    { value: 'cliente_asc', label: 'Cliente A→Z' },
    { value: 'cliente_desc', label: 'Cliente Z→A' },
    { value: 'fecha_vencimiento_asc', label: 'Vencimiento más próximo' },
    { value: 'fecha_vencimiento_desc', label: 'Vencimiento más lejano' },
    { value: 'total_desc', label: 'Mayor importe' },
    { value: 'total_asc', label: 'Menor importe' },
    { value: 'estado_asc', label: 'Estado A→Z' },
    { value: 'estado_desc', label: 'Estado Z→A' },
]

function getPeriodoFromParams(params: URLSearchParams): { periodo: string; desde: string; hasta: string } {
    const desde = params.get('desde')
    const hasta = params.get('hasta')
    const mes = params.get('mes')
    const anio = params.get('anio')
    if (desde && hasta) return { periodo: 'rango', desde, hasta }
    if (mes && anio) {
        const m = parseInt(mes, 10)
        const a = parseInt(anio, 10)
        const hoy = new Date()
        if (m === hoy.getMonth() + 1 && a === hoy.getFullYear()) return { periodo: 'este-mes', desde: '', hasta: '' }
        const d = `${a}-${String(m).padStart(2, '0')}-01`
        const lastDay = new Date(a, m, 0).getDate()
        const h = `${a}-${String(m).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`
        return { periodo: 'rango', desde: d, hasta: h }
    }
    if (anio && !mes) {
        if (parseInt(anio, 10) === currentYear) return { periodo: 'este-anio', desde: '', hasta: '' }
        return { periodo: 'rango', desde: `${anio}-01-01`, hasta: `${anio}-12-31` }
    }
    return { periodo: 'todos', desde: '', hasta: '' }
}

interface FacturasFiltersProps {
    series?: Array<{ id: string; codigo: string; nombre: string }>
    pageSize?: number
}

export function FacturasFilters({ series = [], pageSize: initialPageSize = 10 }: FacturasFiltersProps) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const [isPending, startTransition] = useTransition()

    const [busqueda, setBusqueda] = useState(searchParams.get('q') || '')
    const [estado, setEstado] = useState(searchParams.get('estado') || 'todas')
    const [periodo, setPeriodo] = useState(() => getPeriodoFromParams(searchParams).periodo)
    const [customDesde, setCustomDesde] = useState(() => getPeriodoFromParams(searchParams).desde)
    const [customHasta, setCustomHasta] = useState(() => getPeriodoFromParams(searchParams).hasta)
    const [orden, setOrden] = useState(searchParams.get('orden') || 'fecha_desc')
    const [clienteId, setClienteId] = useState(searchParams.get('clienteId') || '')
    const [clienteLabel, setClienteLabel] = useState(searchParams.get('clienteLabel') || '')
    const [serieId, setSerieId] = useState(searchParams.get('serie') || '')
    const [pageSize, setPageSize] = useState(searchParams.get('pageSize') || String(initialPageSize))
    const [periodoOpen, setPeriodoOpen] = useState(false)

    // Sincronizar estado local con la URL de forma eficiente
    useEffect(() => {
        const q = searchParams.get('q') || ''
        const est = searchParams.get('estado') || 'todas'
        const ord = searchParams.get('orden') || 'fecha_desc'
        const cId = searchParams.get('clienteId') || ''
        const cLab = searchParams.get('clienteLabel') || ''
        const sId = searchParams.get('serie') || ''
        const pSize = searchParams.get('pageSize') || String(initialPageSize)
        const { periodo: p, desde: d, hasta: h } = getPeriodoFromParams(searchParams)

        if (busqueda !== q) setBusqueda(q)
        if (estado !== est) setEstado(est)
        if (orden !== ord) setOrden(ord)
        if (clienteId !== cId) setClienteId(cId)
        if (clienteLabel !== cLab) setClienteLabel(cLab)
        if (serieId !== sId) setSerieId(sId)
        if (pageSize !== pSize) setPageSize(pSize)
        if (periodo !== p) setPeriodo(p)
        if (customDesde !== d) setCustomDesde(d)
        if (customHasta !== h) setCustomHasta(h)
    }, [searchParams, initialPageSize]) // Eliminados estados locales de las dependencias para evitar bucles

    const applySearch = useCallback((q: string) => {
        const trimmed = q.trim()
        const params = new URLSearchParams(searchParams.toString())
        if ((params.get('q') || '') === trimmed) return
        if (trimmed) params.set('q', trimmed)
        else params.delete('q')
        params.delete('page')
        router.push(`/ventas/facturas?${params.toString()}`)
        router.refresh()
    }, [searchParams, router])

    useEffect(() => {
        const t = setTimeout(() => applySearch(busqueda), DEBOUNCE_MS)
        return () => clearTimeout(t)
    }, [busqueda, applySearch])

    const applyPeriodo = useCallback((p: string, d?: string, h?: string) => {
        const params = new URLSearchParams(searchParams.toString())
        params.delete('mes')
        params.delete('anio')
        params.delete('desde')
        params.delete('hasta')
        params.delete('page')

        if (p === 'todos') {
            // Sin filtro de fecha
        } else if (p === 'este-mes') {
            const hoy = new Date()
            params.set('mes', String(hoy.getMonth() + 1))
            params.set('anio', String(hoy.getFullYear()))
        } else if (p === 'este-anio') {
            params.set('anio', String(currentYear))
        } else if (p === 'rango' && d && h && d <= h) {
            params.set('desde', d)
            params.set('hasta', h)
        }

        const queryString = params.toString()
        startTransition(() => {
            router.push(`/ventas/facturas?${queryString}`)
            router.refresh()
        })
        setPeriodoOpen(false)
    }, [searchParams, router])

    const handlePeriodoPill = (p: string) => {
        setPeriodo(p)
        if (p === 'rango') {
            setPeriodoOpen(true)
            return
        }
        applyPeriodo(p)
    }

    const handleApplyRango = () => {
        if (customDesde && customHasta && customDesde <= customHasta) {
            setPeriodo('rango')
            applyPeriodo('rango', customDesde, customHasta)
        }
    }

    const handleEstado = (value: string) => {
        setEstado(value)
        const params = new URLSearchParams(searchParams.toString())
        if (value !== 'todas') params.set('estado', value)
        else params.delete('estado')
        params.delete('page')
        startTransition(() => { router.push(`/ventas/facturas?${params.toString()}`); router.refresh() })
    }

    const handleOrden = (value: string) => {
        setOrden(value)
        const params = new URLSearchParams(searchParams.toString())
        if (value !== 'fecha_desc') params.set('orden', value)
        else params.delete('orden')
        params.delete('page')
        startTransition(() => { router.push(`/ventas/facturas?${params.toString()}`); router.refresh() })
    }

    const handleClienteChange = (id: string, label: string) => {
        setClienteId(id)
        setClienteLabel(label)
        const params = new URLSearchParams(searchParams.toString())
        if (id) { params.set('clienteId', id); params.set('clienteLabel', label) }
        else { params.delete('clienteId'); params.delete('clienteLabel') }
        params.delete('page')
        startTransition(() => { router.push(`/ventas/facturas?${params.toString()}`); router.refresh() })
    }

    const handleSerieChange = (value: string) => {
        const id = value === '__todas__' ? '' : value
        setSerieId(id)
        const params = new URLSearchParams(searchParams.toString())
        if (id) params.set('serie', id)
        else params.delete('serie')
        params.delete('page')
        startTransition(() => { router.push(`/ventas/facturas?${params.toString()}`); router.refresh() })
    }

    const handlePageSizeChange = (value: string) => {
        setPageSize(value)
        const params = new URLSearchParams(searchParams.toString())
        params.set('pageSize', value)
        params.set('page', '1')
        startTransition(() => { router.push(`/ventas/facturas?${params.toString()}`); router.refresh() })
    }

    const handleLimpiar = () => {
        setBusqueda('')
        setEstado('todas')
        setPeriodo('todos')
        setCustomDesde('')
        setCustomHasta('')
        setOrden('fecha_desc')
        setClienteId('')
        setClienteLabel('')
        setSerieId('')
        startTransition(() => { router.push('/ventas/facturas'); router.refresh() })
    }

    const tieneFiltrosActivos =
        !!busqueda.trim() || estado !== 'todas' || periodo !== 'todos' || orden !== 'fecha_desc' || !!clienteId || !!serieId

    const periodoLabel =
        periodo === 'todos' ? 'Todas las fechas' :
            periodo === 'este-mes' ? 'Este mes' :
                periodo === 'este-anio' ? 'Este año' :
                    customDesde && customHasta ? `${customDesde} – ${customHasta}` : 'Rango personalizado'

    const estadoActual = ESTADOS.find(e => e.value === estado)
    const ordenActual = ORDEN_OPTIONS.find(o => o.value === orden)

    return (
        <Card data-testid="facturas-filters" className="border-slate-200 dark:border-slate-700/50 bg-white dark:bg-slate-900/80 shadow-md overflow-hidden">
            <CardContent className="p-5">
                <div className="flex flex-col gap-5">
                    {/* Búsqueda */}
                    <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:gap-4">
                        <div className="relative flex-1 min-w-0" role="search">
                            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
                            <Input
                                id="facturas-search"
                                data-testid="facturas-filter-search"
                                placeholder="Buscar por cliente, CIF, número o importe…"
                                value={busqueda}
                                onChange={e => setBusqueda(e.target.value)}
                                className="pl-10 h-10 rounded-lg bg-slate-50/80 dark:bg-slate-800/50 border-slate-200 dark:border-slate-600"
                                disabled={isPending}
                            />
                            {busqueda && (
                                <button type="button" onClick={() => setBusqueda('')}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                                    <X className="h-4 w-4" />
                                </button>
                            )}
                        </div>
                        {tieneFiltrosActivos && (
                            <Button variant="ghost" size="sm" onClick={handleLimpiar} disabled={isPending}
                                className="text-slate-600 hover:text-slate-900 dark:text-slate-400"
                                data-testid="facturas-filter-limpiar">
                                <X className="h-4 w-4 mr-1.5" />
                                Limpiar
                            </Button>
                        )}
                    </div>

                    {/* Período: pills + rango */}
                    <div className="space-y-3">
                        <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400">
                            <Calendar className="h-3.5 w-3.5" />
                            <span className="text-xs font-semibold uppercase tracking-wide">Período</span>
                        </div>
                        <div className="flex flex-wrap items-center gap-2">
                            {PERIODO_OPTIONS.map(p => {
                                const isActive = periodo === p.value
                                return (
                                    <Button
                                        key={p.value}
                                        type="button"
                                        variant={isActive ? 'default' : 'outline'}
                                        size="sm"
                                        onClick={() => handlePeriodoPill(p.value)}
                                        disabled={isPending}
                                        className={cn(
                                            'h-8 rounded-lg text-xs font-medium transition-all',
                                            isActive && 'ring-2 ring-primary/30 shadow-sm'
                                        )}
                                        data-testid={`facturas-filter-periodo-${p.value}`}
                                    >
                                        {isActive && <Check className="h-3 w-3 mr-1" />}
                                        {p.label}
                                    </Button>
                                )
                            })}
                            {periodo === 'rango' && (
                                <Popover open={periodoOpen} onOpenChange={setPeriodoOpen}>
                                    <PopoverTrigger asChild>
                                        <Button variant="outline" size="sm" className="h-8 rounded-lg text-xs"
                                            data-testid="facturas-filter-rango-trigger">
                                            {customDesde && customHasta ? `${customDesde} – ${customHasta}` : 'Elegir fechas'}
                                        </Button>
                                    </PopoverTrigger>
                                    <PopoverContent className="w-80 p-4" align="start">
                                        <div className="grid grid-cols-2 gap-3">
                                            <div>
                                                <Label className="text-xs">Desde</Label>
                                                <Input type="date" value={customDesde} onChange={e => setCustomDesde(e.target.value)} className="mt-1" />
                                            </div>
                                            <div>
                                                <Label className="text-xs">Hasta</Label>
                                                <Input type="date" value={customHasta} onChange={e => setCustomHasta(e.target.value)} className="mt-1" />
                                            </div>
                                            <Button className="col-span-2" onClick={handleApplyRango}
                                                disabled={!customDesde || !customHasta || customDesde > customHasta}
                                                data-testid="facturas-filter-rango-aplicar">
                                                Aplicar rango
                                            </Button>
                                        </div>
                                    </PopoverContent>
                                </Popover>
                            )}
                        </div>
                        <p className="text-[11px] text-slate-400">
                            {periodo === 'todos' ? 'Mostrando todas las facturas sin filtro de fecha' : `Período: ${periodoLabel}`}
                        </p>
                    </div>

                    {/* Estado + Cliente + Orden */}
                    <div className="flex flex-col gap-4 border-t border-slate-200 dark:border-slate-700 pt-4">
                        <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400">
                            <SlidersHorizontal className="h-3.5 w-3.5" />
                            <span className="text-xs font-semibold uppercase tracking-wide">Estado, cliente y orden</span>
                        </div>
                        <div className="flex flex-wrap gap-2" role="group">
                            {ESTADOS.map(e => {
                                const isActive = estado === e.value
                                return (
                                    <button
                                        key={e.value}
                                        type="button"
                                        disabled={isPending}
                                        onClick={() => handleEstado(e.value)}
                                        className={cn(
                                            'px-3 py-1.5 rounded-lg text-xs font-medium border transition-all',
                                            isActive ? cn(e.color || 'bg-slate-800 text-white dark:bg-slate-200 dark:text-slate-900', 'border-transparent shadow-sm') : 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-600 hover:border-slate-300'
                                        )}
                                        data-testid={`facturas-filter-estado-${e.value}`}
                                    >
                                        {e.label}
                                    </button>
                                )
                            })}
                        </div>
                        <div className="flex flex-wrap items-end gap-4">
                            <div className="space-y-1.5">
                                <Label className="text-xs text-slate-500">Cliente</Label>
                                <ClienteCombobox value={clienteId} label={clienteLabel} onChange={handleClienteChange} disabled={isPending} />
                            </div>
                            {series.length > 0 && (
                                <div className="space-y-1.5">
                                    <Label className="text-xs text-slate-500">Serie</Label>
                                    <Select value={serieId || '__todas__'} onValueChange={handleSerieChange} disabled={isPending}>
                                        <SelectTrigger data-testid="facturas-filter-serie" className="w-[140px] h-9 rounded-lg">
                                            <SelectValue placeholder="Todas" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="__todas__">Todas</SelectItem>
                                            {series.map(s => (
                                                <SelectItem key={s.id} value={s.id}>{s.codigo}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            )}
                            <div className="space-y-1.5">
                                <Label className="text-xs text-slate-500">Ordenar</Label>
                                <Select value={orden} onValueChange={handleOrden} disabled={isPending}>
                                    <SelectTrigger data-testid="facturas-filter-orden" className="w-[180px] h-9 rounded-lg">
                                        <ArrowUpDown className="h-3.5 w-3.5 mr-2 text-slate-400" />
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {ORDEN_OPTIONS.map(o => (
                                            <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-1.5">
                                <Label className="text-xs text-slate-500">Por página</Label>
                                <Select value={pageSize} onValueChange={handlePageSizeChange} disabled={isPending}>
                                    <SelectTrigger data-testid="facturas-filter-page-size" className="w-[80px] h-9 rounded-lg">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {PAGE_SIZE_OPTIONS.map(o => (
                                            <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                            {tieneFiltrosActivos && (
                                <div className="ml-auto flex items-center gap-2 flex-wrap">
                                    {clienteId && clienteLabel && (
                                        <Badge variant="outline" className="text-xs bg-violet-50 text-violet-700 dark:bg-violet-900/30 border-violet-200">
                                            <User className="h-3 w-3 mr-1" />
                                            {clienteLabel}
                                            <button type="button" onClick={() => handleClienteChange('', '')} className="ml-1 hover:text-violet-900">
                                                <X className="h-3 w-3" />
                                            </button>
                                        </Badge>
                                    )}
                                    <Badge variant="secondary" className="text-xs bg-primary/10 text-primary" data-testid="facturas-filters-active-badge">
                                        Filtros activos
                                    </Badge>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </CardContent>
        </Card>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { format } from 'date-fns'
import { es } from 'date-fns/locale'
import { MoreVertical, Eye, Edit, Trash, FileWarning, Download, Mail, ChevronDown, FileSpreadsheet } from 'lucide-react'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table'
import { formatFacturaDisplayNumero, cn } from '@/lib/utils'
import { FacturaWithCliente } from '@/types/ventas'
import { eliminarFacturaAction } from '@/app/actions/ventas'
import { toast } from 'sonner'

interface FacturasTableProps {
    facturas: FacturaWithCliente[]
    totalCount: number
    currentPage: number
    pageSize: number
    searchQuery?: string
    enviadaIds?: string[]
}

/** Resalta las coincidencias del término de búsqueda en el texto (case-insensitive).
 * Solo aplica resaltado tras montar en cliente para evitar errores de hidratación. */
function HighlightedText({ text, query }: { text: string; query?: string }) {
    const [mounted, setMounted] = useState(false)
    useEffect(() => setMounted(true), [])

    if (!mounted || !query?.trim() || !text) return <>{text}</>

    const q = query.trim()
    const regex = new RegExp(`(${q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi')
    const parts = text.split(regex)
    return (
        <>
            {parts.map((part, i) =>
                i % 2 === 1 ? (
                    <mark key={i} className="bg-amber-200 dark:bg-amber-600/50 text-amber-900 dark:text-amber-100 rounded px-0.5 font-medium">
                        {part}
                    </mark>
                ) : (
                    part
                )
            )}
        </>
    )
}

type SortColumn = 'numero' | 'cliente' | 'fecha_emision' | 'fecha_vencimiento' | 'total' | 'estado'
const SORT_MAP: Record<SortColumn, { asc: string; desc: string }> = {
    numero: { asc: 'numero_asc', desc: 'numero_desc' },
    cliente: { asc: 'cliente_asc', desc: 'cliente_desc' },
    fecha_emision: { asc: 'fecha_asc', desc: 'fecha_desc' },
    fecha_vencimiento: { asc: 'fecha_vencimiento_asc', desc: 'fecha_vencimiento_desc' },
    total: { asc: 'total_asc', desc: 'total_desc' },
    estado: { asc: 'estado_asc', desc: 'estado_desc' },
}

export function FacturasTable({
    facturas,
    totalCount,
    currentPage,
    pageSize,
    searchQuery,
    enviadaIds = [],
}: FacturasTableProps) {
    const router = useRouter()
    const searchParams = useSearchParams()
    const currentOrden = searchParams.get('orden') || 'fecha_desc'
    const [deleteTarget, setDeleteTarget] = useState<{ id: string; label: string } | null>(null)
    const [isDeleting, setIsDeleting] = useState(false)
    const [exportingAll, setExportingAll] = useState(false)

    const formatCurrency = (amount: number, currency: string = 'EUR') => {
        return new Intl.NumberFormat('es-ES', {
            style: 'currency',
            currency: currency,
        }).format(amount)
    }

    const formatDate = (dateStr: string) => {
        if (!dateStr) return '-'
        return format(new Date(dateStr), 'dd MMM, yyyy', { locale: es })
    }

    const getEstadoBadge = (factura: FacturaWithCliente) => {
        const estado = factura.estado
        const esExterna = !!(factura as any).es_externa
        const esEnviada = enviadaIds.includes(factura.id)

        const variants: Record<string, { label: string; className: string }> = {
            pagada: {
                label: 'Pagada',
                className: 'bg-green-100 text-green-700 dark:bg-green-900/50 dark:text-green-300 border-green-200 dark:border-green-800',
            },
            parcial: {
                label: 'Parcial',
                className: 'bg-orange-100 text-orange-700 dark:bg-orange-900/50 dark:text-orange-300 border-orange-200 dark:border-orange-800',
            },
            emitida: {
                label: 'Emitida',
                className: 'bg-blue-100 text-blue-700 dark:bg-blue-900/50 dark:text-blue-300 border-blue-200 dark:border-blue-800',
            },
            vencida: {
                label: 'Vencida',
                className: 'bg-red-100 text-red-700 dark:bg-red-900/50 dark:text-red-300 border-red-200 dark:border-red-800',
            },
            borrador: {
                label: 'Borrador',
                className: 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300 border-slate-200 dark:border-slate-700',
            },
            anulada: {
                label: 'Anulada',
                className: 'bg-orange-100 text-orange-700 dark:bg-orange-900/50 dark:text-orange-300 border-orange-200 dark:border-orange-800',
            },
        }

        // Externa: siempre mostrar "Externa" (coincide con filtro)
        if (esExterna) {
            if (estado === 'borrador' && !(factura as any).archivo_url) {
                return (
                    <Badge className="bg-amber-100 text-amber-700 dark:bg-amber-900/50 dark:text-amber-300 border-amber-200 dark:border-amber-800 px-2.5 py-1 font-medium text-xs whitespace-nowrap max-w-full truncate" variant="outline" title="Externa (Pendiente PDF)">
                        Externa (Pend. PDF)
                    </Badge>
                )
            }
            const sub = estado === 'pagada' ? ' - Pagada' : estado === 'emitida' ? ' - Emitida' : ''
            return (
                <Badge className="bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-300 border-orange-200 dark:border-orange-800 px-2.5 py-1 font-medium text-xs whitespace-nowrap max-w-full truncate" variant="outline" title={`Externa${sub}`}>
                    Externa{sub}
                </Badge>
            )
        }

        // Enviada: factura enviada por email (coincide con filtro)
        if (esEnviada) {
            return (
                <Badge className="bg-violet-100 text-violet-700 dark:bg-violet-900/30 dark:text-violet-300 border-violet-200 dark:border-violet-800 px-3 py-1 font-medium" variant="outline">
                    Enviada
                </Badge>
            )
        }

        const variant = variants[estado] || variants.borrador
        return (
            <Badge className={`border ${variant.className} px-3 py-1 font-medium capitalize`} variant="outline">
                {variant.label}
            </Badge>
        )
    }

    const totalPages = Math.ceil(totalCount / pageSize)

    const handlePageChange = (page: number) => {
        const params = new URLSearchParams(window.location.search)
        params.set('page', page.toString())
        router.push(`/ventas/facturas?${params.toString()}`)
    }

    const handleDelete = async () => {
        if (!deleteTarget) return
        setIsDeleting(true)
        try {
            const result = await eliminarFacturaAction(deleteTarget.id)
            if (result.success) {
                toast.success('Factura eliminada con éxito')
                router.refresh()
            } else {
                toast.error(result.error || 'Error al eliminar la factura')
            }
        } catch {
            toast.error('Error inesperado al eliminar la factura')
        } finally {
            setIsDeleting(false)
            setDeleteTarget(null)
        }
    }

    const exportCsvPage = () => {
        const headers = ['Número', 'Serie', 'Cliente', 'CIF', 'Fecha Emisión', 'Fecha Vencimiento', 'Base Imponible', 'IVA', 'Descuento', 'Retención', 'Total', 'Estado', 'Externa', 'Empresa']
        const rows = facturas.map((f) => [
            formatFacturaDisplayNumero(f.serie, f.numero),
            f.serie || '',
            f.cliente?.nombre_comercial || f.cliente?.nombre_fiscal || '',
            f.cliente?.cif || '',
            f.fecha_emision || '',
            f.fecha_vencimiento || '',
            String((f as any).base_imponible ?? ''),
            String((f as any).cuota_iva ?? ''),
            String((f as any).descuento ?? ''),
            String((f as any).retencion_irpf ?? ''),
            String(f.total),
            f.estado,
            (f as any).es_externa ? 'Sí' : 'No',
            (f as any).empresa?.nombre_comercial ?? '',
        ])
        const csv = [headers.join(';'), ...rows.map((r) => r.map((c) => `"${String(c).replace(/"/g, '""')}"`).join(';'))].join('\n')
        const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8' })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = `facturas-pagina-${new Date().toISOString().slice(0, 10)}.csv`
        a.style.display = 'none'
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        URL.revokeObjectURL(url)
    }

    const buildExportUrl = (format: 'xlsx' | 'csv') => {
        const params = new URLSearchParams(searchParams.toString())
        params.set('format', format)
        params.delete('page')
        params.delete('pageSize')
        return `/api/ventas/facturas/export?${params.toString()}`
    }

    const handleExportAll = (format: 'xlsx' | 'csv') => {
        setExportingAll(true)
        const url = buildExportUrl(format)
        const a = document.createElement('a')
        a.href = url
        a.download = `facturas-${new Date().toISOString().slice(0, 10)}.${format}`
        a.style.display = 'none'
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        setExportingAll(false)
    }

    const handleSort = (col: SortColumn) => {
        const { asc, desc } = SORT_MAP[col]
        const nextOrden = currentOrden === asc ? desc : asc
        const params = new URLSearchParams(searchParams.toString())
        params.set('orden', nextOrden)
        params.delete('page')
        router.push(`/ventas/facturas?${params.toString()}`)
    }

    const getSortIndicator = (col: SortColumn) => {
        const { asc, desc } = SORT_MAP[col]
        if (currentOrden === asc) return ' ↑'
        if (currentOrden === desc) return ' ↓'
        return ''
    }

    const isVencida = (fechaVenc: string | null) => {
        if (!fechaVenc) return false
        return new Date(fechaVenc) < new Date(new Date().setHours(0, 0, 0, 0))
    }

    if (facturas.length === 0) {
        return (
            <Card className="border-white/20 bg-white/70 backdrop-blur-xl dark:border-white/10 dark:bg-slate-900/60">
                <CardContent className="p-12 text-center">
                    <p className="text-slate-600 dark:text-slate-400 font-medium">No se encontraron facturas</p>
                    <p className="text-sm text-slate-500 mt-2">Prueba a cambiar los filtros o crea tu primera factura</p>
                    <Button asChild className="mt-4" variant="outline">
                        <a href="/ventas/facturas/nueva">Nueva factura</a>
                    </Button>
                </CardContent>
            </Card>
        )
    }

    return (
        <>
            <Card className="border-white/20 bg-white/70 backdrop-blur-xl dark:border-white/10 dark:bg-slate-900/60 overflow-hidden">
                <CardContent className="p-0">
                    <div className="flex items-center justify-end gap-2 px-4 py-2 border-b border-slate-200 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/30">
                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="outline" size="sm" disabled={exportingAll} className="text-xs" data-testid="facturas-export-trigger">
                                    <Download className="h-3.5 w-3.5 mr-1.5" />
                                    Exportar
                                    <ChevronDown className="h-3.5 w-3.5 ml-1" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                                <DropdownMenuItem onClick={exportCsvPage} data-testid="facturas-export-pagina">
                                    <Download className="h-4 w-4 mr-2" />
                                    Exportar página actual (CSV)
                                </DropdownMenuItem>
                                <DropdownMenuSeparator />
                                <DropdownMenuItem onClick={() => handleExportAll('xlsx')} data-testid="facturas-export-todas-xlsx">
                                    <FileSpreadsheet className="h-4 w-4 mr-2" />
                                    Exportar todas filtradas (Excel)
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={() => handleExportAll('csv')} data-testid="facturas-export-todas-csv">
                                    <Download className="h-4 w-4 mr-2" />
                                    Exportar todas filtradas (CSV)
                                </DropdownMenuItem>
                            </DropdownMenuContent>
                        </DropdownMenu>
                    </div>
                    <div className="overflow-x-auto">
                        <Table className="table-fixed w-full">
                            <TableHeader className="bg-slate-50/50 dark:bg-slate-800/50">
                                <TableRow>
                                    <TableHead
                                        className="font-semibold text-slate-600 dark:text-slate-400 w-[120px] min-w-[100px] cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('numero') }}
                                        aria-sort={currentOrden.startsWith('numero') ? (currentOrden === 'numero_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-numero"
                                    >
                                        Número{getSortIndicator('numero')}
                                    </TableHead>
                                    <TableHead
                                        className="font-semibold text-slate-600 dark:text-slate-400 min-w-0 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('cliente') }}
                                        aria-sort={currentOrden.startsWith('cliente') ? (currentOrden === 'cliente_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-cliente"
                                    >
                                        Cliente{getSortIndicator('cliente')}
                                    </TableHead>
                                    <TableHead
                                        className="font-semibold text-slate-600 dark:text-slate-400 w-[115px] hidden md:table-cell cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('fecha_emision') }}
                                        aria-sort={currentOrden.startsWith('fecha') && !currentOrden.includes('vencimiento') ? (currentOrden === 'fecha_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-fecha-emision"
                                    >
                                        Fecha Emisión{getSortIndicator('fecha_emision')}
                                    </TableHead>
                                    <TableHead
                                        className="font-semibold text-slate-600 dark:text-slate-400 w-[125px] hidden lg:table-cell cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('fecha_vencimiento') }}
                                        aria-sort={currentOrden.startsWith('fecha_vencimiento') ? (currentOrden === 'fecha_vencimiento_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-fecha-vencimiento"
                                    >
                                        Fecha Venc.{getSortIndicator('fecha_vencimiento')}
                                    </TableHead>
                                    <TableHead
                                        className="text-right font-semibold text-slate-600 dark:text-slate-400 w-[100px] pr-2 md:pr-5 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('total') }}
                                        aria-sort={currentOrden.startsWith('total') ? (currentOrden === 'total_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-total"
                                    >
                                        Total{getSortIndicator('total')}
                                    </TableHead>
                                    <TableHead
                                        className="font-semibold text-slate-600 dark:text-slate-400 w-[140px] min-w-[120px] pl-2 md:pl-5 cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-800/80 select-none"
                                        onClick={(e) => { e.stopPropagation(); handleSort('estado') }}
                                        aria-sort={currentOrden.startsWith('estado') ? (currentOrden === 'estado_asc' ? 'ascending' : 'descending') : undefined}
                                        data-testid="facturas-th-estado"
                                    >
                                        Estado{getSortIndicator('estado')}
                                    </TableHead>
                                    <TableHead className="w-[48px] md:w-[56px]"></TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {facturas.map((factura) => (
                                    <TableRow
                                        key={factura.id}
                                        data-testid="factura-row"
                                        className="cursor-pointer hover:bg-slate-50/80 dark:hover:bg-slate-800/50 transition-colors"
                                        onClick={() => router.push(`/ventas/facturas/${factura.id}`)}
                                    >
                                        <TableCell className="font-mono font-medium text-slate-700 dark:text-slate-300">
                                            <div className="flex items-center gap-2">
                                                <HighlightedText
                                                    text={formatFacturaDisplayNumero(factura.serie, factura.numero)}
                                                    query={searchQuery}
                                                />
                                                {factura.es_externa && (
                                                    <div className="flex gap-1" title="Factura Externa">
                                                        <Badge variant="secondary" className="h-5 px-1 text-[10px] bg-blue-50 text-blue-700 border-blue-100">EXT</Badge>
                                                        {!factura.archivo_url && (
                                                            <span title="Pendiente de PDF" className="flex items-center text-amber-600">
                                                                <FileWarning className="h-4 w-4" />
                                                            </span>
                                                        )}
                                                    </div>
                                                )}
                                            </div>
                                        </TableCell>
                                        <TableCell className="w-[200px] max-w-[200px] min-w-0 overflow-hidden !whitespace-normal">
                                            <div className="flex flex-col min-w-0 overflow-hidden w-full">
                                                <span className="font-medium text-slate-900 dark:text-slate-100 truncate" title={factura.cliente?.nombre_comercial || factura.cliente?.nombre_fiscal || 'Cliente Desconocido'}>
                                                    <HighlightedText
                                                        text={factura.cliente?.nombre_comercial || factura.cliente?.nombre_fiscal || 'Cliente Desconocido'}
                                                        query={searchQuery}
                                                    />
                                                </span>
                                                <span className="text-xs text-slate-500 dark:text-slate-400 truncate" title={factura.cliente?.cif || '-'}>
                                                    <HighlightedText
                                                        text={factura.cliente?.cif || '-'}
                                                        query={searchQuery}
                                                    />
                                                </span>
                                            </div>
                                        </TableCell>
                                        <TableCell className="text-slate-600 dark:text-slate-400 hidden md:table-cell">
                                            <span suppressHydrationWarning>{formatDate(factura.fecha_emision)}</span>
                                        </TableCell>
                                        <TableCell className={cn('w-[125px] hidden lg:table-cell', isVencida(factura.fecha_vencimiento) && factura.estado !== 'pagada' && factura.estado !== 'anulada' && 'text-red-600 dark:text-red-400 font-medium')}>
                                            <span suppressHydrationWarning>{formatDate(factura.fecha_vencimiento)}</span>
                                            {isVencida(factura.fecha_vencimiento) && factura.estado !== 'pagada' && factura.estado !== 'anulada' && (
                                                <span className="ml-1 text-[10px] text-red-600 dark:text-red-400" title="Vencida">⚠</span>
                                            )}
                                        </TableCell>
                                        <TableCell className="text-right font-bold text-slate-900 dark:text-slate-100 pr-2 md:pr-5">
                                            <span suppressHydrationWarning>
                                                <HighlightedText
                                                    text={formatCurrency(factura.total, factura.divisa || undefined)}
                                                    query={searchQuery}
                                                />
                                            </span>
                                        </TableCell>
                                        <TableCell className="pl-2 md:pl-5 min-w-0 overflow-hidden pr-2">
                                            <div className="max-w-full min-w-0 overflow-hidden">
                                                {getEstadoBadge(factura)}
                                            </div>
                                        </TableCell>
                                        <TableCell onClick={(e) => e.stopPropagation()} className="w-[48px] md:w-[120px]">
                                            <div className="flex items-center gap-0.5">
                                                <Button variant="ghost" size="icon" className="h-7 w-7 text-slate-500 hover:text-primary" onClick={(e) => { e.stopPropagation(); router.push(`/ventas/facturas/${factura.id}`) }} title="Ver">
                                                    <Eye className="h-3.5 w-3.5" />
                                                </Button>
                                                <Button variant="ghost" size="icon" className="h-7 w-7 text-slate-500 hover:text-primary" onClick={(e) => { e.stopPropagation(); router.push(`/ventas/facturas/${factura.id}/pdf`) }} title="Descargar PDF">
                                                    <Download className="h-3.5 w-3.5" />
                                                </Button>
                                                <Button variant="ghost" size="icon" className="h-7 w-7 text-slate-500 hover:text-primary" onClick={(e) => { e.stopPropagation(); router.push(`/ventas/facturas/${factura.id}/email`) }} title="Enviar email">
                                                    <Mail className="h-3.5 w-3.5" />
                                                </Button>
                                                <DropdownMenu>
                                                    <DropdownMenuTrigger asChild>
                                                        <Button variant="ghost" size="icon" className="h-7 w-7 text-slate-500 hover:text-primary">
                                                            <MoreVertical className="h-3.5 w-3.5" />
                                                        </Button>
                                                    </DropdownMenuTrigger>
                                                    <DropdownMenuContent align="end" className="bg-white/90 backdrop-blur-xl dark:bg-slate-900/90 border-slate-200 dark:border-slate-800">
                                                        <DropdownMenuItem onClick={() => router.push(`/ventas/facturas/${factura.id}/editar`)} className="cursor-pointer">
                                                            <Edit className="h-4 w-4 mr-2" />
                                                            Editar
                                                        </DropdownMenuItem>
                                                        <DropdownMenuItem className="text-red-600 focus:text-red-600 cursor-pointer" onClick={() => setDeleteTarget({ id: factura.id, label: formatFacturaDisplayNumero(factura.serie, factura.numero) || factura.id })}>
                                                            <Trash className="h-4 w-4 mr-2" />
                                                            Eliminar
                                                        </DropdownMenuItem>
                                                    </DropdownMenuContent>
                                                </DropdownMenu>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </div>

                    {/* Paginación */}
                    <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-3 border-t border-slate-200 dark:border-slate-800 px-4 sm:px-6 py-4 bg-slate-50/50 dark:bg-slate-900/30">
                        <p className="text-xs sm:text-sm text-slate-500 dark:text-slate-400 order-2 sm:order-1">
                            Mostrando <span className="font-medium text-slate-900 dark:text-slate-100">{(currentPage - 1) * pageSize + 1}</span>-
                            <span className="font-medium text-slate-900 dark:text-slate-100">{Math.min(currentPage * pageSize, totalCount)}</span> de <span className="font-medium text-slate-900 dark:text-slate-100">{totalCount}</span> facturas
                        </p>
                        <div className="flex flex-wrap items-center justify-center sm:justify-end gap-2 order-1 sm:order-2">
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => handlePageChange(currentPage - 1)}
                                disabled={currentPage === 1}
                                className="bg-white/50 hover:bg-white dark:bg-slate-800/50 dark:hover:bg-slate-800"
                            >
                                Anterior
                            </Button>
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                const page = i + 1
                                return (
                                    <Button
                                        key={page}
                                        variant={page === currentPage ? 'default' : 'outline'}
                                        size="sm"
                                        onClick={() => handlePageChange(page)}
                                        className={page === currentPage ? 'bg-primary text-primary-foreground' : 'bg-white/50 hover:bg-white dark:bg-slate-800/50 dark:hover:bg-slate-800'}
                                    >
                                        {page}
                                    </Button>
                                )}
                            )}
                            {totalPages > 5 && <span className="text-slate-400">...</span>}
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => handlePageChange(currentPage + 1)}
                                disabled={currentPage === totalPages}
                                className="bg-white/50 hover:bg-white dark:bg-slate-800/50 dark:hover:bg-slate-800"
                            >
                                Siguiente
                            </Button>
                        </div>
                    </div>
                </CardContent>
            </Card>

            {/* Delete Confirmation Dialog */}
            <AlertDialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>¿Estás seguro?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Esta acción eliminará permanentemente la factura <strong>{deleteTarget?.label}</strong> y todas sus líneas asociadas. Esta acción no se puede deshacer.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel disabled={isDeleting}>Cancelar</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleDelete}
                            disabled={isDeleting}
                            className="bg-red-600 text-white hover:bg-red-700 focus:ring-red-600"
                        >
                            {isDeleting ? 'Eliminando...' : 'Eliminar Factura'}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { toast } from 'sonner'
import { Plus, Trash2, Loader2, Percent, Building2, FileText, Upload } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'

import { guardarBorradorAction, crearFacturaAction, obtenerProximoNumeroPreviewAction } from '@/app/actions/ventas'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Separator } from '@/components/ui/separator'
import { EmpresaSelector } from '@/components/empresa-selector'
import { PlantillaSelector } from '@/components/plantilla-selector'
import { ConfirmDialog } from '@/components/ui/confirm-dialog'
import { SimpleCombobox } from '@/components/ui/simple-combobox'

interface NuevaFacturaFormProps {
    clientes: any[]
    clientesByEmpresa?: Record<string, any[]>
    series: Array<{ id: string; codigo: string; nombre: string; predeterminada?: boolean; empresa_id?: string }>
    empresaId: string
    empresaConfig: any
    empresasConfigs?: Record<string, { retencion_predeterminada?: number | null }>
    defaultEmpresaId?: string
    empresas?: Array<{ id: string; nombre: string }>
}

const EMPRESA_VISION_GLOBAL_ID = 'ALL'

// Template IDs
const PLANTILLA_ESTANDAR_ID = '42c849e4-e1e2-4eaa-b719-9bb64ab1fabd'
const PLANTILLA_CORPORATIVA_ID = '5e63ff58-2cd5-4234-805a-fd93f50ee84c'

const EMPRESA_EDISON_ID = 'af15f25a-7ade-4de8-9241-a42e1b8407da'

export function NuevaFacturaForm({ clientes, clientesByEmpresa = {}, series, empresaId, empresaConfig, empresasConfigs = {}, defaultEmpresaId, empresas = [] }: NuevaFacturaFormProps) {
    const router = useRouter()
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [lineas, setLineas] = useState<any[]>([
        { concepto: '', cantidad: 1, precio_unitario: 0, iva_porcentaje: 21, descuento_porcentaje: 0, subtotal: 0 }
    ])

    // Multi-company state (RFC-025). Si empresaId es 'ALL', usar primera empresa disponible
    const [selectedEmpresaId, setSelectedEmpresaId] = useState(
        empresaId === EMPRESA_VISION_GLOBAL_ID ? (defaultEmpresaId || empresas[0]?.id || '') : empresaId
    )
    const [selectedPlantillaId, setSelectedPlantillaId] = useState('')
    const [showConfirmDialog, setShowConfirmDialog] = useState(false)

    // Form state
    const [serieId, setSerieId] = useState('')
    const [proximoNumeroPreview, setProximoNumeroPreview] = useState<string | null>(null)
    const [retencionPorcentaje, setRetencionPorcentaje] = useState(0)
    const [clienteId, setClienteId] = useState('')
    const [fechaEmision, setFechaEmision] = useState(new Date().toISOString().split('T')[0])
    const [notas, setNotas] = useState('')
    const [descuentoTipo, setDescuentoTipo] = useState<'porcentaje' | 'fijo'>('porcentaje')
    const [descuentoValor, setDescuentoValor] = useState(0)
    const [esExterna, setEsExterna] = useState(false)
    const [numeroManual, setNumeroManual] = useState('')
    const [archivo, setArchivo] = useState<File | null>(null)
    const [isUploading, setIsUploading] = useState(false)
    const supabase = createClient()

    // Divisa (RFC-029)
    const [divisa, setDivisa] = useState('EUR')
    const [tipoCambio, setTipoCambio] = useState(1.0)

    const getSimboloDivisa = (cod: string) => {
        switch (cod) {
            case 'USD': return '$'
            case 'GBP': return '£'
            default: return '€'
        }
    }

    // Totales
    const [totales, setTotales] = useState({
        subtotal: 0,
        base_imponible: 0,
        iva: 0,
        total: 0,
        importe_descuento: 0
    })

    const seriesParaMostrar = empresaId === EMPRESA_VISION_GLOBAL_ID
        ? series.filter((s: any) => s.empresa_id === selectedEmpresaId)
        : series

    const clientesParaMostrar = (empresaId === EMPRESA_VISION_GLOBAL_ID && clientesByEmpresa[selectedEmpresaId])
        ? clientesByEmpresa[selectedEmpresaId]
        : clientes

    // Preview del próximo número al cambiar serie
    useEffect(() => {
        if (!serieId) {
            setProximoNumeroPreview(null)
            return
        }
        let cancelled = false
        obtenerProximoNumeroPreviewAction(serieId).then((num) => {
            if (!cancelled) setProximoNumeroPreview(num)
        })
        return () => { cancelled = true }
    }, [serieId])

    useEffect(() => {
        if (seriesParaMostrar.length > 0 && !serieId) {
            const empresaSerieId = (empresaConfig as any)?.serie_predeterminada_id
            const fromEmpresa = empresaSerieId && seriesParaMostrar.some((s: any) => s.id === empresaSerieId) ? empresaSerieId : null
            const fromPredeterminada = seriesParaMostrar.find((s: any) => s.predeterminada)?.id
            setSerieId(fromEmpresa || fromPredeterminada || seriesParaMostrar[0].id)
        }
    }, [seriesParaMostrar, serieId, empresaConfig, esExterna])

    // Effect: al cambiar empresa, resetear plantilla; PlantillaSelector asignará la predeterminada
    useEffect(() => {
        setSelectedPlantillaId('')
    }, [selectedEmpresaId])

    // Effect: retención por defecto según empresa (Edison: 1% IRPF por defecto)
    useEffect(() => {
        const config = empresasConfigs[selectedEmpresaId]
        const fromConfig = config?.retencion_predeterminada ?? (empresaConfig as any)?.retencion_predeterminada
        const defaultRetencion = fromConfig ?? (selectedEmpresaId === EMPRESA_EDISON_ID ? -1 : 0)
        setRetencionPorcentaje(Number(defaultRetencion) || 0)
    }, [selectedEmpresaId, empresasConfigs, empresaConfig])

    useEffect(() => {
        const subtotal = lineas.reduce((acc, linea) => acc + (linea.cantidad * linea.precio_unitario), 0)
        let importe_descuento = 0

        if (descuentoTipo === 'porcentaje') {
            importe_descuento = subtotal * (descuentoValor / 100)
        } else {
            importe_descuento = descuentoValor
        }

        const base_imponible = subtotal - importe_descuento
        const iva = lineas.reduce((acc, l) => acc + (l.cantidad * l.precio_unitario * (l.iva_porcentaje || 21) / 100), 0)
        // efectoRetencion: negativo cuando el porcentaje es negativo (resta), positivo cuando suma
        const efectoRetencion = base_imponible * (retencionPorcentaje / 100)
        const total = base_imponible + iva + efectoRetencion

        setTotales({
            subtotal,
            base_imponible,
            iva,
            total,
            importe_descuento
        })
    }, [lineas, descuentoTipo, descuentoValor, retencionPorcentaje])

    const addLinea = () => {
        setLineas([...lineas, { concepto: '', cantidad: 1, precio_unitario: 0, iva_porcentaje: 21, descuento_porcentaje: 0, subtotal: 0 }])
    }

    const removeLinea = (index: number) => {
        if (lineas.length > 1) {
            setLineas(lineas.filter((_, i) => i !== index))
        }
    }

    const updateLinea = (index: number, field: string, value: any) => {
        const newLineas = [...lineas]
        newLineas[index][field] = value
        setLineas(newLineas)
    }

    const buildFormData = () => {
        const lineasForSchema = lineas.map(l => ({
            concepto: l.concepto,
            descripcion: '',
            cantidad: l.cantidad,
            precio_unitario: l.precio_unitario,
            descuento_porcentaje: l.descuento_porcentaje || 0,
            iva_porcentaje: l.iva_porcentaje || 21,
        }))
        const fd = new FormData()
        fd.set('empresa_id', selectedEmpresaId)
        fd.set('serie', serieId)
        fd.set('cliente_id', clienteId)
        fd.set('fecha_emision', fechaEmision)
        fd.set('plantilla_pdf_id', selectedPlantillaId || '')
        fd.set('forma_pago', '')
        fd.set('descuento_tipo', descuentoTipo)
        fd.set('descuento_valor', String(descuentoValor))
        fd.set('recargo_equivalencia', 'false')
        fd.set('recargo_porcentaje', '5.2')
        fd.set('retencion_porcentaje', String(retencionPorcentaje))
        fd.set('importe_descuento', String(totales.importe_descuento || 0))
        fd.set('importe_retencion', String((totales.base_imponible * Math.abs(retencionPorcentaje)) / 100))
        fd.set('subtotal', String(totales.subtotal))
        fd.set('base_imponible', String(totales.base_imponible))
        fd.set('iva', String(totales.iva))
        fd.set('total', String(totales.total))
        fd.set('lineas', JSON.stringify(lineasForSchema))
        fd.set('notas', notas)
        fd.set('divisa', divisa)
        fd.set('divisa', divisa)
        fd.set('tipo_cambio', String(tipoCambio))
        fd.set('es_externa', String(esExterna))
        fd.set('numero_manual', numeroManual)
        return fd
    }

    const uploadFile = async (): Promise<string | null> => {
        if (!archivo) return null
        setIsUploading(true)
        try {
            const fileExt = archivo.name.split('.').pop()
            const fileName = `${empresaId}/${Date.now()}_${Math.random().toString(36).substring(7)}.${fileExt}`

            const { error: uploadError } = await supabase.storage
                .from('facturas-externas')
                .upload(fileName, archivo)

            if (uploadError) throw uploadError

            const { data: { publicUrl } } = supabase.storage
                .from('facturas-externas')
                .getPublicUrl(fileName)

            return publicUrl
        } catch (error: any) {
            console.error('Error uploading file:', error)
            toast.error(`Error al subir el archivo: ${error.message || error.error || 'Desconocido'}`)
            return null
        } finally {
            setIsUploading(false)
        }
    }

    const validateAndShowConfirm = () => {
        if (!serieId || series.length === 0) {
            toast.error('Selecciona una serie de facturación validada')
            return
        }
        if (esExterna && !archivo) {
            toast.error('Debes subir el PDF de la factura externa para emitirla')
            return
        }
        if (!clienteId) {
            toast.error('Por favor, selecciona un cliente')
            return
        }
        if (lineas.some(l => !l.concepto || l.precio_unitario <= 0)) {
            toast.error('Completa todos los conceptos y precios')
            return
        }
        setShowConfirmDialog(true)
    }

    const handleGuardarBorrador = async () => {
        // Borrador no requiere serie obligatoria, pero si hay, mejor.
        // if (!esExterna && (!serieId || series.length === 0)) ...
        // External draft allows no PDF.
        if (!clienteId) {
            toast.error('Por favor, selecciona un cliente')
            return
        }
        if (lineas.some(l => !l.concepto || l.precio_unitario <= 0)) {
            toast.error('Completa todos los conceptos y precios')
            return
        }
        setIsSubmitting(true)
        try {
            let archivoUrl = null
            if (esExterna && archivo) {
                archivoUrl = await uploadFile()
                if (!archivoUrl) {
                    setIsSubmitting(false)
                    return
                }
            }
            const fd = buildFormData()
            if (archivoUrl) fd.set('archivo_url', archivoUrl)

            const result = await guardarBorradorAction(fd)
            if (result.success) {
                toast.success('Borrador guardado correctamente')
                router.push('/ventas/facturas')
                router.refresh()
            } else {
                toast.error(result.error || 'Error al guardar borrador')
            }
        } catch (err: any) {
            toast.error(err.message || 'Error al guardar borrador')
        } finally {
            setIsSubmitting(false)
        }
    }

    const handleEmitir = async () => {
        setIsSubmitting(true)
        try {
            let archivoUrl = null
            if (esExterna && archivo) {
                archivoUrl = await uploadFile()
                if (!archivoUrl) {
                    setIsSubmitting(false)
                    return
                }
            }
            const fd = buildFormData()
            if (archivoUrl) fd.set('archivo_url', archivoUrl)

            const result = await crearFacturaAction(fd)
            if (result.success) {
                setShowConfirmDialog(false)
                const numeroCompleto = result.data?.numero
                const facturaId = result.data?.id
                toast.success(numeroCompleto ? `Factura emitida: ${numeroCompleto}` : 'Factura emitida correctamente', { duration: 5000 })
                // Redirigir al detalle para ver el número de factura de forma prominente
                if (facturaId) {
                    router.replace(`/ventas/facturas/${facturaId}`)
                } else {
                    router.replace('/ventas/facturas')
                }
            } else {
                toast.error(result.error || 'Error al emitir factura')
            }
        } catch (err: any) {
            toast.error(err.message || 'Error al emitir factura')
        } finally {
            setIsSubmitting(false)
        }
    }

    return (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            {/* Formulario Principal (8/12) */}
            <div className="lg:col-span-8 space-y-6">
                <Card className="shadow-sm">
                    <CardHeader className="bg-slate-50/50 border-b border-slate-100">
                        <CardTitle className="text-xl font-semibold text-slate-800 flex items-center gap-2">
                            <span className="text-primary">📄</span> Datos de la Factura
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="pt-6 space-y-6">
                        {/* RFC-025: Empresa Emisora y Plantilla */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-4 bg-linear-to-r from-primary/5 to-transparent rounded-lg border border-primary/10">
                            <div className="space-y-2 min-w-0">
                                <Label className="flex items-center gap-2">
                                    <Building2 className="h-4 w-4 text-primary" />
                                    Empresa Emisora
                                </Label>
                                <Select
                                    value={selectedEmpresaId}
                                    onValueChange={(id) => {
                                        setSelectedEmpresaId(id)
                                        setSerieId('')
                                    }}
                                    disabled={empresaId !== EMPRESA_VISION_GLOBAL_ID}
                                >
                                    <SelectTrigger data-testid="factura-empresa-select" className="w-full min-w-0">
                                        <SelectValue placeholder="Seleccionar empresa" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {empresas.map((emp) => (
                                            <SelectItem key={emp.id} value={emp.id}>
                                                {emp.nombre}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2 min-w-0">
                                <Label className="flex items-center gap-2">
                                    <FileText className="h-4 w-4 text-primary" />
                                    Plantilla PDF
                                </Label>
                                <PlantillaSelector
                                    empresaId={selectedEmpresaId}
                                    value={selectedPlantillaId}
                                    onChange={setSelectedPlantillaId}
                                />
                            </div>
                        </div>



                        <div className="flex items-center space-x-2 p-4 bg-slate-50 rounded-lg border border-slate-200">
                            <div className="flex items-center space-x-2">
                                <Label htmlFor="externa-switch" className="font-semibold cursor-pointer">Factura Externa</Label>
                                <span
                                    data-testid="factura-externa-switch"
                                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-slate-400 focus:ring-offset-2 ${esExterna ? 'bg-primary' : 'bg-slate-200'}`}
                                    onClick={() => setEsExterna(!esExterna)}
                                >
                                    <span
                                        className={`${esExterna ? 'translate-x-6' : 'translate-x-1'} inline-block h-4 w-4 transform rounded-full bg-white transition-transform`}
                                    />
                                </span>
                            </div>
                            {esExterna && <span className="text-xs text-slate-500 ml-2">Se asignará número de serie automáticamente. Puedes subir el PDF ahora o más tarde.</span>}
                        </div>

                        <Separator className="bg-slate-100" />

                        {/* Serie y Cliente */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {seriesParaMostrar.length > 0 && (
                                <div className="space-y-2">
                                    <Label>Serie de Facturación</Label>
                                    <Select value={serieId} onValueChange={setSerieId}>
                                        <SelectTrigger className="bg-white">
                                            <SelectValue placeholder="Seleccionar serie..." />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {seriesParaMostrar.map((s: any) => (
                                                <SelectItem key={s.id} value={s.id}>
                                                    {s.nombre} ({s.codigo})
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    {proximoNumeroPreview && (
                                        <p className="text-sm text-slate-600 dark:text-slate-400 flex items-center gap-2">
                                            <span className="font-mono font-semibold text-primary">{proximoNumeroPreview}</span>
                                            <span className="text-xs">(se asignará al emitir)</span>
                                        </p>
                                    )}
                                </div>
                            )}

                            {esExterna && (
                                <div className="space-y-2 animate-in fade-in slide-in-from-right-2">
                                    <Label className="flex items-center gap-2">
                                        <Upload className="h-4 w-4 text-primary" />
                                        Documento PDF
                                    </Label>
                                    <Input
                                        type="file"
                                        accept="application/pdf"
                                        onChange={(e) => setArchivo(e.target.files?.[0] || null)}
                                        className="bg-white file:mr-4 file:py-1 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                                    />
                                </div>
                            )}
                            <div className="space-y-2" data-testid="cliente-combobox-wrapper">
                                <Label htmlFor="cliente">Cliente</Label>
                                <SimpleCombobox
                                    data-testid="combobox-cliente"
                                    options={clientesParaMostrar.map(c => ({
                                        value: c.id,
                                        label: c.nombre_fiscal,
                                        subLabel: c.cif
                                    }))}
                                    value={clienteId}
                                    onChange={(val) => setClienteId(val)}
                                    placeholder="Seleccionar cliente..."
                                    searchPlaceholder="Buscar cliente por nombre o CIF..."
                                    emptyText="No se encontraron clientes."
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Fecha de emisión</Label>
                                <Input
                                    type="date"
                                    value={fechaEmision}
                                    onChange={(e) => setFechaEmision(e.target.value)}
                                    className="bg-white"
                                />
                            </div>
                        </div>

                        {/* RFC-029: Divisa y Tipo de Cambio */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 p-4 bg-slate-50 rounded-lg border border-slate-200">
                            <div className="space-y-2">
                                <Label>Divisa</Label>
                                <Select value={divisa} onValueChange={setDivisa}>
                                    <SelectTrigger className="bg-white">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="EUR">Euro (€)</SelectItem>
                                        <SelectItem value="USD">Dólar ($)</SelectItem>
                                        <SelectItem value="GBP">Libra (£)</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            {divisa !== 'EUR' && (
                                <div className="space-y-2 md:col-span-2 animate-in slide-in-from-left-2">
                                    <Label>Tipo de Cambio (1 EUR = ? {divisa})</Label>
                                    <div className="flex gap-4 items-center">
                                        <Input
                                            type="number"
                                            step="0.0001"
                                            value={Number.isNaN(tipoCambio) ? '' : tipoCambio}
                                            onChange={(e) => setTipoCambio(parseFloat(e.target.value) || 1)}
                                            className="bg-white"
                                        />
                                        <p className="text-xs text-slate-500 italic">
                                            Se utilizará para cálculos internos si fuera necesario.
                                        </p>
                                    </div>
                                </div>
                            )}
                        </div>

                        <Separator className="bg-slate-100" />

                        {/* Líneas de Factura */}
                        <div className="space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-sm font-bold uppercase tracking-wider text-slate-500">Líneas de Concepto</h3>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={addLinea}
                                    className="h-8 text-primary border-primary/20 hover:bg-primary/5"
                                >
                                    <Plus className="h-4 w-4 mr-1" /> Añadir Línea
                                </Button>
                            </div>

                            <div className="space-y-3">
                                {lineas.map((linea, index) => (
                                    <div key={index} className="flex gap-3 items-start animate-in fade-in slide-in-from-top-2 duration-300">
                                        <div className="flex-1">
                                            <Input
                                                placeholder="Concepto / Servicio"
                                                value={linea.concepto}
                                                onChange={(e) => updateLinea(index, 'concepto', e.target.value)}
                                                className="bg-white"
                                            />
                                        </div>
                                        <div className="w-20">
                                            <Input
                                                type="number"
                                                placeholder="Cant"
                                                value={Number.isNaN(linea.cantidad) ? '' : linea.cantidad}
                                                onChange={(e) => updateLinea(index, 'cantidad', parseFloat(e.target.value) || 0)}
                                                className="bg-white text-center"
                                            />
                                        </div>
                                        <div className="w-32">
                                            <div className="relative">
                                                <Input
                                                    type="number"
                                                    placeholder="Precio"
                                                    value={Number.isNaN(linea.precio_unitario) ? '' : linea.precio_unitario}
                                                    onChange={(e) => updateLinea(index, 'precio_unitario', parseFloat(e.target.value) || 0)}
                                                    className="bg-white pl-7"
                                                />
                                                <span className="absolute left-2.5 top-2.5 h-4 w-4 text-slate-400 font-medium">{getSimboloDivisa(divisa)}</span>
                                            </div>
                                        </div>
                                        <div className="w-32">
                                            <div className="h-10 flex items-center px-3 bg-slate-50 rounded-md border border-slate-200 font-medium text-slate-700">
                                                {((Number(linea.cantidad) || 0) * (Number(linea.precio_unitario) || 0)).toFixed(2)}{getSimboloDivisa(divisa)}
                                            </div>
                                        </div>
                                        {lineas.length > 1 && (
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                onClick={() => removeLinea(index)}
                                                className="h-10 w-10 text-slate-400 hover:text-red-500 hover:bg-red-50"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <Separator className="bg-slate-100" />

                        {/* Notas */}
                        <div className="space-y-2">
                            <Label htmlFor="notas" className="flex items-center gap-2">
                                <span className="text-slate-400">📝</span> Notas / Clausulas Adicionales
                            </Label>
                            <Textarea
                                id="notas"
                                placeholder="Añadir notas internas o para el cliente..."
                                value={notas}
                                onChange={(e) => setNotas(e.target.value)}
                                className="min-h-[100px] bg-white"
                            />
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Resumen y Guardado (4/12) */}
            <div className="lg:col-span-4 space-y-6">
                <Card className="shadow-lg border-primary/10 overflow-hidden">
                    <CardHeader className="bg-primary text-primary-foreground py-4">
                        <CardTitle className="text-lg font-bold flex items-center justify-between">
                            Resumen Económico
                            <span className="text-xs font-normal opacity-80 uppercase">{divisa} ({getSimboloDivisa(divisa)})</span>
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="pt-6 space-y-4">
                        <div className="flex justify-between text-sm">
                            <span className="text-slate-500">Subtotal</span>
                            <span className="font-medium">{totales.subtotal.toFixed(2)}{getSimboloDivisa(divisa)}</span>
                        </div>

                        {/* Descuento Global Segment */}
                        <div className="space-y-2 pt-2 border-t border-slate-100">
                            <div className="flex items-center justify-between text-sm">
                                <Label className="text-slate-500 font-normal">Descuento Global</Label>
                                <div className="flex items-center rounded-md border border-slate-200 bg-slate-50">
                                    <button
                                        type="button"
                                        onClick={() => setDescuentoTipo('porcentaje')}
                                        className={`px-2 py-1 text-xs rounded-l-md ${descuentoTipo === 'porcentaje' ? 'bg-primary text-primary-foreground' : 'text-slate-500 hover:text-slate-900'}`}
                                    >
                                        <Percent className="h-3 w-3" />
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => setDescuentoTipo('fijo')}
                                        className={`px-2 py-1 text-xs rounded-r-md ${descuentoTipo === 'fijo' ? 'bg-primary text-primary-foreground' : 'text-slate-500 hover:text-slate-900'}`}
                                    >
                                        <span className="font-bold text-[10px]">{getSimboloDivisa(divisa)}</span>
                                    </button>
                                </div>
                            </div>
                            <div className="relative">
                                <Input
                                    type="number"
                                    value={Number.isNaN(descuentoValor) ? '' : descuentoValor}
                                    onChange={(e) => setDescuentoValor(parseFloat(e.target.value) || 0)}
                                    className="bg-white h-9"
                                />
                                <span className="absolute right-3 top-2.5 text-xs text-slate-400">
                                    {descuentoTipo === 'porcentaje' ? '%' : getSimboloDivisa(divisa)}
                                </span>
                            </div>
                        </div>

                        <Separator className="bg-slate-100" />

                        <div className="flex justify-between text-sm font-medium">
                            <span>Base Imponible</span>
                            <span>{totales.base_imponible.toFixed(2)}{getSimboloDivisa(divisa)}</span>
                        </div>

                        <div className="flex justify-between text-sm">
                            <span className="text-slate-500">
                                IVA (
                                {lineas.length > 0
                                    ? [...new Set(lineas.map((l) => l.iva_porcentaje ?? 21))].sort((a, b) => a - b).join('%, ') + '%'
                                    : '21%'}
                                )
                            </span>
                            <span>{totales.iva.toFixed(2)}{getSimboloDivisa(divisa)}</span>
                        </div>

                        {(retencionPorcentaje > 0 || retencionPorcentaje < 0) && (
                            <div className="flex justify-between text-sm text-amber-700 dark:text-amber-400">
                                <span>Retención IRPF ({retencionPorcentaje}%)</span>
                                <span>-{(totales.base_imponible * Math.abs(retencionPorcentaje) / 100).toFixed(2)}{getSimboloDivisa(divisa)}</span>
                            </div>
                        )}

                        <div className="space-y-2">
                            <Label className="text-slate-500 font-normal text-xs">Retención IRPF % (solo Empresa/Autónomo)</Label>
                            <Input
                                data-testid="retencion-irpf-input"
                                type="number"
                                min={-1}
                                max={100}
                                step={0.5}
                                value={Number.isNaN(retencionPorcentaje) ? '' : retencionPorcentaje}
                                onChange={(e) => setRetencionPorcentaje(parseFloat(e.target.value) || 0)}
                                className="bg-white h-9"
                            />
                        </div>

                        <div className="bg-slate-50 -mx-6 p-6 space-y-2 border-y border-slate-200">
                            <div className="flex justify-between items-center">
                                <span className="text-lg font-bold text-slate-800 tracking-tight">TOTAL</span>
                                <span className="text-2xl font-black text-primary">
                                    {totales.total.toFixed(2)}{getSimboloDivisa(divisa)}
                                </span>
                            </div>
                        </div>

                        <Button
                            className="w-full bg-linear-to-r from-primary to-primary/80 hover:scale-[1.02] transition-all text-white font-bold h-12 text-lg shadow-md shadow-primary/20"
                            onClick={validateAndShowConfirm}
                            disabled={isSubmitting}
                        >
                            {isSubmitting ? (
                                <>
                                    <Loader2 className="mr-2 h-5 w-5 animate-spin" /> Procesando...
                                </>
                            ) : (
                                'Emitir Factura'
                            )}
                        </Button>
                        <Button
                            variant="outline"
                            className="w-full h-10 border-slate-200"
                            onClick={handleGuardarBorrador}
                            disabled={isSubmitting}
                        >
                            {isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
                            Guardar Borrador
                        </Button>
                        <Button
                            variant="outline"
                            className="w-full h-10 text-slate-500 border-slate-200"
                            onClick={() => router.back()}
                            disabled={isSubmitting}
                        >
                            Cancelar
                        </Button>
                    </CardContent>
                </Card>

                {/* Confirmation Dialog */}
                <ConfirmDialog
                    open={showConfirmDialog}
                    onOpenChange={setShowConfirmDialog}
                    title="Confirmar emisión de factura"
                    description={`¿Estás seguro de emitir esta factura por ${totales.total.toFixed(2)}${getSimboloDivisa(divisa)}? Una vez emitida, no podrá ser eliminada, solo rectificada.`}
                    confirmText="Sí, emitir factura"
                    cancelText="Revisar datos"
                    onConfirm={handleEmitir}
                />

                {/* Info Card */}
                <div className="bg-amber-50 rounded-xl p-4 border border-amber-100 flex gap-3 shadow-sm">
                    <span className="text-xl">💡</span>
                    <p className="text-xs text-amber-800 leading-relaxed">
                        Recuerda que una vez emitida, la factura tendrá un número correlativo asignado automáticamente y no podrá ser eliminada, solo rectificada.
                    </p>
                </div>
            </div>
        </div >
    )
}

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { format } from 'date-fns'
import { es } from 'date-fns/locale'
import { Banknote, CreditCard, Building2, CheckCircle2 } from 'lucide-react'

import { PagoFactura } from '@/types/ventas'

interface HistorialPagosCardProps {
    pagos: PagoFactura[]
}

export function HistorialPagosCard({ pagos }: HistorialPagosCardProps) {
    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(amount)
    }

    const getIcon = (metodo: string) => {
        switch (metodo.toLowerCase()) {
            case 'transferencia': return <Building2 className="w-4 h-4" />
            case 'tarjeta': return <CreditCard className="w-4 h-4" />
            default: return <Banknote className="w-4 h-4" />
        }
    }

    return (
        <Card>
            <CardHeader>
                <CardTitle className="text-sm uppercase tracking-wider text-slate-500 font-bold">Historial de Pagos</CardTitle>
            </CardHeader>
            <CardContent>
                {pagos.length === 0 ? (
                    <div className="text-center py-6 text-slate-500 text-sm">
                        No hay pagos registrados para esta factura.
                    </div>
                ) : (
                    <div className="space-y-4">
                        {pagos.map((pago, index) => (
                            <div key={pago.id} className="flex gap-3 items-start relative pb-4 border-b border-slate-100 last:border-0 last:pb-0">
                                <div className="mt-1 w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center shrink-0">
                                    {getIcon(pago.metodo_pago)}
                                </div>
                                <div className="flex-1 space-y-1">
                                    <div className="flex justify-between">
                                        <p className="font-semibold text-slate-900">{formatCurrency(pago.importe)}</p>
                                        <span className="text-xs text-slate-500">{format(new Date(pago.fecha_pago), 'dd MMM yyyy', { locale: es })}</span>
                                    </div>
                                    <p className="text-xs text-slate-600 capitalize flex items-center gap-1">
                                        {pago.metodo_pago}
                                        {index === 0 && <span className="px-1.5 py-0.5 bg-green-100 text-green-700 text-[10px] rounded-full font-bold">NUEVO</span>}
                                    </p>
                                    {pago.referencia && (
                                        <p className="text-[10px] text-slate-400">Ref: {pago.referencia}</p>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </CardContent>
        </Card>
    )
}
